        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCompanyAccountDropDownData")]
        public JsonResult GetCompanyAccountDropDownData()
        {
            ////
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                DataSet ds = new DataSet();
                using (System.Data.SqlClient.SqlConnection sqlconn = new System.Data.SqlClient.SqlConnection(Cryptography.Decrypt(System.Configuration.ConfigurationManager.AppSettings["ConnectionString"].ToStr(), "tcloudX@@!", true)))
                {
                    sqlconn.Open();
                    using (System.Data.SqlClient.SqlCommand cmd = new System.Data.SqlClient.SqlCommand())
                    {
                        cmd.Connection = sqlconn;
                        cmd.CommandType = CommandType.StoredProcedure;
                        cmd.CommandText = "stp_FillCompanyAccountCombos";
                        using (System.Data.SqlClient.SqlDataAdapter da = new System.Data.SqlClient.SqlDataAdapter(cmd))
                        {
                            da.Fill(ds);
                        }
                    }

                    //var LocationTypes = ds.Tables[0].AsEnumerable()
                    //   .Select(datarow => new
                    //   {
                    //       Id = datarow.Field<int>("Id"),
                    //       LocationType = datarow.Field<string>("LocationType")
                    //   });
                    var SubCompanies = ds.Tables[0].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          CompanyName = datarow.Field<string>("CompanyName")
                      });
                    var BookingTypes = ds.Tables[1].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          BookingTypeName = datarow.Field<string>("BookingTypeName")
                      });
                    var VehicleTypes = ds.Tables[2].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          VehicleType = datarow.Field<string>("VehicleType")
                      });
                    var PaymentTypes = ds.Tables[3].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          PaymentType = datarow.Field<string>("PaymentType")
                      });
                    var AccountNames = ds.Tables[4].AsEnumerable()
                    .Select(datarow => new
                    {
                        Id = datarow.Field<int>("Id"),
                        CompanyName = datarow.Field<string>("CompanyName")
                    });
                    var CompanyGroups = ds.Tables[5].AsEnumerable()
                   .Select(datarow => new
                   {
                       Id = datarow.Field<int>("Id"),
                       GroupName = datarow.Field<string>("GroupName")
                   });
                    var AccountTypes = ds.Tables[6].AsEnumerable()
                    .Select(datarow => new
                    {
                        Id = datarow.Field<int>("Id"),
                        AccountTypeName = datarow.Field<string>("AccountTypeName")
                    });
                    var Fleet_VehicleTypes = ds.Tables[7].AsEnumerable()
                    .Select(datarow => new
                    {
                        Id = datarow.Field<int>("Id"),
                        VehicleType = datarow.Field<string>("VehicleType")
                    });
                    var Type = ds.Tables[8].AsEnumerable()
                    .Select(datarow => new
                    {
                        GroupName = datarow.Field<string>("Type")
                    });
                    var Charges = ds.Tables[9].AsEnumerable()
                    .Select(datarow => new
                    {
                        Id = datarow.Field<int>("Id"),
                        GroupName = datarow.Field<string>("ChargesName")
                    });
                    response.Data =
                        new
                        {
                            //LocationTypes = LocationTypes,
                            SubCompanies = SubCompanies,
                            VehicleTypes = VehicleTypes,
                            BookingTypes = BookingTypes,
                            PaymentTypes = PaymentTypes,
                            AccountNames = AccountNames,
                            CompanyGroups = CompanyGroups,
                            AccountTypes = AccountTypes,
                            Fleet_VehicleTypes = Fleet_VehicleTypes,
                            Type = Type,
                            Charges = Charges,
                        };
                    //      response.Data = list;
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCompanyVehicleDropDownData")]
        public JsonResult GetCompanyVehicleDropDownData()
        {
            //

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {

                DataSet ds = new DataSet();
                using (System.Data.SqlClient.SqlConnection sqlconn = new System.Data.SqlClient.SqlConnection(Cryptography.Decrypt(System.Configuration.ConfigurationManager.AppSettings["ConnectionString"].ToStr(), "tcloudX@@!", true)))
                {

                    sqlconn.Open();

                    using (System.Data.SqlClient.SqlCommand cmd = new System.Data.SqlClient.SqlCommand())
                    {

                        cmd.Connection = sqlconn;

                        cmd.CommandType = CommandType.StoredProcedure;
                        cmd.CommandText = "stp_FillCompanyVehicleCombos";

                        using (System.Data.SqlClient.SqlDataAdapter da = new System.Data.SqlClient.SqlDataAdapter(cmd))
                        {

                            da.Fill(ds);
                        }

                    }



                    var VehicleTypes = ds.Tables[0].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          VehicleType = datarow.Field<string>("VehicleType")
                      });

                    var FuelTypes = ds.Tables[1].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          FuelType = datarow.Field<string>("FuelType")
                      });

                    var VehicleColor = ds.Tables[2].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          VehicleColor = datarow.Field<string>("VehicleColor")
                      });

                    var SubCompanies = ds.Tables[3].AsEnumerable()
                      .Select(datarow => new
                      {
                          Id = datarow.Field<int>("Id"),
                          CompanyName = datarow.Field<string>("CompanyName")
                      });


                    response.Data = new { VehicleTypes = VehicleTypes, FuelTypes = FuelTypes, VehicleColor = VehicleColor, SubCompanies = SubCompanies };
                }

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);

        }


        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCompanyVehcileListData")]
        public JsonResult GetCompanyVehcileListData(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            List<Fleet_Master> lst = new List<Fleet_Master>();
            try
            {
                if (obj.companyVehicle != null)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        string sqlQuery = $@"
                      SELECT 
                          a.Id,
                          a.VehicleID,
                          a.Plateno AS PlateNo,
                          a.VehicleNo,
                          a.VehicleOwner AS Owner,
                          a.VehicleMake AS Make,
                          a.VehicleModel AS Model,
                          CONVERT(VARCHAR, a.MOTExpiryDate, 103) AS Mot,
                          CONVERT(VARCHAR, a.RoadTaxExpDate, 103) AS RoadTax,
                          CONVERT(VARCHAR, a.InsuranceExpiry, 103) AS Insurance,
                          CONVERT(VARCHAR, a.PLateExpiryDate, 103) AS Plate,
                          CONVERT(VARCHAR, a.PHCVehicleExpiryDate, 103) AS PHCVehicleExpiryDate,
                          a.VehicleTypeId,
                          a.FuelTypeId,
                          a.VehicleColor,
                          a.LogBookNo,
                          a.MOTExpiryPath,
                          a.InsuranceExpiryPath,
                          a.RoadTaxExpPath,
                          a.LogBookPath,
                          a.PHCVehicleExpiryPath,
                          CONVERT(VARCHAR, a.ManufactureDate, 103) As Manufacture
                      FROM Fleet_Master a
                      WHERE a.Id = {obj.companyVehicle.ID}";

                        var result = db.ExecuteQuery<Fleet_Master_Update>(sqlQuery).ToList();

                        response.Data = new { VehicleTypes = result };
                    }
                }
                else
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        string sqlQuery = $@"
                         SELECT 
                             a.Id,
                             a.VehicleID,
                             a.Plateno AS PlateNo,
                             a.VehicleNo,
                             a.VehicleOwner AS Owner,
                             a.VehicleMake AS Make,
                             a.VehicleModel AS Model,
                             CONVERT(VARCHAR, a.MOTExpiryDate, 103) AS Mot,
                             CONVERT(VARCHAR, a.RoadTaxExpDate, 103) AS RoadTax,
                             CONVERT(VARCHAR, a.InsuranceExpiry, 103) AS Insurance,
                             CONVERT(VARCHAR, a.PLateExpiryDate, 103) AS Plate,
                             CONVERT(VARCHAR, a.PHCVehicleExpiryDate, 103) AS PHCVehicleExpiryDate,
                             a.VehicleTypeId,
                             a.FuelTypeId,
                             a.VehicleColor,
                             a.LogBookNo,
                             a.MOTExpiryPath,
                             a.InsuranceExpiryPath,
                             a.RoadTaxExpPath,
                             a.LogBookPath,
                             a.PHCVehicleExpiryPath,
                             CAST(ISNULL(a.InActive,0) AS BIT) InActive,
                             b.VehicleType AS Vehicle
                         FROM Fleet_Master a
                         LEFT JOIN Fleet_VehicleTypes b ON a.VehicleTypeId = b.Id";

                        var result = db.ExecuteQuery<Fleet_Master_Update>(sqlQuery).ToList();

                        response.Data = new { VehicleTypes = result };
                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("InActiveComapnyVehicle")]
        public JsonResult InActiveComapnyVehicle(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            List<Fleet_Master> lst = new List<Fleet_Master>();
            try
            {
                if (obj.companyVehicle != null)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        db.ExecuteQuery<int>(@"
                                      UPDATE Fleet_Master 
                                      SET InActive = CASE WHEN InActive = 1 THEN 0 ELSE 1 END 
                                      WHERE Id = {0}", obj.companyVehicle.ID);
                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetVehicleTypesListData")]
        public JsonResult GetVehicleTypesListData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                var serializer = new JavaScriptSerializer();
                serializer.MaxJsonLength = Int32.MaxValue;
                if (obj.fleetVehicleType != null)
                {
                    //? "where a.Id == " + obj.fleetVehicleType.Id.ToString() : "";
                    var VehicleTypesList = (from a in General.GetQueryable<Fleet_VehicleType>(null)
                                            where a.Id == obj.fleetVehicleType.Id
                                            orderby a.OrderNo
                                            select new
                                            {
                                                Id = a.Id,
                                                Vehicle = a.VehicleType,
                                                Passengers = a.NoofPassengers,
                                                Luggages = a.NoofLuggages,
                                                BackgroundColor = a.BackgroundColor,
                                                TextColor = a.TextColor,
                                                //  Photo = (a.Photo != null && a.Photo.Length > 0) ? (a.Photo.ToArray()) : null,
                                                //Photo = (a.Photo != null && a.Photo.Length > 0) ? Convert.ToBase64String(a.Photo.ToArray()) : null, //a.CompanyLogo.ToArray(),
                                                StartRate = a.StartRate,
                                                StartRateUpToMiles = a.StartRateValidMiles,
                                                AttributeValues = a.AttributeValues
                                            });
                    //var VehiclePhoto = (from a in General.GetQueryable<Fleet_VehicleType>(null)
                    //                        where a.Id == obj.fleetVehicleType.Id
                    //                        orderby a.OrderNo
                    //                        select new
                    //                        {
                    //                            Photo = (a.Photo != null && a.Photo.Length > 0) ? (a.Photo.ToArray()) : null,
                    //                           // Photo = (a.Photo != null && a.Photo.Length > 0) ? Convert.ToBase64String(a.Photo.ToArray()) : null,
                    //                        });
                    var vehiclePhotoList = (from a in General.GetQueryable<Fleet_VehicleType>(null)
                                            where a.Id == obj.fleetVehicleType.Id
                                            orderby a.OrderNo
                                            select a.Photo)
                        .ToList();
                    var vehiclePhotoBase64List = vehiclePhotoList.Select(photo =>
                                                    photo != null && photo.Length > 0 ? Convert.ToBase64String(photo) : null)
                                                    .ToList();
                    response.Data = new { VehicleTypes = VehicleTypesList, VehiclePhoto = vehiclePhotoBase64List, MaxJsonLength = int.MaxValue };
                }
                else
                {
                    var VehicleTypesList = (from a in General.GetQueryable<Fleet_VehicleType>(null)
                                            orderby a.OrderNo
                                            select new
                                            {
                                                Id = a.Id,
                                                Vehicle = a.VehicleType,
                                                Passengers = a.NoofPassengers,
                                                Luggages = a.NoofLuggages,
                                                BackgroundColor = a.BackgroundColor,
                                                TextColor = a.TextColor,
                                                StartRate = a.StartRate,
                                                StartRateUpToMiles = a.StartRateValidMiles,
                                            });
                    response.Data = new { VehicleTypes = VehicleTypesList, MaxJsonLength = int.MaxValue };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveFareMeterSetting")]
        public JsonResult SaveFareMeterSetting(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFareMeterSetting.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }
                //  decimal MeterRoundedValue = 0;
                int FareMeterType = 3;
                //if (obj.FareMeterType == -1)
                //{
                //    response.Message = "Required : Fare Meter Type";
                //    return Json(response, JsonRequestBehavior.AllowGet);
                //}
                //if (obj.FareMeterType == 2)
                //{
                //    MeterRoundedValue = obj.FareRoundedValue.ToDecimal();
                //    FareMeterType = 2;
                //}
                //if (obj.FareMeterType == 3)
                //{
                //    MeterRoundedValue = obj.FareRoundedValue.ToDecimal();
                //    FareMeterType = 3;
                //}
                //else
                //{
                //    FareMeterType = 2;
                //    MeterRoundedValue = 0;
                //}
                Gen_SysPolicy sysPolicy = General.GetQueryable<Gen_SysPolicy>(null).FirstOrDefault();
                SysPolicyBO sysPolicyBO = new SysPolicyBO();
                if (sysPolicy != null)
                {
                    sysPolicyBO.GetByPrimaryKey(sysPolicy.Id);
                    sysPolicyBO.Edit();
                }
                sysPolicyBO.Current.Gen_SysPolicy_Configurations[0].FareMeterType = 3;
                //   sysPolicyBO.Current.Gen_SysPolicy_Configurations[0].FareMeterRoundedCalc = MeterRoundedValue.ToDecimal();
                string[] skipProperties = new string[] { "Gen_SysPolicy", "Fleet_VehicleType" };
                List<Gen_SysPolicy_FareMeterSetting> listofFares = (from a in obj.FareMeterSettings
                                                                    select new Gen_SysPolicy_FareMeterSetting
                                                                    {
                                                                        //
                                                                        Id = a.Id,
                                                                        SysPolicyId = sysPolicyBO.Current.Id,
                                                                        VehicleTypeId = a.VehicleTypeId,
                                                                        HasMeter = a.HasMeter,
                                                                        AutoStartWaiting = a.AutoStartWaiting,
                                                                        AutoStartWaitingBelowSpeed = a.AutoStartWaitingBelowSpeed,
                                                                        AutoStartWaitingBelowSpeedSeconds = a.AutoStartWaitingBelowSpeedSeconds,
                                                                        AutoStopWaitingOnSpeed = a.AutoStopWaitingOnSpeed,
                                                                        DrvWaitingChargesPerMin = a.DrvWaitingChargesPerMin,
                                                                        AccWaitingChargesPerMin = a.AccWaitingChargesPerMin
                                                                    }).ToList();
                IList<Gen_SysPolicy_FareMeterSetting> savedListFares = sysPolicyBO.Current.Gen_SysPolicy_FareMeterSettings;
                Utils.General.SyncChildCollection(ref savedListFares, ref listofFares, "Id", skipProperties);
                bool IsUpdated = false;
                if (sysPolicyBO.Current.Gen_SysPolicy_Configurations[0].EnablePeakOffPeakFares.ToBool() != obj.EnablePeakOffPeakWiseFares
                    || sysPolicyBO.Current.Gen_SysPolicy_Configurations[0].FareMeterType.ToInt() != obj.FareMeterType)
                {
                    sysPolicyBO.Current.Gen_SysPolicy_Configurations[0].EnablePeakOffPeakFares = obj.EnablePeakOffPeakWiseFares;
                    IsUpdated = true;
                }
                List<BookingFeesRange> list = new List<BookingFeesRange>();
                if (obj.BookingFeesRange != null)
                {
                    list = (from r in obj.BookingFeesRange
                            select new BookingFeesRange
                            {
                                From = r.From,
                                To = r.To,
                                Charges = r.Charges
                            }).ToList();
                }
                MeterTariff obje = new MeterTariff();
                obje.RemoveExtraCharges = obj.RemoveExtraCharges ? "1" : "0";
                obje.ShowExtraCharges = obj.ShowExtraCharges ? "1" : "0";
                obje.ExtraChargesPerQty = obj.ExtraChargesPerQty.ToString();
                obje.ShowBookingFees = obj.ShowBookingFees ? "1" : "0";
                obje.BookingFeesRange = list;
                obje.ShowParkingCharges = obj.ShowParkinCharges ? "1" : "0";
                obje.ChangePlotOnAsDirected = obj.ChangePlotAsDirected ? "1" : "0";
                string jsonParameterValue = Newtonsoft.Json.JsonConvert.SerializeObject(obje);
                sysPolicyBO.Current.Gen_SysPolicy_Configurations[0].PDANewWeekMessageByDay = jsonParameterValue.ToStr();
                sysPolicyBO.Save();

                foreach (var item in obj.FareMeterSettings)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        db.ExecuteQuery<int>("update Gen_SysPolicy_FareMeterSettings set FreeWaitingSeconds=" + item.FreeWaitingSeconds + "where Id =" + item.Id);
                    }
                }

                Global.ReloadMeterList();

                //
            }
            catch (Exception ex)
            {
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveFleetDriverbtnUpdateSetting")]
        public JsonResult SaveFleetDriverbtnUpdateSetting(AdminApi obj, HttpPostedFileBase file)
        {
            DriverBO objdriver = new DriverBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {


                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFleetDriverbtnUpdateSetting.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableFlagDown.ToBool()) + Environment.NewLine);
                }
                catch
                {
                }
                //
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    //int? Id = obj.fleetVehicleType.Id;

                    int? Id = obj.fleetDriver.Id;
                    //if (Id == 0)
                    //{

                    //    //UM_User obj_User = General.GetQueryable<UM_User>(null).OrderByDescending(c => c.Id).FirstOrDefault();
                    //    //objuser.New();

                    //}
                    //else
                    //{
                    //    objdriver.GetByPrimaryKey(Id);
                    //    objdriver.Edit();
                    //}


                    //int driverId = obj.fleetDriver.Id.ToInt();
                    var objQueue = db.Fleet_DriverQueueLists.Where(a => a.DriverId == Id && a.Status == true).OrderByDescending(c => c.Id).FirstOrDefault();

                    if (objQueue == null)
                    {
                        response.Message = "You can't update pda settings at this time " + Environment.NewLine + "Please Login a Driver before updating it";
                        response.HasError = true;
                        //ENUtils.ShowMessage("You can't update pda settings at this time " + Environment.NewLine + "Please Login a Driver before updating it");
                        return Json(response, JsonRequestBehavior.AllowGet);
                    }
                    else
                    {

                        if (obj.fleetDriver.Fleet_Driver_PDASettings.Count > 0 && obj.fleetDriver.Fleet_Driver_PDASettings[0].CurrentPdaVersion < 10)
                        {
                            if (General.GetQueryable<Fleet_Driver_Location>(c => c.DriverId == obj.fleetDriver.Id && c.UpdateDate.AddMinutes(1) < DateTime.Now).Count() > 0)
                            {
                                response.Message = "Driver PDA is not working at the moment! Please Re-Login it or Check pda Internet settings";
                                response.HasError = true;
                                //ENUtils.ShowMessage("You can't update pda settings at this time " + Environment.NewLine + "Please Login a Driver before updating it");
                                return Json(response, JsonRequestBehavior.AllowGet);
                                //ENUtils.ShowMessage("Driver PDA is not working at the moment! Please Re-Login it or Check pda Internet settings");                                

                            }
                        }

                    }

                    decimal version = obj.fleetDriver.Fleet_Driver_PDASettings[0].CurrentPdaVersion.ToDecimal();

                    string biddingMessage = string.Empty;
                    //please check logic below
                    var policy = db.Gen_SysPolicy_Configurations.Where(m => m.SysPolicyId == 1).FirstOrDefault();
                    if (obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableBidding == true)
                    {

                        if (policy.BiddingType.ToInt() == 1)
                        {
                            biddingMessage = "Fastest Finger";
                        }
                        else if (policy.BiddingType.ToInt() == 2)
                        {
                            biddingMessage = "Nearest Driver";
                        }
                        else if (policy.BiddingType.ToInt() == 3)
                        {
                            biddingMessage = "Longest Waiting in Queue";
                        }

                    }

                    string FareMessage = string.Empty;
                    if (obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableFareMeter == true)
                    {

                        if (policy.EnablePeakOffPeakFares.ToBool())
                        {
                            FareMessage = "PeakOff Peak Fares";
                        }
                        else
                        {
                            FareMessage = "Mileage Fares";

                        }

                    }

                    decimal drvWaitingCharges = 0.00m;
                    decimal drvAccWaitingCharges = 0.00m;
                    string navigationApp = "4";

                    string manualFares = (obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableManualFares == true ? "1" : "0");
                    if (obj.fleetDriver.Fleet_Driver_PDASettings[0].NavigationApp == 1)
                        navigationApp = "1";
                    else if (obj.fleetDriver.Fleet_Driver_PDASettings[0].NavigationApp == 2)
                        navigationApp = "2";
                    else if (obj.fleetDriver.Fleet_Driver_PDASettings[0].NavigationApp == 3)
                        navigationApp = "3";
                    else if (obj.fleetDriver.Fleet_Driver_PDASettings[0].NavigationApp == 4)
                        navigationApp = "5";
                    if (obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableOptionalManualFares == true && obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableManualFares == true)
                        manualFares = "2";
                    if (obj.fleetDriver.Fleet_Driver_PDASettings[0].EnableJobExtraCharges == true)
                    {
                        var obj1 = General.GetObject<Fleet_VehicleType>(c => c.DriverWaitingChargesPerHour != null && c.DriverWaitingChargesPerHour > 0);
                        if (obj1 != null)
                        {
                            drvWaitingCharges = obj1.DriverWaitingChargesPerHour.ToDecimal();
                            drvAccWaitingCharges = obj1.AccountWaitingChargesPerHour.ToDecimal();
                        }
                    }

                    //btnUpdateSettings.Enabled = false;

                    StringBuilder contents = new StringBuilder();
                    contents.Append("update settings<<<");


                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFleetDriverbtnUpdateSetting2.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + Environment.NewLine);
                    }
                    catch
                    {
                    }

