        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetAdminDashboardBookingGraph")]
        public JsonResult GetAdminDashboardBookingGraph(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    int Month = obj.Month.ToInt(); ;
                    int Year = obj.Year.ToInt();
                    int User_Id = obj.UserId.ToInt();
                    string DayName = obj.DayName == null ? "" : obj.DayName;
                    string DateType = obj.DateType == null ? "" : obj.DateType;
                    string ReportType = obj.ReportType == null ? "" : obj.ReportType;
                    DateTime from = obj.Fromdate.ToDateTime();
                    DateTime till = obj.Todate.ToDateTime();


                    //FromDate = obj.Fromdate.ToDateTime();
                    //TillDate = obj.Todate.ToDateTime();


                    //FromDate
                    //ToDate
                    //ReportType
                    //DateType


                    string DateStatus = "";
                    DateTime FromDate = DateTime.Now.ToDate();
                    DateTime TillDate = DateTime.Now.ToDate();
                    DateTime Last_WK_FromDate = DateTime.Now.ToDate();
                    DateTime Last_WK_TillDate = DateTime.Now.ToDate();


                    if (DateType == "CURRENT_WEEK")
                    {
                        FromDate = DateTime.Now.GetStartOfCurrentWeek().ToDate();
                        TillDate = DateTime.Now.GetEndOfCurrentWeek().ToDate();
                        Last_WK_FromDate = DateTime.Now.GetStartOfCurrentWeek().ToDate().AddDays(-7);
                        Last_WK_TillDate = DateTime.Now.GetStartOfCurrentWeek().ToDate().AddDays(-1);

                        DateStatus = " For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());

                    }
                    //else if (DateType == "LAST_WEEK")
                    //{

                    //}
                    else if (DateType == "MONTHLY")
                    {
                        FromDate = new DateTime(Year, Month, 1);

                        TillDate = new DateTime(Year, Month, DateTime.DaysInMonth(Year, Month));


                        //Last_WK_FromDate = new DateTime(Year, Month - 1, 1);

                        //Last_WK_TillDate = new DateTime(Year, Month - 1, DateTime.DaysInMonth(Year, Month - 1));

                        DateStatus = " For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());
                    }

                    else if (DateType == "Datewise")
                    {
                        FromDate = from;

                        TillDate = till;


                        //Last_WK_FromDate = new DateTime(Year, Month - 1, 1);

                        //Last_WK_TillDate = new DateTime(Year, Month - 1, DateTime.DaysInMonth(Year, Month - 1));

                        DateStatus = " For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());
                    }

                    else if (DateType == "DAILY")
                    {
                        FromDate = DateTime.Today.ToDateTime();
                        TillDate = DateTime.Now.ToDateTime();

                        DateStatus = "For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());
                    }

                    FromDate = FromDate.ToDate();
                    TillDate = TillDate.ToDate() + TimeSpan.Parse("23:59:59");



                    //   var query = db.ExecuteQuery<AdminGraphCount>("exec SP_GetAdminDashBoardJobsNew").ToList();
                    var query = db.ExecuteQuery<AdminGraphCount>("exec SP_GetAdminDashBoardJobsNew {0},{1},{2},{3},{4},{5},{6}", User_Id, DayName, ReportType, FromDate, TillDate, Last_WK_FromDate, Last_WK_TillDate).ToList();
                    response.Data = new
                    {
                        AdminDashboardGraphCount = query
                    };
                }
            }
            catch (Exception ex)
            {
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


