        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveSubCompanyRecord")]
        public JsonResult SaveSubCompanyRecord(AdminApi obj, HttpPostedFileBase file, string base64File)
        {
            SubCompanyBO objSubCompany = new SubCompanyBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveSubCompanyRecord.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    //int? Id = obj.fleetVehicleType.Id;
                    int? Id = obj.SubCompany.Id;
                    if (Id == 0)
                    {
                        Gen_SubCompany obj_SubCompany = General.GetQueryable<Gen_SubCompany>(null).OrderByDescending(c => c.Id).FirstOrDefault();
                        objSubCompany.New();
                    }
                    else
                    {
                        objSubCompany.GetByPrimaryKey(Id);
                        objSubCompany.Edit();
                    }
                    if (objSubCompany.Current != null)
                    {
                        if (file != null)
                        {
                            using (BinaryReader br = new BinaryReader(file.InputStream))
                            {
                                //objSubCompany.Current.CompanyLogo = new System.Data.Linq.EntitySet<Fleet_Driver_Image>();
                                byte[] uploadedFile = br.ReadBytes(file.ContentLength);
                                objSubCompany.Current.CompanyLogo = uploadedFile;
                            }
                        }
                        else if (!string.IsNullOrEmpty(base64File))
                        {
                            byte[] uploadedFile = Convert.FromBase64String(base64File);
                            objSubCompany.Current.CompanyLogo = uploadedFile;
                        }
                        objSubCompany.Current.CompanyName = obj.SubCompany.CompanyName.ToStr().Trim();
                        objSubCompany.Current.EmailAddress = obj.SubCompany.EmailAddress.ToStr().Trim();
                        objSubCompany.Current.Address = obj.SubCompany.Address.ToStr().Trim();
                        objSubCompany.Current.TelephoneNo = obj.SubCompany.TelephoneNo.ToStr().Trim();
                        objSubCompany.Current.EmergencyNo = obj.SubCompany.EmergencyNo.ToStr().Trim();
                        objSubCompany.Current.WebsiteUrl = obj.SubCompany.WebsiteUrl.ToStr().Trim();
                        objSubCompany.Current.Fax = obj.SubCompany.Fax.ToStr().Trim();
                        objSubCompany.Current.EmailCC = obj.SubCompany.EmailCC.ToStr().Trim();
                        objSubCompany.Current.IsSysGen = false;
                        // objSubCompany.Current.CompanyLogo = obj.SubCompany.CompanyLogo;
                        objSubCompany.Current.BankName = obj.SubCompany.BankName.ToStr().Trim();
                        objSubCompany.Current.AccountNo = obj.SubCompany.AccountNo.ToStr().Trim();
                        objSubCompany.Current.AccountTitle = obj.SubCompany.AccountTitle.ToStr().Trim();
                        objSubCompany.Current.CompanyNumber = obj.SubCompany.CompanyNumber.ToStr().Trim();
                        objSubCompany.Current.CompanyVatNumber = obj.SubCompany.CompanyVatNumber.ToStr().Trim();
                        objSubCompany.Current.SortCode = obj.SubCompany.SortCode.ToStr().Trim();
                        objSubCompany.Current.IbanNumber = obj.SubCompany.IbanNumber.ToStr().Trim();
                        objSubCompany.Current.BlcNumber = obj.SubCompany.BlcNumber.ToStr().Trim();
                        objSubCompany.Current.BackgroundColor = obj.SubCompany.BackgroundColor.ToInt();
                        objSubCompany.Current.MapIcon = obj.SubCompany.MapIcon.ToStr().Trim();
                        objSubCompany.Current.SmtpHasSSL = obj.SubCompany.SmtpHasSSL == null ? false : obj.SubCompany.SmtpHasSSL;
                        objSubCompany.Current.SmtpHost = obj.SubCompany.SmtpHost == null ? "" : obj.SubCompany.SmtpHost;
                        objSubCompany.Current.SmtpPassword = obj.SubCompany.SmtpPassword.ToStr().Trim();
                        objSubCompany.Current.SmtpPort = obj.SubCompany.SmtpPort.ToStr().Trim();
                        objSubCompany.Current.SmtpUserName = obj.SubCompany.SmtpUserName.ToStr().Trim();
                        objSubCompany.Current.UseDifferentEmailForInvoices = obj.SubCompany.UseDifferentEmailForInvoices;
                        objSubCompany.Current.SmtpInvoiceUserName = obj.SubCompany.SmtpInvoiceUserName.ToStr().Trim();
                        objSubCompany.Current.SmtpInvoicePassword = obj.SubCompany.SmtpInvoicePassword.ToStr().Trim();
                        objSubCompany.Current.SmtpInvoiceHost = obj.SubCompany.SmtpInvoiceHost.ToStr().Trim();
                        objSubCompany.Current.SmtpInvoicePort = obj.SubCompany.SmtpInvoicePort.ToStr().Trim();
                        objSubCompany.Current.SmtpInvoiceSSL = obj.SubCompany.SmtpInvoiceSSL;
                        objSubCompany.Current.DisableAcceptEmail = obj.SubCompany.DisableAcceptEmail;
                        objSubCompany.Current.DisableDeclineEmail = obj.SubCompany.DisableDeclineEmail;
                        objSubCompany.Current.ConnectionString = obj.SubCompany.ConnectionString.ToStr().Trim();
                        objSubCompany.Current.AccountEmailCC = obj.SubCompany.AccountEmailCC.ToStr().Trim();
                        objSubCompany.Current.DefaultCounty = obj.SubCompany.DefaultCounty.ToStr().Trim();
                        objSubCompany.Current.DeadMileage = obj.SubCompany.DeadMileage;
                        objSubCompany.Current.DeadMileageType = obj.SubCompany.DeadMileageType.ToInt();
                        objSubCompany.Save();


                        bool AmountWise = false;
                        if (db.Gen_ServiceCharges.Where(c => c.SubCompanyId == objSubCompany.Current.Id).Count() == 0)
                        {

                            Gen_ServiceCharge objServiceCharge = new Gen_ServiceCharge();
                            objServiceCharge.SubCompanyId = objSubCompany.Current.Id;
                            if (obj.SubCompanyBookingFees.ToDecimal() > 0)
                            {
                                AmountWise = true;
                            }
                            objServiceCharge.AmountWise = AmountWise; //chkAmount.Checked;

                            objServiceCharge.ServiceChargePercent = 0;
                            objServiceCharge.ServiceChargeAmount = obj.SubCompanyBookingFees.ToDecimal();

                            db.Gen_ServiceCharges.InsertOnSubmit(objServiceCharge);
                            db.SubmitChanges();
                        }
                        else
                        {
                            // int Id = db.Gen_ServiceCharges.Where(c => c.SubCompanyId == objMaster.Current.Id).FirstOrDefault().Id;
                            var query = db.Gen_ServiceCharges.FirstOrDefault(c => c.SubCompanyId == objSubCompany.Current.Id);
                            if (obj.SubCompanyBookingFees.ToDecimal() > 0)
                            {
                                AmountWise = true;
                            }
                            query.AmountWise = AmountWise;

                            query.ServiceChargePercent = 0;
                            query.ServiceChargeAmount = obj.SubCompanyBookingFees.ToDecimal();



                            db.SubmitChanges();
                        }





                        response.Data = "";
                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objSubCompany.Errors.Count > 0)
                {
                    response.Message = objSubCompany.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }



        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetFareVehicleTypesClickData")]
        public JsonResult GetFareVehicleTypesClickData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                //--
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    Fare listOfData = General.GetObject<Fare>(c => c.VehicleTypeId == obj.fleetVehicleType.Id);
                    var Fare_OtherCharges = listOfData.Fare_OtherCharges.Select(x => new Fare_OtherCharge
                    {
                        Id = x.Id,
                        CompanyRate = x.CompanyRate,
                        FareId = x.FareId,
                        FromEndTime = x.FromEndTime,
                        FromMile = x.FromMile,
                        FromStartTime = x.FromStartTime,
                        NightTimeRate = x.NightTimeRate,
                        OffPeakTimeRate = x.OffPeakTimeRate,
                        PeakTimeRate = x.PeakTimeRate,
                        Rate = x.Rate,
                        TillEndTime = x.TillEndTime,
                        TillStartTime = x.TillStartTime,
                        ToMile = x.ToMile,
                    });


                    var Fare_PDAMeters = listOfData.Fare_PDAMeters.Select(x => new Fare_PDAMeter
                    {
                        Id = x.Id,
                        FareId = x.FareId,
                        FromMile = x.FromMile,
                        ToMile = x.ToMile,
                        Rate = x.Rate,
                        PeakTimeRate = x.PeakTimeRate,
                        OffPeakTimeRate = x.OffPeakTimeRate,
                        NightTimeRate = x.NightTimeRate,
                        FromStartTime = x.FromStartTime,
                        TillStartTime = x.TillStartTime,
                        FromEndTime = x.FromEndTime,
                        TillEndTime = x.TillEndTime,
                        CompanyRate = x.CompanyRate,
                    });

                    var Fare_ZoneWisePricings = listOfData.Fare_ZoneWisePricings.Select(x => new Fare_ZoneWisePricing
                    {
                        Id = x.Id,
                        FareId = x.FareId,
                        FromZoneId = x.FromZoneId,
                        ToZoneId = x.ToZoneId,
                        Price = x.Price,
                        CompanyRate = x.CompanyRate

                    });

                    //--

                    //--

                    //var Fare_ChargesDetails = listOfData.Fare_ChargesDetails;
                    //var Fare_PDAMeters = listOfData.Fare_PDAMeters;                     
                    var FromDayName = listOfData.FromDayName;
                    var FromDateTime = String.Format("{0:dd/MM/yyyy}", listOfData.FromDateTime);
                    var AddBy = listOfData.AddBy;
                    var CompanyId = listOfData.CompanyId;
                    var DayValue = listOfData.DayValue;
                    var EditBy = listOfData.EditBy;
                    var EditOn = String.Format("{0:dd/MM/yyyy HH:mm:ss}", listOfData.EditOn);
                    var Gen_Company = listOfData.Gen_Company;
                    var Id = listOfData.Id;
                    var isCompanyWise = listOfData.IsCompanyWise;
                    var isDayWise = listOfData.IsDayWise;
                    var isVehicleWise = listOfData.IsVehicleWise;
                    var PerMinJourneyCharges = listOfData.PerMinJourneyCharges;
                    var SpecialDayName = listOfData.SpecialDayName;
                    var StartRate = listOfData.StartRate;
                    var StartRateValidMiles = listOfData.StartRateValidMiles;
                    var SubCompanyId = listOfData.SubCompanyId;
                    var TillDateTime = String.Format("{0:dd/MM/yyyy}", listOfData.TillDateTime);
                    var TillDayName = listOfData.TillDayName;
                    var TillSpecialDate = String.Format("{0:dd/MM/yyyy HH:mm:ss}", listOfData.TillSpecialDate);
                    var VehicleTypeId = listOfData.VehicleTypeId;
                    var Gen_Company_AgentCommissions = listOfData.Gen_Company_AgentCommissions;

                    var VehicleType = listOfData.Fleet_VehicleType.VehicleType;


                    var Companies = from a in db.Gen_Companies
                                    join b in db.Gen_SubCompanies on a.SubCompanyId equals b.Id into table2
                                    from b in table2.DefaultIfEmpty()
                                    where a.SubCompanyId == SubCompanyId
                                    select new
                                    {
                                        Id = a.Id,
                                        Code = a.CompanyCode,
                                        AccountName = a.CompanyName,
                                        AccountType = a.AccountType.AccountTypeName,
                                        Address = a.Address,
                                        Email = a.Email,
                                        Telephone = a.TelephoneNo,
                                        Mobile = a.MobileNo,
                                        ContactName = a.ContactName,
                                        SubCompanyId = a.SubCompanyId,
                                        SubCompany = b != null ? b.CompanyName : "",
                                        CompanyName = a != null ? a.CompanyName : ""
                                    };

                    //response.Data = new { FareDetail = listOfData };
                    //response.Data = listOfData;
                    response.Data = new
                    {
                        FromDayName = FromDayName,
                        FromDateTime = FromDateTime,
                        AddBy = AddBy,
                        CompanyId = CompanyId,
                        DayValue = DayValue,
                        EditBy = EditBy,
                        EditOn = EditOn,
                        Id = Id,
                        isCompanyWise = isCompanyWise,
                        isDayWise = isDayWise,
                        isVehicleWise = isVehicleWise,
                        PerMinJourneyCharges = PerMinJourneyCharges,
                        SpecialDayName = SpecialDayName,
                        StartRate = StartRate,
                        StartRateValidMiles = StartRateValidMiles,
                        SubCompanyId = SubCompanyId,
                        TillDateTime = TillDateTime,
                        TillDayName = TillDayName,
                        TillSpecialDate = TillSpecialDate,
                        VehicleTypeId = VehicleTypeId,
                        VehicleType = VehicleType,

                        Gen_Company = Gen_Company,
                        Gen_Company_AgentCommissions = Gen_Company_AgentCommissions,
                        Fare_OtherCharges = Fare_OtherCharges,
                        Fare_PDAMeters = Fare_PDAMeters,
                        Fare_ZoneWisePricings = Fare_ZoneWisePricings,
                        Companies = Companies.ToList(),
                    };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

