        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("grdPlotWiseFare_Save")]
        public JsonResult grdPlotWiseFare_Save(AdminApi obj, HttpPostedFileBase file)
        {
            FareBO objFare = new FareBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "grdPlotWiseFare_Save.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }
                int VehicleTypeId = obj.fare.VehicleTypeId.ToInt();
                int? CompanyId = obj.fare.CompanyId.ToIntorNull();
                int SubCompanyId = obj.fare.SubCompanyId.ToInt();
                int FareId = obj.fare.Id;
                var GlobalFareId = FareId;
                var SetValue = obj.CellSetValue;
                var RowValue = obj.RowValue.ToString();
                var HeaderValue = obj.HeaderValue;
                decimal updateValue = obj.CellSetValue.ToDecimal();
                if (GlobalFareId != 0)
                {
                    grdPlotWiseFare2_Save(updateValue, RowValue, HeaderValue, GlobalFareId);
                    response.Data = "";
                }
                else
                {
                    if (FareId > 0)
                    {
                        objFare.GetByPrimaryKey(FareId);
                        objFare.Edit();
                    }
                    else
                    {
                        objFare.New();
                    }
                    objFare.SaveWithoutValidatingVehicleType = true;
                    objFare.Current.VehicleTypeId = VehicleTypeId;
                    objFare.Current.IsCompanyWise = obj.fare.IsCompanyWise;
                    objFare.Current.CompanyId = CompanyId.ToIntorNull();
                    objFare.Current.SubCompanyId = SubCompanyId.ToIntorNull();
                    objFare.Save();
                    var list = General.GetQueryable<Fare>(c => (c.VehicleTypeId == VehicleTypeId) && (c.SubCompanyId == SubCompanyId) && ((CompanyId == null || c.CompanyId == CompanyId))).ToList();
                    if (CompanyId == null)
                    {
                        list = list.Where(c => c.CompanyId == null).ToList();
                    }
                    GlobalFareId = list.FirstOrDefault().Id;
                    grdPlotWiseFare2_Save(updateValue, RowValue, HeaderValue, GlobalFareId);
                    response.Data = "";
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objFare.Errors.Count > 0)
                {
                    response.Message = objFare.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }



        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveFixedFares")]
        public JsonResult SaveFixedFares(AdminApi obj, HttpPostedFileBase file)
        {
            FareBO objFare = new FareBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFixedFares.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    foreach (var item in obj.fare.Fare_ChargesDetails)
                    {
                        decimal Rate = item.Rate.ToDecimal();
                        decimal CompanyRate = item.CompanyRate.ToDecimal();
                        int FareId = obj.fare.Id;
                        int? OriginLocationTypeId = item.OriginLocationTypeId;
                        int? DestinationLocationTypeId = item.DestinationLocationTypeId;
                        string FromAddress = item.FromAddress;
                        string ToAddress = item.ToAddress;
                        db.ExecuteQuery<int>("INSERT INTO FARE_CHARGESDETAILS (FareId,OriginLocationTypeId,DestinationLocationTypeId,FromAddress,ToAddress,Rate,CompanyRate)" +
                               "Values(" + FareId + "," + OriginLocationTypeId.ToIntorNull() + "," + DestinationLocationTypeId.ToIntorNull() + ",'" + FromAddress.ToStr().Trim() + "','" + ToAddress.ToStr().Trim() + "'," + Rate.ToDecimal() + "," + CompanyRate.ToDecimal() + ");");
                    }

                    response.Data = "";
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objFare.Errors.Count > 0)
                {
                    response.Message = objFare.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

