        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveFareGrdOtherCharges")]
        public JsonResult SaveFareGrdOtherCharges(AdminApi obj, HttpPostedFileBase file)
        {
            FareBO objFare = new FareBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFareGrdOtherCharges.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }
                int? Id = obj.fare.Id;
                if (Id == 0)
                {
                    Fare obj_Fare = General.GetQueryable<Fare>(null).OrderByDescending(c => c.Id).FirstOrDefault();
                    objFare.New();
                    objFare.Current.AddBy = obj.fare.AddBy;  //AppVars.LoginObj.LuserId.ToInt();
                    objFare.Current.AddOn = DateTime.Now;
                }
                else
                {
                    objFare.GetByPrimaryKey(Id);
                    objFare.Edit();
                }
                objFare.SaveWithoutValidatingVehicleType = true;
                objFare.Current.VehicleTypeId = obj.fare.VehicleTypeId;
                DateTime dateValue = new DateTime(1900, 1, 1, 0, 0, 0);
                objFare.Current.FromDayName = obj.fare.FromDayName;
                objFare.Current.TillDayName = obj.fare.TillDayName;
                if (obj.fare.FromDateTime != null)
                {
                    objFare.Current.FromDateTime = new DateTime(1900, 1, 1, obj.fare.FromDateTime.Value.Hour, obj.fare.FromDateTime.Value.Minute, 0);  //fromStartTime
                    objFare.Current.TillDateTime = new DateTime(1900, 1, 1, obj.fare.TillDateTime.Value.Hour, obj.fare.TillDateTime.Value.Minute, 59); //tillStartTime
                }
                objFare.Current.StartRate = obj.fare.StartRate;
                objFare.Current.StartRateValidMiles = obj.fare.StartRateValidMiles;  //StartRateMile
                objFare.Current.PerMinJourneyCharges = obj.fare.PerMinJourneyCharges;  //startRateCost
                objFare.Current.IsCompanyWise = obj.fare.IsCompanyWise; //chkCompanyWise.Checked;
                objFare.Current.CompanyId = obj.fare.CompanyId; //ddlCompany.SelectedValue.ToIntorNull();
                objFare.Current.SubCompanyId = obj.fare.SubCompanyId; //ddlSubCompanyId.SelectedValue.ToIntorNull();
                string FromDay = objFare.Current.FromDayName;
                string TillDay = obj.fare.TillDayName;
                string DayValue = string.Empty;
                int FromDayId = 0;
                int TillDayId = 0;
                if (FromDay == "Monday")
                {
                    FromDayId = 2;
                }
                else if (FromDay == "Tuesday")
                {
                    FromDayId = 3;
                }
                else if (FromDay == "Wednesday")
                {
                    FromDayId = 4;
                }
                else if (FromDay == "Thursday")
                {
                    FromDayId = 5;
                }
                else if (FromDay == "Friday")
                {
                    FromDayId = 6;
                }
                else if (FromDay == "Saturday")
                {
                    FromDayId = 7;
                }
                else if (FromDay == "Sunday")
                {
                    FromDayId = 1;
                }
                if (TillDay == "Monday")
                {
                    TillDayId = 2;
                }
                else if (TillDay == "Tuesday")
                {
                    TillDayId = 3;
                }
                else if (TillDay == "Wednesday")
                {
                    TillDayId = 4;
                }
                else if (TillDay == "Thursday")
                {
                    TillDayId = 5;
                }
                else if (TillDay == "Friday")
                {
                    TillDayId = 6;
                }
                else if (TillDay == "Saturday")
                {
                    TillDayId = 7;
                }
                else if (TillDay == "Sunday")
                {
                    TillDayId = 1;
                }
                if (FromDayId > TillDayId)
                {
                    for (int i = FromDayId; i >= TillDayId; i++)
                    {
                        if (string.IsNullOrEmpty(DayValue))
                        {
                            DayValue = i.ToStr();
                        }
                        else
                        {
                            DayValue += "," + i.ToStr();
                        }
                        if (i == 7)
                        {
                            i = 0;
                            for (int j = 1; j <= TillDayId; j++)
                            {
                                if (string.IsNullOrEmpty(DayValue))
                                {
                                    DayValue = j.ToStr();
                                }
                                else
                                {
                                    DayValue += "," + j.ToStr();
                                }
                            }
                            break;
                        }
                    }
                }
                else if (FromDayId == TillDayId)
                {
                    DayValue = FromDayId.ToStr();
                }
                else
                {
                    for (int i = FromDayId; i <= TillDayId; i++)
                    {
                        if (string.IsNullOrEmpty(DayValue))
                        {
                            DayValue = i.ToStr();
                        }
                        else
                        {
                            DayValue += "," + i.ToStr();
                        }
                    }
                }
                obj.fare.DayValue = DayValue;
                objFare.Current.DayValue = obj.fare.DayValue; //DayValue;
                objFare.Current.SpecialDayName = obj.fare.SpecialDayName;  //SpecialDayName;
                objFare.Current.IsDayWise = obj.fare.IsDayWise;  //IsSpecialDay;
                objFare.Current.FromSpecialDate = obj.fare.FromSpecialDate != null ? obj.fare.FromSpecialDate.ToDateorNull() + Convert.ToDateTime(obj.FromTimestr).ToDateTimeorNull().Value.TimeOfDay : obj.fare.FromSpecialDate.ToDateorNull();   //dtpFromSpecialTime.Value
                objFare.Current.TillSpecialDate = obj.fare.TillSpecialDate != null ? obj.fare.TillSpecialDate.ToDateorNull() + Convert.ToDateTime(obj.ToTimestr).ToDateTimeorNull().Value.TimeOfDay : obj.fare.TillSpecialDate.ToDateorNull();  //dtpTillSpecialTime.Value
                                                                                                                                                                                                                                                //? Field missing and property
                                                                                                                                                                                                                                                //objFare.Current.WaitingCharges = obj.fare.waitingcharges.Value;  //numwaitingcharges     //? Field missing and property
                                                                                                                                                                                                                                                //objFare.Current.WaitingChargesPerSeconds = obj.fare.WaitingChargesPerSeconds;  //numwaitingsecs.Value.ToInt();  //? Field missing and property
                                                                                                                                                                                                                                                //objFare.Current.WaitingSecondsFree = obj.fare.WaitingSecondsFree   //numwaitingfreemins.Value.ToInt(); //? Field missing and property
                                                                                                                                                                                                                                                //objFare.Current.ZoneId = obj.fare.ZoneId;  //? Field missing and property
                objFare.Save();

                try
                {
                    string zoneId = obj.ZoneId != null ? obj.ZoneId : "NULL";
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        db.ExecuteQuery<int>("Update Fare set ZoneId = " + zoneId + " where Id = " + objFare.Current.Id + " ");
                    }
                }
                catch
                {
                }

                //if (obj.ddlZone.Visible)
                //{
                //    string zoneId = ddlZone.SelectedValue != null ? ddlZone.SelectedValue.ToInt().ToStr() : "NULL";
                //    using (TaxiDataContext db = new TaxiDataContext())
                //    {
                //        db.ExecuteQuery<int>("Update Fare set ZoneId = " + zoneId + " where Id = " + objFare.Current.Id + " ");
                //    }
                //}
                var query = (from a in General.GetQueryable<Fare>(c => c.Id == objFare.Current.Id)
                             select new
                             {
                                 Id = a.Id,
                                 VehicleTypeId = a.VehicleTypeId,
                                 EffectiveDate = a.EffectiveDate,
                                 AddOn = a.AddOn,
                                 AddBy = a.AddBy,
                                 EditOn = a.EditOn,
                                 EditBy = a.EditBy,
                                 IsVehicleWise = a.IsVehicleWise,
                                 IsCompanyWise = a.IsCompanyWise,
                                 CompanyId = a.CompanyId,
                                 SubCompanyId = a.SubCompanyId,
                                 PerMinJourneyCharges = a.PerMinJourneyCharges,
                                 IsDayWise = a.IsDayWise,
                                 DayValue = a.DayValue,
                                 StartRate = a.StartRate,
                                 StartRateValidMiles = a.StartRateValidMiles,
                                 FromDayName = a.FromDayName,
                                 TillDayName = a.TillDayName,
                                 SpecialDayName = a.SpecialDayName,
                                 FromSpecialDate = a.FromSpecialDate,
                                 TillSpecialDate = a.TillSpecialDate,
                                 FromDateTime = a.FromDateTime,
                                 TillDateTime = a.TillDateTime
                             });
                response.Data = query;
            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objFare.Errors.Count > 0)
                {
                    response.Message = objFare.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

