        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetEditDriverCommissionList")]
        public JsonResult GetEditDriverCommissionList(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    long Id = obj.Id.ToLong();
                    var DriverCommissionData = db.ExecuteQuery<GetFleetDriverCommission>("exec Stp_GetEditDriverCommissionList {0},{1}", Id, 1).ToList();
                    //var DriverCommision_ChargesData = db.ExecuteQuery<Fleet_DriverCommision_Charges>("exec Stp_GetEditDriverCommissionList {0},{1}", Id, 2).ToList();
                    //var bookingData = db.ExecuteQuery<Booking>("exec Stp_GetEditDriverCommissionList {0},{1}", Id, 3).ToList();
                    var DriverCommExpData = db.ExecuteQuery<DriverCommisExpenses>("exec Stp_GetEditDriverCommissionList {0},{1}", Id, 4).ToList();
                    var GetDriverTypeId = db.ExecuteQuery<int>("exec Stp_GetEditDriverCommissionList {0},{1}", Id, 5).ToList();
                    //var GetBookingId = db.ExecuteQuery<long>("exec Stp_GetEditDriverCommissionList {0},{1}", Id,0, 6).ToList();
                    int? DriverId = DriverCommissionData[0].DriverId;  //obj.DriverId.ToInt();
                    DateTime? fromDate = DriverCommissionData[0].FromDate;  //obj.Fromdate;
                    DateTime? tillDate = DriverCommissionData[0].ToDate;  //obj.Todate;
                    int DriverTypeId = GetDriverTypeId[0].ToInt();    //obj.DriverTypeId.ToInt();
                    //long? BookingId = GetBookingId[0].ToInt();
                    int? AccountBookingDays = 0; // obj.AccountBookingDays.ToInt();
                    DateTime? ACCJobsTillDate = DriverCommissionData[0].FromDate;   //obj.Fromdate;
                    bool IsFareAndWaitingWiseComm = false; //obj.IsFareAndWaitingWiseComm;
                    int? PickType = 0; //obj.PickType;
                                       //if (obj.DriverTypeId == 2)
                                       //{
                    if (AccountBookingDays.ToInt() < 0)
                    {
                        ACCJobsTillDate = fromDate.Value.AddDays(-1).ToDate();
                    }
                    else
                    {
                        ACCJobsTillDate = tillDate;
                    }
                    string[] hiddenColumns = null;
                    if (!IsFareAndWaitingWiseComm)
                        hiddenColumns = new string[] {  "Id", "Parking","Destination","ExtraDrop","MeetAndGreet","Congtion",
                                                "Total","OrderNo","PupilNo","BookingDate","Description","Charges","AccountType","CompanyId","Waiting"
                                                ,"IsCommissionWise","DriverCommissionType","DriverCommission","PaymentTypeId","DropOffCharge","PickupCharge","BookingStatusId"};
                    else
                        hiddenColumns = new string[] {  "Id", "Parking","Destination","ExtraDrop","MeetAndGreet","Congtion",
                                                "Total","OrderNo","PupilNo","BookingDate","Description","Charges","AccountType","CompanyId"
                                                ,"IsCommissionWise","DriverCommissionType","DriverCommission","PaymentTypeId","DropOffCharge","PickupCharge","BookingStatusId"};
                    var policy = db.Gen_SysPolicy_Configurations.Where(m => m.SysPolicyId == 1).FirstOrDefault();
                    bool? RentForProcessedJobs = policy.RentForProcessedJobs;
                    Expression<Func<Booking, bool>> _conditionDate = null;
                    DateTime? ACCJobsFromDate = fromDate.Value.AddDays(AccountBookingDays.ToInt());
                    ACCJobsTillDate = fromDate;
                    if (PickType == 0)
                    {
                        if (policy.PickBookingOnInvoicingType.ToInt() == 2)
                        {
                            _conditionDate = b => (((b.PickupDateTime.Value.Date >= fromDate && b.PickupDateTime.Value.Date <= tillDate))) && (b.DriverId == DriverId && ((b.PaymentTypeId != Enums.PAYMENT_TYPES.CASH && b.BookingStatusId == Enums.BOOKINGSTATUS.NOPICKUP) || b.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED));
                        }
                        else if (policy.PickBookingOnInvoicingType.ToInt() == 4)
                        {
                            _conditionDate = b => (((b.PickupDateTime.Value.Date >= fromDate && b.PickupDateTime.Value.Date <= tillDate))) && (b.DriverId == DriverId && ((b.PaymentTypeId != Enums.PAYMENT_TYPES.CASH && (b.BookingStatusId == Enums.BOOKINGSTATUS.NOPICKUP || b.BookingStatusId == Enums.BOOKINGSTATUS.CANCELLED)) || b.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED));
                        }
                        else
                        {
                            _conditionDate = b => (((b.PickupDateTime.Value.Date >= fromDate && b.PickupDateTime.Value.Date <= tillDate) && b.PaymentTypeId == Enums.PAYMENT_TYPES.CASH) || ((b.PickupDateTime.Value.Date >= ACCJobsFromDate && b.PickupDateTime.Value.Date <= ACCJobsTillDate) && b.PaymentTypeId != Enums.PAYMENT_TYPES.CASH)) && (b.DriverId == DriverId && b.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED);
                        }
                    }
                    else
                    {
                        if (policy.PickBookingOnInvoicingType.ToInt() == 2)
                        {
                            _conditionDate = b => (((b.BookingDate.Value.Date >= fromDate && b.BookingDate.Value.Date <= tillDate) && b.PaymentTypeId == Enums.PAYMENT_TYPES.CASH) || ((b.BookingDate.Value.Date >= ACCJobsFromDate && b.BookingDate.Value.Date <= ACCJobsTillDate) && b.PaymentTypeId != Enums.PAYMENT_TYPES.BANK_ACCOUNT)) && (b.DriverId == DriverId && (b.BookingStatusId == Enums.BOOKINGSTATUS.NOPICKUP || b.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED));
                        }
                        else
                        {
                            _conditionDate = b => (((b.BookingDate.Value.Date >= fromDate && b.BookingDate.Value.Date <= tillDate) && b.PaymentTypeId == Enums.PAYMENT_TYPES.CASH) || ((b.BookingDate.Value.Date >= ACCJobsFromDate && b.BookingDate.Value.Date <= ACCJobsTillDate) && b.PaymentTypeId != Enums.PAYMENT_TYPES.BANK_ACCOUNT)) && (b.DriverId == DriverId && b.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED);
                        }
                    }
                    List<BookingDriverCommLister> PickBookinglist = ShowDriverCommTransactionExpense2BookingMultiListerData(c => c.DriverId == DriverId && (c.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED), hiddenColumns, _conditionDate, Id);
                    response.Data = new
                    {
                        Id = Id,
                        DriverId = DriverId.ToStr(),
                        fromDate = fromDate.ToStr(),
                        tillDate = tillDate.ToStr(),
                        DriverTypeId = DriverTypeId.ToString(),
                        DriverCommissionData = DriverCommissionData.ToList(),
                        DriverCommissionExpensesList = DriverCommExpData.ToList(), //Newtonsoft.Json.JsonConvert.SerializeObject(DriverCommExpData.ToList()),
                        PickBookinglist1 = PickBookinglist,
                        PickBookinglist = Newtonsoft.Json.JsonConvert.SerializeObject(PickBookinglist)
                    };
                }
                //}
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

