        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("UpdateDriverStatement")]
        public JsonResult UpdateDriverStatement(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            DriverRentBO objMaster = new DriverRentBO();
            DriverCommisionBO objMasterCommission = new DriverCommisionBO();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "UpdateDriverStatement.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj.DriverTypeId) + Environment.NewLine);
                }
                catch
                {
                }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    //int? DriverId = obj.DriverId;
                    //string objTransNo = obj.TransNo;
                    int? ObjDriverTypeId = obj.DriverTypeId;
                    if (obj.DriverTypeId == 1)
                    {
                        string fromAddress = obj.PickupPoint.ToStr().Trim();
                        string toAddress = obj.Destination.ToStr().Trim();
                        if (string.IsNullOrEmpty(fromAddress))
                        {
                            response.Message = "Pickup Address cannot be empty";
                            return Json(response, JsonRequestBehavior.AllowGet);
                        }
                        if (string.IsNullOrEmpty(toAddress))
                        {
                            response.Message = "Destination Address cannot be empty";
                            return Json(response, JsonRequestBehavior.AllowGet);
                        }
                        long id = obj.Id;
                        decimal fare = obj.fare.ToDecimal();
                        decimal parking = obj.parking.ToDecimal();
                        decimal waiting = obj.waiting.ToDecimal();
                        decimal extraDrop = obj.extraDrop.ToDecimal();
                        decimal bookingFee = obj.bookingFees.ToDecimal();
                        decimal agentfee = obj.AgentFees.ToDecimal();
                        BookingBO objBookngBo = new BookingBO();
                        try
                        {
                            objBookngBo.GetByPrimaryKey(id);
                            if (objBookngBo.Current != null)
                            {
                                objBookngBo.Current.FareRate = fare;
                                objBookngBo.Current.CongtionCharges = parking;
                                objBookngBo.Current.MeetAndGreetCharges = waiting;
                                objBookngBo.Current.ExtraDropCharges = extraDrop;
                                objBookngBo.Current.ServiceCharges = bookingFee;
                                if (objBookngBo.Current.CompanyId == null)
                                {
                                    objBookngBo.Current.TotalCharges = objBookngBo.Current.FareRate.ToDecimal()
                                                 + objBookngBo.Current.ExtraDropCharges.ToDecimal() + objBookngBo.Current.MeetAndGreetCharges.ToDecimal() + objBookngBo.Current.CongtionCharges.ToDecimal() + objBookngBo.Current.ServiceCharges.ToDecimal();
                                }
                                else
                                {
                                    objBookngBo.Current.TotalCharges = objBookngBo.Current.CompanyPrice.ToDecimal() + objBookngBo.Current.ParkingCharges.ToDecimal() + objBookngBo.Current.WaitingCharges.ToDecimal() + objBookngBo.Current.ExtraDropCharges.ToDecimal() + objBookngBo.Current.ServiceCharges.ToDecimal();
                                }
                                objBookngBo.Save();
                                //Moazzam Bhai please cheque below?   //??
                                //CalculateDriverStatement(AdminApi obj)
                                //CalculateTotal();
                                //long index = grdLister.CurrentRow != null ? grdLister.CurrentRow.Cells["Id"].Value.ToLong() : -1;
                                //int val = grdLister.TableElement.VScrollBar.Value;
                                //Save();
                                //if (index > 0)
                                //    grdLister.CurrentRow = grdLister.Rows.FirstOrDefault(c => c.Cells["Id"].Value.ToLong() == index);
                                //grdLister.TableElement.VScrollBar.Value = val;
                                //          CalculateBalance();
                            }
                        }
                        catch (Exception ex)
                        {
                            if (objMaster.Errors.Count > 0)
                            {
                                //ENUtils.ShowMessage(objMaster.ShowErrors());
                                response.Message = objMaster.ShowErrors();
                                return Json(response, JsonRequestBehavior.AllowGet);
                            }
                            else
                            {
                                response.Message = ex.Message;
                                return Json(response, JsonRequestBehavior.AllowGet);
                            }
                        }
                    }
                    else if (obj.DriverTypeId == 2)
                    {
                        long id = obj.Id;
                        decimal fare = obj.fares.ToDecimal();
                        decimal parking = obj.parking.ToDecimal();
                        decimal waiting = obj.waiting.ToDecimal();
                        decimal extra = obj.extraDrop.ToDecimal();
                        decimal bookingfee = obj.bookingFees.ToDecimal();
                        decimal agentfee = obj.AgentFees.ToDecimal();
                        if (bookingfee > fare)
                        {
                            response.Message = "Booking Fee cannot be greater than Fares";
                            return Json(response, JsonRequestBehavior.AllowGet);
                        }
                        BookingBO objMasterComm = new BookingBO();
                        objMasterComm.GetByPrimaryKey(id);
                        if (objMasterComm.Current != null)
                        {
                            objMasterComm.Current.FareRate = fare;
                            objMasterComm.Current.CongtionCharges = parking;
                            objMasterComm.Current.MeetAndGreetCharges = waiting;
                            objMasterComm.Current.ServiceCharges = bookingfee;
                            objMasterComm.Current.ExtraDropCharges = extra;
                            // objMaster.Current.TipAmount = tip;
                            objMasterComm.Current.AgentCommission = agentfee;
                            // objMaster.Current.TotalCharges = TotalCharges;
                            if (objMasterComm.Current.CompanyId == null)
                            {
                                objMasterComm.Current.TotalCharges = objMasterComm.Current.FareRate.ToDecimal()
                                             + objMasterComm.Current.ExtraDropCharges.ToDecimal() + objMasterComm.Current.MeetAndGreetCharges.ToDecimal() + objMasterComm.Current.CongtionCharges.ToDecimal();
                            }
                            else
                            {
                                objMasterComm.Current.TotalCharges = objMasterComm.Current.CompanyPrice.ToDecimal() + objMasterComm.Current.ParkingCharges.ToDecimal() + objMasterComm.Current.WaitingCharges.ToDecimal() + objMasterComm.Current.ExtraDropCharges.ToDecimal();
                            }
                            objMasterComm.CheckCustomerValidation = false;
                            objMasterComm.CheckDataValidation = false;
                            objMasterComm.DisableUpdateReturnJob = true;
                            objMasterComm.Save();
                            //CalculateDriverStatement(AdminApi obj)
                            // Moazzam bhai please check below???? /??
                            //decimal Total = (fare + waiting + extra);
                            //if (AppVars.objPolicyConfiguration.NoCommissionFromAccount.ToBool() && row.Cells[COLS.PaymentTypeId].Value.ToInt() == Enums.PAYMENT_TYPES.BANK_ACCOUNT)
                            //{
                            //    row.Cells[COLS.Commission].Value = 0.00m;
                            //}
                            //else
                            //{
                            //    row.Cells[COLS.Commission].Value = ((row.Cells[COLS.Fares].Value.ToDecimal() + row.Cells[COLS.Waiting].Value.ToDecimal() + row.Cells[COLS.ExtraDrop].Value.ToDecimal()) * numCommissionPercent.Value) / 100;
                            //}
                            //CalculateTotal();
                            //long index = grdLister.CurrentRow != null ? grdLister.CurrentRow.Cells["Id"].Value.ToLong() : -1;
                            //int val = grdLister.TableElement.VScrollBar.Value;
                            //Save();
                            //if (index > 0)
                            //    grdLister.CurrentRow = grdLister.Rows.FirstOrDefault(c => c.Cells["Id"].Value.ToLong() == index);
                            //grdLister.TableElement.VScrollBar.Value = val;
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objMaster.Errors.Count > 0)
                {
                    response.Message = objMaster.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

