        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("DriverCommissionSendEmail")]
        public JsonResult DriverCommissionSendEmail(DriverCommissionSendEmailRequest obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    string CustomerEmail = db.ExecuteQuery<string>("select email from Fleet_Driver where id={0}", obj.DriverId).FirstOrDefault();
                    var data = new EmailInfo2();
                    if (obj.UseDifferentEmailForInvoices.ToBool())
                    {
                        data = new EmailInfo2 { SubCompanyId = obj.SubcompanyId.ToInt(), From = db.Gen_SubCompanies.Where(c => c.Id == obj.SubcompanyId).Select(c => c.SmtpUserName).FirstOrDefault(), To = CustomerEmail, TransNo = obj.TransNo, MessageBody = "", Subject = "", CommissionId = obj.CommissionId, DriverId = obj.DriverId };
                    }
                    else
                    {
                        data = new EmailInfo2 { SubCompanyId = obj.SubcompanyId.ToInt(), From = "", To = CustomerEmail, TransNo = obj.TransNo, MessageBody = "", Subject = "", CommissionId = obj.CommissionId, DriverId = obj.DriverId };
                    }
                    response.Data = new
                    {
                        EmailInfo = data
                    };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

