                        decimal? agentFeesTotal = numAgentTotal;

                        decimal? numaccountbookingfeetotal = PickBookinglist.Where(x => x.PaymentTypeId != 1).Select(x => x.BookingFee).Sum();

                        decimal? numAccountExpenses = obj.numAccountExpenses;


                        totalCredit = (AccountjobTotal + Credit + parkingTotal + extraTotal + numAccountExpenses);
                        totalDebit = Debit + (DriverRent + agentFeesTotal + TotalpdaRent + TotalCarRent + TotalCarInsuranceRent + TotalPrimeCompanyRent);


                        owedBalance = (totalDebit - totalCredit);

                        Currentbalance = owedBalance + OldBalance;

