                                                                             PickupCharge = r.PickupCharge != null ? r.PickupCharge : 0,
                                                                             PaymentTypeId = r.PaymentTypeId,
                                                                             Payment = r.Payment,
                                                                             ServiceCharges = r.ServiceCharges != null ? r.ServiceCharges : 0,
                                                                             PickupPlot = r.PickupPlot,
                                                                             DropOffPlot = r.DropOffPlot,
                                                                             Promotion = r.Promotion != null ? r.Promotion : 0,
                                                                             BookingStatusId = r.BookingStatusId,
                                                                             StatusName = r.StatusName
                                                                         }).ToList();


                        db.CommandTimeout = 5;
                        var query = db.Fleet_Drivers.Where(c => c.Id == obj.DriverId).Select(c => c.MaxCommission).FirstOrDefault().ToDecimal();
                        var numMaxCommission = query;

                        var query2 = db.Fleet_Drivers.Where(c => c.Id == obj.DriverId).Select(c => c.NICNo).FirstOrDefault().ToDecimal();
                        var numMinCommLimit = query2.ToStr().Trim().IsNumeric() ? query2.ToStr().Trim().ToDecimal() : 0.00m;

                        //if (AppVars.listUserRights.Count(c => c.functionId == "DEBIT CONGESTION") > 0)     // ??
                        //{
                        //    AddDefeultExpenseValue();
                        //}

                        //Calculation
                        decimal Credit = 0.00m;
                        decimal Debit = 0.00m;
                        decimal totalCredit = 0.00m;
                        decimal totalDebit = 0.00m;
                        decimal owedBalance = 0.00m;
                        decimal Currentbalance = 0.00m;
                        //double totalWeeks = (dtpTillDate.Value.ToDate().Subtract(dtpFromDate.Value.ToDate()).TotalDays) / 7;
                        double? totalWeeks = (obj.Todate.Value.ToDate().Subtract(obj.Fromdate.Value.ToDate()).TotalDays) / 7;
                        if (totalWeeks <= 0)
                            totalWeeks = 1;


                        decimal numpdaRent = obj.numpdaRent.ToDecimal();
                        var TotalWeeks = totalWeeks.ToInt();
                        decimal pdaRent = numpdaRent;

                        var TotalCashBooking = string.Format("{0:£ #.##}", PickBookinglist
                        .Where(c => c.PaymentTypeId.Value.ToInt() == Enums.PAYMENT_TYPES.CASH)
                        .Sum(c => c.Fare.Value.ToDecimal() + c.Waiting.Value.ToDecimal() + c.ExtraDrop.Value.ToDecimal()));

                        // change from Total to Fare Sum
                        var TotalAccountBooking = string.Format("{0:£ #.##}", PickBookinglist
                            .Where(c => c.PaymentTypeId.Value.ToInt() != Enums.PAYMENT_TYPES.CASH)
                            .Sum(c => c.Fare.Value.ToDecimal() + c.Waiting.Value.ToDecimal() + c.ExtraDrop.Value.ToDecimal()));



                        decimal? accountjobstotal = PickBookinglist
                            .Where(c => c.PaymentTypeId.Value.ToInt() != Enums.PAYMENT_TYPES.CASH)
                            .Sum(c => c.Fare.Value.ToDecimal() + c.Waiting.Value.ToDecimal() + c.ExtraDrop.Value.ToDecimal());


                        decimal parkingTotal = PickBookinglist
                            .Where(c => c.PaymentTypeId.Value.ToInt() != Enums.PAYMENT_TYPES.CASH)
                            .Sum(c => c.Parking.Value.ToDecimal());

                        //if (AppVars.listUserRights.Count(c => c.functionId == "DEBIT CONGESTION") > 0)   // ??
                        //{
                        parkingTotal = PickBookinglist.Where(c => c.PaymentTypeId.Value.ToInt() != Enums.PAYMENT_TYPES.CASH
                                                                     && (
                                                                     c.PickupPlot.ToStr().Contains("CONGESTION") == false
                                                                      && c.DropOffPlot.ToStr().Contains("CONGESTION") == false
                                                                     )
                                                                     )
                                                                   .Sum(c => c.Parking.ToDecimal());
                        //}

                        var numParkingTotal = parkingTotal;

                        decimal extraTotal = 0.00m;

                        var numExtraTotal = extraTotal;

                        decimal numPromotion = PickBookinglist.Where(a => a.Promotion != null).Sum(c => c.Promotion.Value.ToDecimal());  ///?

                        decimal jobsFareTotal = PickBookinglist.Sum(c => c.Fare.ToDecimal() +
                        c.Waiting.Value.ToDecimal() + c.ExtraDrop.Value.ToDecimal());

                        var InvoiceAmount = string.Format("{0:£ #.##}", jobsFareTotal);



                        if (InvoiceAmount == "£ ")
                        {
                            InvoiceAmount = "£ 0";
                        }
                        if (TotalAccountBooking == "£ ")
                        {
                            TotalAccountBooking = "£ 0";
                        }

                        var CommsionTotal = obj.CommsionTotal;
                        if (CommsionTotal == "£ ")  // ??
                        {
                            CommsionTotal = "£ 0"; // ??
                        }

                        var numAgentFeeTotal = PickBookinglist.Where(c => c.PaymentTypeId.Value.ToInt() == Enums.PAYMENT_TYPES.CASH)
                                .Sum(c => (c.AgentCommission.ToDecimal()).ToDecimal());

                        numAgentFeeTotal = numAgentFeeTotal + PickBookinglist.Where(c => c.PaymentTypeId.Value.ToInt() == Enums.PAYMENT_TYPES.CASH).Sum(c => (c.ServiceCharges.Value.ToDecimal()).ToDecimal());

                        decimal NumAccountBookingFeeTotal = PickBookinglist.Where(c => c.PaymentTypeId.ToInt() != Enums.PAYMENT_TYPES.CASH).Sum(c => (c.ServiceCharges.Value.ToDecimal()).ToDecimal());

                        decimal JobTotal = InvoiceAmount.TrimStart('£', ' ').ToDecimal();
                        CommsionTotal = "0.00";

                        decimal commissionTotal = 0.00m;

                        //commissionTotal = GetCommissionTotal(jobsFareTotal, numAgentFeeTotal, numCommissionPercent, PickBookinglist);
                        //rtn = Math.Round(PickBookinglist.Sum(c => c.Commission.Commission.Value.ToDecimal()), 2);  //  temparary value define // ?

                        commissionTotal = Math.Round(PickBookinglist.Sum(c => c.DriverCommission.Value.ToDecimal()), 2);

                        //MaxCommission
                        if (numMaxCommission > 0 && commissionTotal > numMaxCommission)
                        {
                            commissionTotal = numMaxCommission;
                        }

                        if (numMinCommLimit > 0 && commissionTotal < numMinCommLimit && PickBookinglist.Count > 0)
                        {
                            commissionTotal = numMinCommLimit;
                        }

                        decimal numVAT = 0; // temarary define //?? /?

                        if (numVAT > 0)
                        {
                            commissionTotal = commissionTotal + Math.Round(((commissionTotal * numVAT) / 100), 2);

                        }

                        CommsionTotal = commissionTotal.ToStr();

                        decimal owed = Math.Round((pdaRent + numAgentFeeTotal + commissionTotal) - TotalAccountBooking.TrimStart('£', ' ').ToDecimal(), 2);

                        //
                        decimal DriverOwed = owed;
                        if (obj.DriverCommissionExpenseList != null)
                        {
                            List<Fleet_DriverCommissionExpense> DriverCommissionExpense = (from a in obj.DriverCommissionExpenseList
                                                                                           select new Fleet_DriverCommissionExpense
                                                                                           {
                                                                                               Id = a.Id.ToLong(),
                                                                                               CommissionId = a.CommissionId.ToLong(),
                                                                                               Debit = Debit.ToDecimal(),
                                                                                               Credit = a.Credit.ToDecimal(),
                                                                                               Amount = a.Amount.ToDecimal(),
                                                                                               Description = a.Description.ToStr(),
                                                                                               Date = a.Date.ToDateTimeorNull(),
                                                                                               AddBy = a.AddBy.ToStr()
                                                                                           }).ToList();
                            if (DriverCommissionExpense.Count > 0)
                            {
                                Debit = DriverCommissionExpense.Sum(c => c.Debit.ToDecimal());
                                Credit = DriverCommissionExpense.Sum(c => c.Credit.ToDecimal());
                                totalDebit = (commissionTotal + numpdaRent + obj.numCollectionDeliveryAmount.ToDecimal() + numAgentFeeTotal + Debit);
                                totalCredit = (TotalAccountBooking.TrimStart('£', ' ').ToDecimal() + obj.spnAccountExpenses.ToDecimal() + parkingTotal + extraTotal + +numPromotion + Credit);
                                owedBalance = (totalDebit - totalCredit);
                            }

                        }

                        DriverOwed = owedBalance;
                        decimal OldBalance = obj.OldBalance.ToDecimal();

                        totalDebit += OldBalance;   //OldBalance.TrimStart('£', ' ').ToDecimal();
                        Currentbalance = (totalDebit - totalCredit);
                        decimal Balance = Currentbalance;

                        response.Data = new
                        {
                            totalWeeks = totalWeeks,
                            numpdaRent = numpdaRent,
                            TotalWeeks = TotalWeeks,
                            pdaRent = pdaRent,
                            TotalCashBooking = TotalCashBooking,
                            TotalAccountBooking = TotalAccountBooking,
                            parkingTotal = parkingTotal,

                            extraTotal = extraTotal,
                            numPromotion = numPromotion,
                            jobsFareTotal = jobsFareTotal,
                            InvoiceAmount = InvoiceAmount,
                            CommsionTotal = CommsionTotal,
                            numAgentFeeTotal = numAgentFeeTotal,
                            NumAccountBookingFeeTotal = NumAccountBookingFeeTotal,
                            JobTotal = JobTotal,
                            commissionTotal = commissionTotal,
                            DriverOwed = DriverOwed,
                            OldBalance = OldBalance,
                            totalDebit = totalDebit,
                            Currentbalance = Currentbalance,
                            AccountjobTotal = accountjobstotal,
                            AccountTotal = accountjobstotal
                        };
                    }
                }

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }


            return Json(response, JsonRequestBehavior.AllowGet);

        }

