        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("InsertZone")]
        public JsonResult InsertZone(Gen_Zones request)
        {

            try
            {
                //

                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\InsertZone.txt", DateTime.Now + ",json:" + request.Gen_Zone_PolyVertices.Count + Environment.NewLine);
            }
            catch
            { }



            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                request.MinLatitude = request.Gen_Zone_PolyVertices.Min(a => a.Latitude);
                request.MaxLatitude = request.Gen_Zone_PolyVertices.Max(a => a.Latitude);
                request.MinLongitude = request.Gen_Zone_PolyVertices.Min(a => a.Longitude);
                request.MaxLongitude = request.Gen_Zone_PolyVertices.Max(a => a.Longitude);
                string Msg = General.AddZone(request);
                response.Message = "success";
                response.Data = Msg;

                General.RecyclePool();
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
