        private Gen_SubCompany objSubcompany;
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SendEmail")]
        public JsonResult SendEmail(AdminApi obj, HttpPostedFileBase file)
        {

            string ToEmail = obj.toEmail;
            string EmailSubject = obj.emailSubject;
            string from = obj.fromEmail;
            string base64File = obj.base64File;
            string fileName = obj.fileName;
            string body = obj.emailBody;
            if (body.Length == 0 || body == null)
                body = EmailSubject;
            body = body.Replace("\r\n", "<br/>").Trim();
            //if (objSubcompany == null)
            //{
            //    objSubcompany = AppVars.objSubCompany;
            //}
            if (obj.SubCompanyId > 0)
            {
                objSubcompany = new TaxiDataContext().Gen_SubCompanies.FirstOrDefault(x => x.Id == obj.SubCompanyId.ToInt());
            }
            if (objSubcompany == null || string.IsNullOrEmpty(objSubcompany?.SmtpUserName.ToStr()) || string.IsNullOrEmpty(objSubcompany?.SmtpPassword.ToStr()) || string.IsNullOrEmpty(objSubcompany?.SmtpHost.ToStr()))
            {
                objSubcompany = new TaxiDataContext().Gen_SubCompanies.FirstOrDefault();
            }
            if (objSubcompany != null)
            {
                objSubcompany.IsTpCompany = /*ReportViewer1.Tag.ToStr() == "invoice" &&*/ objSubcompany != null && objSubcompany.UseDifferentEmailForInvoices.ToBool() ? true : false;
            }
            string exportType = obj.exportType;
            byte[] pdfBytes = Convert.FromBase64String(base64File);
            MemoryStream pdfStream = new MemoryStream(pdfBytes);
            Attachment pdfAttachment = new Attachment(pdfStream, fileName);
            List<Attachment> attachments = new List<Attachment>();
            attachments.Add(pdfAttachment);
            ClsEmail Email = new ClsEmail();
            ClsEmail.Send(EmailSubject, body, from, ToEmail, attachments, objSubcompany, "");
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    db.ExecuteCommand("exec insertInSendEmail {0}, {1}, {2}, {3}",
                        EmailSubject,
                        body,
                        string.IsNullOrWhiteSpace(obj.UserName) ? obj.user.UserName : obj.UserName,
                        ToEmail);
                }
            }
            catch (Exception ex)
            {
            }
            ///////save file for testing
            //byte[] fileBytes = new byte[file.ContentLength];
            //file.InputStream.Read(fileBytes, 0, file.ContentLength);
            // Save the file to disk
            //string filePath = Server.MapPath("~/" + file.FileName);
            //System.IO.File.WriteAllBytes(filePath, fileBytes);
            //EmailReport(exportType.ToLower(), from, ToEmail, EmailSubject, body);
            //  EmailReport(exportType.ToLower(), from, ToEmail, EmailSubject, body);
            //ClsEmail objEmail = new ClsEmail();
            //objEmail.Send(EmailSubject, body, from, ToEmail, file, obj.Subcompany, "filename");
            //EmailReport(exportType.ToLower(), from, ToEmail, EmailSubject, body);
            return Json(0, JsonRequestBehavior.AllowGet);
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("TestSendEmail")]
        public JsonResult TestSendEmail(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                Gen_SubCompany obj_SubCompany = General.GetQueryable<Gen_SubCompany>(null).Where(a => a.Id == obj.SubCompanyId).FirstOrDefault();
                if (obj_SubCompany == null) { response.HasError = true; return Json(response, JsonRequestBehavior.AllowGet); }

                bool IsEmailVerified = ClsEmail.TestEmailSetting(obj.emailSubject, obj.fromEmail, obj.toEmail, obj_SubCompany);
                if (IsEmailVerified) { response.HasError = false; } else { response.HasError = true; }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;

            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("AllDriverCommissionStatementDelete")]
        public JsonResult ALlDriverCommissionStatementDelete(AdminApi obj)
        {
            //
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\AllDriverCommissionStatementDelete.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var Id = obj.Id;
                    db.stp_RunProcedure("delete from Fleet_DriverCommision where Id in(" + Id + ")");
                    response.Data = "";
                }
            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\AllDriverCommissionStatementDelete.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                response.Message = ex.Message;
            }
            return new CustomJsonResult { Data = response };
        }

