        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("AllDriverCommissionDisplayCommissionList")]
        public JsonResult AllDriverCommissionDisplayCommissionList(AllDriverCommissionGetDisplayCommissionRequest obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    DateTime? fromDate = obj.RentFromDateTime.ToDateTimeorNull();
                    DateTime? tillDate = obj.RentToDateTime.ToDateTimeorNull();
                    int driverId = obj.Id[0].ToInt();
                    decimal CommissionDue = 0;
                    //int DriverId = 0;
                    decimal DriverCommissionPerBooking = 0.00m;
                    decimal pdaRent = 0.00m;
                    decimal collectionCharges = 0.00m;
                    decimal oldBalance = 0.00m;
                    decimal AgentCommission = 0;
                    decimal MaxCommission = 0, MinCommission = 0;
                    var listofDrivers = (from a in General.GetQueryable<Fleet_Driver>(c => c.DriverTypeId == 2 && c.IsActive == true)
                                         select new
                                         {
                                             a.Id,
                                             a.MaxCommission,
                                             a.NICNo
                                         }).ToList();
                    List<int> drivers = new List<int>();
                    drivers = obj.Id.ToList();
                    //List<int> listofDriversToGenerate = selectedRows.Select(c => c.Cells["Id"].Value.ToInt()).ToList<int>();      //id List
                    //string drivers = string.Join(",", listofDriversToGenerate);
                    string driverString = string.Join(",", drivers);
                    //List<stp_getDriverListForGeneratingCommResult> driverCommissionList = null;    // ?
                    List<stp_getDriverListForGeneratingCommResult2> AddAllDriverCommissionDataList = null;
                    List<long?> BookingIds = null;
                    tillDate = tillDate.ToDate();
                    tillDate = tillDate + new TimeSpan(23, 59, 59);
                    //using (TaxiDataContext db = new TaxiDataContext())
                    //{
                    //AddAllDriverCommissionDataList = db.ExecuteQuery<stp_AddAllDriverCommissionList>("exec stp_getDriverListForGeneratingComm {0},{1},{2},{3}"
                    //    , drivers, fromDate, tillDate, AppVars.objPolicyConfiguration.PickBookingOnInvoicingType.ToInt()).ToList();

                    var driverCommissionList = db.ExecuteQuery<stp_getDriverListForGeneratingCommResult2>("exec stp_getDriverListForGeneratingComm {0},{1},{2},{3}"
                        , driverString, fromDate, tillDate, obj.PickBookingOnInvoicingType.ToInt()).ToList();
                    BookingIds = db.Fleet_DriverCommision_Charges.Where(c => c.BookingId != null && c.TransId != 0).Select(c => c.BookingId).ToList();
                    double totalWeeks = (tillDate.ToDate().Subtract(fromDate.ToDate()).TotalDays) / 7;
                    if (totalWeeks < 0)
                        totalWeeks = 1;
                    //var list = db.stp_AddAllDriverCommission(fromDate, tillDate).Where(c => (subCompanyId == 0 || c.SubcompanyId == subCompanyId)).ToList();
                    var DriverCommission = db.ExecuteQuery<stp_AddAllDriverCommission>("exec stp_AddAllDriverCommission {0},{1}", fromDate, tillDate).ToList();

                    List<DisplayCommissionDataList> DisplayCommissionData = new List<DisplayCommissionDataList>();
                    //for 

                    for (int i = 0; i < drivers.Count; i++)
                    {
                        var row = DriverCommission.Where(c => c.Id == drivers[i].ToInt()).ToList();
                        int DriverId = row[0].Id.ToInt();
                        DriverCommissionPerBooking = row[0].DriverCommissionPerBooking.ToDecimal();
                        pdaRent = row[0].PDARent.ToDecimal();
                        collectionCharges = row[0].CollectionCharges.ToDecimal();
                        decimal TotalPDARent = (pdaRent * totalWeeks.ToInt());
                        decimal TotalCollectionCharges = (collectionCharges * totalWeeks.ToInt());
                        //if (row[0].Hokiday.Value.ToBool())
                        bool Holiday = db.ExecuteQuery<bool>("select Top 1 Holyday = WeekOff from Fleet_DriverCommision where id in (select MAX(id) as CommissionId from Fleet_DriverCommision where driverid = {0})", DriverId).FirstOrDefault();
                        //string CustomerEmail = db.ExecuteQuery<string>("select email from Fleet_Driver where id={0}", obj.DriverId).FirstOrDefault();
                        if (Holiday == true)
                        //if (Holiday.Frist().ToBool())
                        {
                            pdaRent = 0.00m;
                            collectionCharges = 0.00m;
                            TotalPDARent = 0.00m;
                            TotalCollectionCharges = 0.00m;
                        }
                        oldBalance = row[0].OldBalance.ToDecimal();
                        MaxCommission = listofDrivers.Where(c => c.Id == DriverId).FirstOrDefault().MaxCommission.ToDecimal();
                        var minCom = listofDrivers.Where(c => c.Id == DriverId).FirstOrDefault().NICNo.ToStr();
                        if (minCom.ToStr().Trim().IsNumeric())
                            MinCommission = minCom.ToDecimal();
                        else
                            MinCommission = 0;
                        CommissionDue = 0;
                        var list3 = (from a in driverCommissionList
                                     join b in BookingIds on a.Id equals b into table2
                                     from b in table2.DefaultIfEmpty()
                                     where (b == null) && a.Driverid == DriverId
                                     select new
                                     {
                                         a.Id,
                                         a.TotalFare,
                                         a.CompanyId,
                                         a.AccountTypeId,
                                         a.DriverCommissionAmount,
                                         a.DriverCommissionType,
                                         a.IsCommissionWise,
                                         a.AgentCommission,
                                         a.DropOffCharge,
                                         a.PickupCharge,
                                         a.Parking,
                                         a.BookingFee,
                                         a.ExtraDropCharges,
                                         a.PickupPlot,
                                         a.DropOffPlot,
                                         a.PaymentTypeId,
                                         a.Promotion
                                     }).ToList();
                        oldBalance = row[0].OldBalance.ToDecimal();
                        decimal ACCJobsTotal = list3.Where(c => c.AccountTypeId != Enums.ACCOUNT_TYPE.CASH).Sum(c => c.TotalFare).ToDecimal();
                        decimal parkingTotal = list3.Sum(c => c.Parking.ToDecimal()).ToDecimal();
                        decimal promotionTotal = list3.Where(c => c.Promotion.ToDecimal() > 0).Sum(c => c.Promotion.ToDecimal()).ToDecimal();
                        decimal subtractPromotionTotal = -(list3.Where(c => c.Promotion.ToDecimal() < 0).Sum(c => c.Promotion.ToDecimal()).ToDecimal());
                        decimal CashJobsTotal = list3.Where(c => c.AccountTypeId == Enums.ACCOUNT_TYPE.CASH).Sum(c => c.TotalFare).ToDecimal();
                        decimal JobsTotal = (ACCJobsTotal + CashJobsTotal);
                        decimal AccountExpenses = 0.00m;
                        //if (AppVars.objPolicyConfiguration.NoCommissionFromAccount.ToBool())
                        if (obj.NoCommissionFromAccount.ToBool())
                        {
                            decimal CTotal = list3.Where(c => c.PaymentTypeId != Enums.PAYMENT_TYPES.BANK_ACCOUNT).Sum(c => c.TotalFare).ToDecimal();
                            decimal AccTotal = 0;
                            DriverCommissionPerBooking = ((CTotal + AccTotal) * DriverCommissionPerBooking / 100);
                        }
                        else
                        {
                            DriverCommissionPerBooking = ((JobsTotal - subtractPromotionTotal) * row[0].DriverCommissionPerBooking.ToDecimal() / 100);
                        }
                        if (MaxCommission > 0 && DriverCommissionPerBooking > MaxCommission)
                        {
                            DriverCommissionPerBooking = MaxCommission;
                        }
                        //
                        // MinCommission
                        if (MinCommission > 0 && DriverCommissionPerBooking < MinCommission)
                        {
                            DriverCommissionPerBooking = MinCommission;
                        }
                        decimal owed = ((AgentCommission + TotalPDARent + DriverCommissionPerBooking) - ACCJobsTotal);
                        decimal PDARent = row[0].PDARent.ToDecimal();   //?
                        CommissionDue = owed;
                        decimal totalCredit = 0.00m;
                        decimal totalDebit = 0.00m;
                        int TotalJobs = list3.Count;
                        decimal BookingFees = 0.0m;
                        totalDebit = owed;
                        totalCredit = (ACCJobsTotal + AccountExpenses + parkingTotal);
                        owed = (totalDebit - totalCredit);
                        var CurrBalance1 = (owed + oldBalance);
                        var Owed1 = owed;
                        var AccountExpense1 = AccountExpenses;
                        var TotalPDARent1 = TotalPDARent;
                        var TotalCollectionAndDelivery1 = TotalCollectionCharges;
                        if (obj.chkApplyBookingFees.ToBool())
                        {
                            BookingFees = (TotalJobs * BookingFees);
                        }
                        DisplayCommissionDataList DisplayCommissionData2 = new DisplayCommissionDataList();
                        DisplayCommissionData2.Email = "";
                        DisplayCommissionData2.Id = DriverId.ToInt();
                        DisplayCommissionData2.DriverNo = 0;
                        DisplayCommissionData2.DriverCommission = DriverCommissionPerBooking;
                        DisplayCommissionData2.DriverCommissionPerBooking = DriverCommissionPerBooking;
                        DisplayCommissionData2.DriverPDARent = pdaRent;
                        DisplayCommissionData2.CommissionPay = 0.00m;
                        DisplayCommissionData2.OldBalance = oldBalance;
                        DisplayCommissionData2.InitialBalance = row[0].InitialBalance;
                        DisplayCommissionData2.SubCompanyId = row[0].SubcompanyId;
                        DisplayCommissionData2.CurrBalance = (owed + oldBalance);
                        DisplayCommissionData2.TotalPDARent = TotalPDARent;
                        DisplayCommissionData2.BookingFees = BookingFees;
                        DisplayCommissionData2.AccountsTotal = ACCJobsTotal;
                        DisplayCommissionData2.AccountExpense = AccountExpenses;
                        DisplayCommissionData2.Owed = owed;
                        DisplayCommissionData2.CommissionId = null;
                        DisplayCommissionData2.CashTotal = CashJobsTotal;
                        DisplayCommissionData2.JobsTotal = (JobsTotal);
                        DisplayCommissionData2.AgentFees = AgentCommission;
                        DisplayCommissionData2.DriverEmail = "";
                        DisplayCommissionData2.PaidPromotion = subtractPromotionTotal;
                        DisplayCommissionData2.Promotion = promotionTotal;
                        DisplayCommissionData2.CollectionAndDelivery = TotalCollectionAndDelivery1;
                        DisplayCommissionData2.TotalCollectionAndDelivery = TotalCollectionCharges;
                        DisplayCommissionData2.Holiday = Holiday.ToBool();
                        DisplayCommissionData2.VAT = 0;
                        DisplayCommissionData2.Bookings = list3.Count;
                        DisplayCommissionData.Add(DisplayCommissionData2);
                    }
                    response.Data = new
                    {
                        //AddAllDriverCommissionDataList = AddAllDriverCommissionDataList,
                        DisplayCommissionData = DisplayCommissionData.ToList()
                        //SubCompanyCount = SubCompanyCount,
                        //SubCompany = SubCompany,
                        //AddAllDriverCommission = AddAllDriverCommission
                    };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveAllDriverCommissions")]
        public JsonResult SaveAllDriverCommissions(List<SaveAllDriverCommissionRequest> obj)
        {
            bool IsSavedTrans = false;
            DateTime? fromDate = null;
            DateTime? tillDate = null;
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                var listofDrivers = (from a in General.GetQueryable<Fleet_Driver>(c => c.DriverTypeId == 2)
                                     select new
                                     {
                                         a.Id,
                                         a.MaxCommission,
                                         a.SubcompanyId,
                                         a.NICNo
                                     }).ToList();
                long transId = 0;
                decimal accJobsTotal = 0;
                decimal rentDue = 0;
                decimal currBalance = 0;
                decimal MaxCommission = 0, MinCommission = 0;
                fromDate = obj[0].RentFromDateTime;
                tillDate = obj[0].RentToDateTime;
                List<int> listofDriversToGenerate = new List<int>();
                //List<int> listofDriversToGenerate = obj.Ids.ToList();
                for (int i = 0; i < obj.Count; i++)
                {
                    listofDriversToGenerate.Add(obj[i].Id);
                }
                string drivers = string.Join(",", listofDriversToGenerate);
                List<stp_getDriverListForGeneratingCommResult2> driverCommissionList = null;
                List<long?> BookingIds = null;
                tillDate = tillDate.ToDate();
                tillDate = tillDate + new TimeSpan(23, 59, 59);
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    driverCommissionList = db.ExecuteQuery<stp_getDriverListForGeneratingCommResult2>("exec stp_getDriverListForGeneratingComm {0},{1},{2},{3}"
                        , drivers, obj[0].RentFromDateTime, obj[0].RentToDateTime, 2).ToList();
                    BookingIds = db.Fleet_DriverCommision_Charges.Where(c => c.BookingId != null && c.TransId != 0).Select(c => c.BookingId).ToList();
                }
                tillDate = tillDate.ToDate();
                ////
                List<ClsRowState> lstrowState = new List<ClsRowState>();
                foreach (var row in obj.ToList())
                {
                    ClsRowState rowState = new ClsRowState();
                    int selectedDriverId = row.Id;
                    transId = 0;
                    accJobsTotal = 0;
                    rentDue = 0;
                    currBalance = 0.00m;
                    //selectedDriverId = row;//fad - assigning driver id
                    // was live
                    //  transId = objCommissionList.FirstOrDefault(c => c.DriverId == row.Cells["Id"].Value.ToInt()).DefaultIfEmpty().Id;
                    //MaxCommission
                    MaxCommission = listofDrivers.Where(c => c.Id == selectedDriverId).FirstOrDefault().MaxCommission.ToDecimal();
                    //
                    var minCom = listofDrivers.Where(c => c.Id == selectedDriverId).FirstOrDefault().NICNo.ToStr();
                    if (minCom.ToStr().Trim().IsNumeric())
                        MinCommission = minCom.ToDecimal();
                    else
                        MinCommission = 0;
                    if (OnSave(selectedDriverId, row.OldBalance, row.DriverCommissionPerBooking, row.DriverPDARent, row.InitialBalance, row.CommissionPay, ref accJobsTotal, ref transId, ref rentDue, ref currBalance, row.Holiday, ref MaxCommission, ref MinCommission, row.VAT, BookingIds, driverCommissionList, fromDate, tillDate))
                    {
                        IsSavedTrans = true;
                        if (rowState == null)
                            rowState = new ClsRowState();
                        //rowState.row = row;
                        rowState.DriverID = selectedDriverId;
                        rowState.transId = transId;
                        rowState.accJobsTotal = accJobsTotal;
                        rowState.rentDue = rentDue;
                        rowState.currBlance = currBalance;
                        try
                        {
                            rowState.subCompanyId = listofDrivers.Where(c => c.Id == selectedDriverId).FirstOrDefault().SubcompanyId.ToInt();
                        }
                        catch
                        {
                            rowState.subCompanyId = 1;
                        }
                    }
                    else
                    {
                        rowState = null;
                    }
                    lstrowState.Add(rowState);
                }
                response.Data = lstrowState;
            }
            catch (Exception ex)
            {
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

