                    //string[] skipProperties = new string[] { "Gen_SysPolicy", "Fleet_VehicleType", "EnableForBookOnline" };

                    string[] skipProperties = new string[] { "Gen_SysPolicy", "Fleet_VehicleType", "EnableForBookOnline", "Gen_SubCompany", "Gen_SysPolicyDocumentsList" };
                    List<Gen_SysPolicy_FaresSetting> listofFares = new List<Gen_SysPolicy_FaresSetting>();

                    if (obj.Gen_SysPolicy_FaresSettings != null)
                    {
                        listofFares = (from a in obj.Gen_SysPolicy_FaresSettings
                                       select new Gen_SysPolicy_FaresSetting
                                       {
                                           Id = a.Id.ToInt(),
                                           SysPolicyId = a.SysPolicyId,
                                           IsAmountWise = a.IsAmountWise.ToBool(),
                                           Amount = a.Amount.ToDecimal(),
                                           Percentage = a.Percentage.ToInt(),
                                           VehicleTypeId = a.VehicleTypeId.ToIntorNull(),
                                           Operator = a.Operator.ToStr(),
                                           VehicleTypeName = a.VehicleTypeName
                                       }).ToList();
                    }

                    IList<Gen_SysPolicy_FaresSetting> savedListFares = sysPolicyBO.Current.Gen_SysPolicy_FaresSettings;

                    Utils.General.SyncChildCollection(ref savedListFares, ref listofFares, "Id", skipProperties);


                    try
                    {
                        List<Gen_SysPolicy_DocumentNumberSetup> listofsavedListDocNumber = (from a in obj.DocumentNumberSettings
                                                                                            select new Gen_SysPolicy_DocumentNumberSetup
                                                                                            {
                                                                                                Id = a.Id.ToInt(),//a.Cells[COL_FARES.ID].Value.ToInt(),
                                                                                                Prefix = a.Prefix, //objMaster.Current.Id,
                                                                                                StartNumber = a.StartNumber,
                                                                                                LastNumber = a.LastNumber,
                                                                                                AutoIncrement = a.AutoIncrement,
                                                                                                SysPolicyId = a.SysPolicyId,
                                                                                                DocumentId = a.DocumentId,
                                                                                                SubcompanyId = a.SubcompanyId
                                                                                            }).ToList();

                        IList<Gen_SysPolicy_DocumentNumberSetup> savedListDocNumber = sysPolicyBO.Current.Gen_SysPolicy_DocumentNumberSetups;

                        Utils.General.SyncChildCollection(ref savedListDocNumber, ref listofsavedListDocNumber, "Id", skipProperties);
                    }
                    catch (Exception)
                    {
                    }
                    sysPolicyBO.Save();

                    string clientCode = obj.CompanyName;
                    string ivrNumbers = obj.IVRInfo[0].IVRNumbers;
                    bool chkCalculateFares = obj.IVRInfo[0].CalculateFares;
                    bool chkReleaseMode = obj.IVRInfo[0].ReleaseMode;

                    string conn = Cryptography.Decrypt(System.Configuration.ConfigurationSettings.AppSettings["ConnectionString"].ToStr(), "tcloudX@@!", true);
                    conn = Cryptography.Encrypt(conn, "softeuroconnskey", true);
                    //string cloudUrl = Cryptography.Encrypt(System.Configuration.ConfigurationSettings.AppSettings["huburl"].ToStr(), "tcloudX!", true);
                    string cloudUrl = Cryptography.Encrypt(obj.HubURL, "tcloudX!", true);


                    ClsIVRCaller.SaveIVRInfo(new ClsIVRCaller.IVRInfo { ClientName = clientCode, ClientConn = conn, CloudUrl = cloudUrl, IVRNumbers = ivrNumbers, ClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr(), CalculateFares = chkCalculateFares, ReleaseMode = chkReleaseMode });
                    try
                    {
                        General.RecyclePool();

                    }
                    catch
                    {

                    }
                    response.Data = "Data save successfully";


                    General.RecyclePool();
                    Global.LoadDataList(true);
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetGeneralSetting")]
        public JsonResult GetGeneralSetting(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                string txtIVRNumbers = "";
                bool chkCalculateFares = false;
                bool chkReleaseMode = false;
                try
                {

                    ClsIVRCaller.IVRInfo ivr = ClsIVRCaller.GetIVRInfo(new ClsIVRCaller.IVRInfo { ClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr() });

                    if (ivr != null)
                    {
                        txtIVRNumbers = ivr.IVRNumbers.ToStr().Trim();
                        chkCalculateFares = ivr.CalculateFares;
                        chkReleaseMode = ivr.ReleaseMode;

                    }
                }
                catch
                {

                }
                //ClsDashboardModel data = new ClsDashboardModel();
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    if (HubProcessor.Instance.objPolicy == null)
                        HubProcessor.Instance.objPolicy = General.GetObject<Gen_SysPolicy_Configuration>(c => c.SysPolicyId == 1);

                    int defaultVehicleTypeId = HubProcessor.Instance.objPolicy.DefaultVehicleTypeId.ToInt();
                    string query = @"Select VT.Id,VT.VehicleType,FS.IsAmountWise,FS.Percentage,FS.Amount,FS.Id FareSettingId,FS.Operator,FS.VehicleTypeName from Fleet_VehicleTypes VT 
                                    Left Join Gen_SysPolicy_FaresSettings FS On VT.Id = FS.VehicleTypeId
                                    Where VT.Id != " + defaultVehicleTypeId + "" +
                                    " Order By VT.OrderNo";
                    var item = db.ExecuteQuery<FareSettingNew>(query).ToList();

                    string query1 = @"select g.Id,g.DocumentId,(select d.DocumentTitle from Gen_SysPolicyDocumentsList d where d.DocumentId = g.DocumentId) DocumentTitle,g.prefix,g.startnumber,g.lastnumber,g.SubCompanyId,(select s.companyname from gen_subcompany s where s.Id = g.SubCompanyId) CompanyName,g.SyspolicyId,g.AutoIncrement from Gen_SysPolicy_DocumentNumberSetups g ";
                    var DocumentNumber = db.ExecuteQuery<DocumentNumberSettings>(query1).ToList();

                    db.DeferredLoadingEnabled = false;
                    response.Data = new
                    {
                        GeneralTab = db.Gen_SysPolicy_Configurations.ToList(),
                        CallerId1Tab = db.CallerIdType_Configurations.ToList(),
                        CallerId2Tab = db.CallerIdVOIP_Configurations.ToList(),
                        SmsTab = db.Gen_SysPolicy_SMSConfigurations.ToList(),
                        SysPolicyConf = db.Gen_SysPolicy_Configurations.ToList(),
                        SMSConfigurations = db.Gen_SysPolicy_SMSConfigurations.ToList(),
                        smsTagList = db.SMSTags.ToList(),
                        VehicleTypeList = item,
                        txtIVRNumbers = txtIVRNumbers,
                        chkCalculateFares = chkCalculateFares,
                        chkReleaseMode = chkReleaseMode,
                        DocumentNumberSettings = DocumentNumber
                    };
                }
            }
            catch
            {
                response.HasError = true;
                response.Message = "exception occured";
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

