        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SavePaymentInvoice")]
        public JsonResult SavePaymentInvoice(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                InvoiceBO objMaster = new InvoiceBO();
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    if (obj.InvoiceId > 0)
                    {
                        objMaster.GetByPrimaryKey(obj.InvoiceId);
                    }
                    if (objMaster.PrimaryKeyValue != null)
                    {
                        objMaster.Edit();
                        objMaster.CheckDataValidation = false;
                        //objMaster.Current.CurrentBalance = obj.InvoiceCurrentBalance; //Ask from Danish Bhai
                        //objMaster.Current.PaidAmount = grdPayment.Rows.Sum(c => c.Cells[COL_PAYMENT.PAYMENT].Value.ToDecimal());
                        decimal paidAmount = obj.invoice_Payments.Sum(c => c.InvoicePayment).Value.ToDecimal();
                        string[] skipProperties = { "Invoice" };
                        IList<invoice_Payment> savedList3 = objMaster.Current.invoice_Payments;
                        List<invoice_Payment> listofDetail3 = (from r in obj.invoice_Payments
                                                               select new invoice_Payment
                                                               {
                                                                   id = r.id.ToInt(),
                                                                   invoiceId = r.invoiceId, //r.Cells[COL_PAYMENT.MASTERID].Value.ToInt(),
                                                                   InvoicePayment = r.InvoicePayment,//  r.Cells[COL_PAYMENT.PAYMENT].Value.ToDecimal(),
                                                                   Balance = r.Balance, //r.Cells[COL_PAYMENT.BALANCE].Value.ToDecimal(),
                                                                   PaymentDate = r.PaymentDate, //r.Cells[COL_PAYMENT.DATE].Value.ToDateTime(),
                                                                   //AddBy =  ,//r.Cells[COL_PAYMENT.AddBy].Value.ToStr(),
                                                                   //AddOn =  //r.Cells[COL_PAYMENT.AddOn].Value.ToDateTimeorNull(),
                                                                   //PaymentDescription =r.de // r.Cells[COL_PAYMENT.PAYMENTDESCRIPTION].Value.ToStr()
                                                               }).ToList();
                        Utils.General.SyncChildCollection(ref savedList3, ref listofDetail3, "id", skipProperties);
                        if (obj.InvoiceCurrentBalance <= 0.05m)
                        {
                            //objMaster.Current.InvoiceTotal = 0;
                            objMaster.Current.InvoicePaymentTypeID = Enums.INVOICE_PAYMENTTYPES.FULLPAID;
                            // Enums.INVOICE_PAYMENTTYPES.CUSTOM
                        }
                        else
                        {
                            //objMaster.Current.InvoiceTotal = txtBalance.Text.ToDecimal();
                            objMaster.Current.InvoicePaymentTypeID = Enums.INVOICE_PAYMENTTYPES.CUSTOM;
                        }
                        objMaster.Save();
                        db.ExecuteQuery<int>("update Invoice set CurrentBalance=" + obj.InvoiceCurrentBalance + ",PaidAmount=" + paidAmount + " where Id=" + objMaster.Current.Id + "");
                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
        decimal extraTotalValue = 0.00m;
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetPaymentInvoice")]
        public JsonResult GetPaymentInvoice(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                int? Id = obj.CompanyId;
                //  grdPayment.RowCount = 0;
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    string TemplateName = db.UM_Form_Templates.FirstOrDefault(c => c.UM_Form.FormName == "frmInvoiceReport" && c.IsDefault == true).DefaultIfEmpty().TemplateName.ToStr();
                    var item = (from a in db.Invoices.Where(c => (c.CompanyId == Id) && (obj.InvoiceId == 0 || c.Id == obj.InvoiceId))
                                orderby a.Id descending
                                select new
                                {
                                    Id = a.Id,
                                    a.InvoiceTotal,
                                    a.TotalInvoiceAmount,
                                    a.InvoiceNo,
                                    a.Gen_Company.HasVat,
                                    a.Gen_Company.VatOnlyOnAdminFees,
                                    //a.CurrentBalance,
                                    a.Gen_Company.AdminFees,
                                    a.Gen_Company.DiscountPercentage,
                                    a.Gen_Company.AdminFeeType,
                                }).FirstOrDefault();
                    //    var objCreditNote = db.InvoiceCreditNotes.Where(c => c.InvoiceId == obj.InvoiceId).Select(c => new { c.Id, c.CreditNoteTotal }).FirstOrDefault();
                    //if (item == null)
                    //{
                    //    lblMessage.Visible = true;
                    //    grdPayment.Rows.Clear();
                    //    txtInvoiceno.Text = "";
                    //    txtBalance.Value = 0;
                    //    txtInvoiceTotal.Value = 0.00m;
                    //    return;
                    //}
                    //lblMessage.Visible = false;
                    //InvoiceId = item.Id.ToInt(); ;
                    //txtInvoiceno.Text = item.InvoiceNo;
                    decimal creditNoteTotal = 0.00m;
                    //if (TemplateName.ToStr().ToLower() != "template10" && TemplateName.ToStr().ToLower() != "template49")
                    //    extraTotalValue = 0.00m;
                    decimal Total = item.InvoiceTotal.ToDecimal() - extraTotalValue;
                    decimal adminFees = item.AdminFees.ToInt();
                    decimal discountAmount = 0.00m;
                    //if (objCreditNote != null)
                    //{
                    //    creditNoteTotal = objCreditNote.CreditNoteTotal.ToDecimal();
                    //}
                    if (item.DiscountPercentage.ToDecimal() > 0)
                    {
                        // lblDiscount.Text = "Discount " + string.Format("{0:##0.##}", item.DiscountPercentage.ToDecimal()) + "%";
                        discountAmount = ((Total * item.DiscountPercentage) / 100).ToDecimal();
                        Total = Total - discountAmount;
                        if (creditNoteTotal > 0)
                        {
                            discountAmount = ((creditNoteTotal * item.DiscountPercentage) / 100).ToDecimal();
                            creditNoteTotal = creditNoteTotal - discountAmount;
                        }
                    }
                    if (item.HasVat.ToBool())
                    {
                        if (item.VatOnlyOnAdminFees.ToBool())
                        {
                            decimal fees = (Total * adminFees) / 100;
                            fees = Math.Round(fees, 2);
                            if (item.AdminFeeType.ToStr() == "Amount")
                                fees = adminFees;
                            Total = Total + fees;
                            Total = Total + (fees * 20) / 100;
                            Total = Math.Round(Total, 2);
                        }
                        else
                        {
                            decimal fees = (Total * adminFees) / 100;
                            fees = Math.Round(fees, 2);
                            if (item.AdminFeeType.ToStr() == "Amount")
                                fees = adminFees;
                            Total = Total + fees;
                            Total = (Total + ((Total * 20) / 100));
                            Total = Math.Round(Total, 2);
                        }
                        if (creditNoteTotal > 0)
                        {
                            creditNoteTotal = (creditNoteTotal + ((creditNoteTotal * 20) / 100));
                        }
                    }
                    else
                    {
                        if (item.AdminFeeType.ToStr() == "Amount")
                            Total = (Total + adminFees);
                        else
                            Total = (Total + (((Total + discountAmount) * adminFees) / 100));
                        Total = Math.Round(Total, 2);
                        if (creditNoteTotal > 0)
                        {
                            creditNoteTotal = (creditNoteTotal + ((creditNoteTotal * adminFees) / 100));
                        }
                    }
                    Total = Total + extraTotalValue;
                    //  txtInvoiceTotal.Value = Total;
                    //if (objCreditNote != null)
                    //{
                    //    lblCreditNote.Visible = true;
                    //    txtCreditNote.Visible = true;
                    //    txtCreditNote.Value = creditNoteTotal;
                    //}
                    //else
                    //    txtCreditNote.Text = creditNoteTotal.ToStr();
                    var data1 = db.invoice_Payments.Where(c => c.invoiceId == item.Id).OrderBy(c => c.id);
                    var query = (from a in data1
                                 select new
                                 {
                                     Id = a.id,
                                     invoiceID = a.invoiceId,
                                     Payment = a.InvoicePayment,
                                     Balance = a.Balance,
                                     Date = a.PaymentDate,
                                     // a.AddBy,
                                     // a.AddOn,
                                     // a.PaymentDescription
                                 }).AsQueryable();
                    response.Data = Newtonsoft.Json.JsonConvert.SerializeObject(query.ToList());
                }
            }
            catch (Exception ex)
            {
                //ENUtils.ShowMessage(ex.Message);
            }
            var jsonResult = Json(response, JsonRequestBehavior.AllowGet);
            jsonResult.MaxJsonLength = int.MaxValue;
            return jsonResult;
        }

