        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("AccountInvoiceReport")]
        public JsonResult AccountInvoiceReport(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            // List<Vu_BookingDetail> list = new List<Vu_BookingDetail>();
            Gen_SubCompany objSubCompany = new Gen_SubCompany();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    if (obj.InvoiceId == null || Convert.ToInt32(obj.InvoiceId) == 0)
                    {
                        var MessRequrid = "Invoice must be requried";
                        return Json(MessRequrid, JsonRequestBehavior.AllowGet);
                    }
                    long? id = obj.InvoiceId.ToLong();
                    var AccountInvoicelist = General.GetQueryable<vu_Invoice>(a => a.Id == id).OrderBy(c => c.PickupDate).ToList();
                    int count = AccountInvoicelist.Count;
                    this.ObjInvoice = General.GetObject<Invoice>(c => c.Id == id);
                    if (ObjInvoice.SubCompanyId == null)
                    {
                        // objSubCompany = obj.SubCompanyId.ToStr(); //AppVars.objSubCompany;
                    }
                    else
                    {
                        objSubCompany = ObjInvoice.Gen_SubCompany;
                    }
                    if (objSubCompany == null)
                    {
                        var MessRequrid = "Company must be requried";
                        return Json(MessRequrid, JsonRequestBehavior.AllowGet);
                    }
                    decimal netAmount = 0.00m;
                    if (count > 0)
                    {
                        for (int k = 0; k < AccountInvoicelist.Count; k++)
                        {
                            netAmount += AccountInvoicelist[k].Charges.ToDecimal() + AccountInvoicelist[k].ParkingCharges.ToDecimal() + AccountInvoicelist[k].WaitingCharges.ToDecimal() + AccountInvoicelist[k].ExtraDropCharges.ToDecimal();
                        }
                    }
                    var company = db.Gen_Companies.ToList();
                    var subcompany = db.Gen_SubCompanies.ToList();
                    var users = db.UM_Users.ToList();
                    var ObjSubCompany = (from c in company
                                         join s in subcompany on c.SubCompanyId equals s.Id
                                         join u in users on c.SubCompanyId equals u.Id
                                         where (c.Id == ObjInvoice.CompanyId)
                                         select new
                                         {
                                             Id = s.Id,
                                             SubCompanyName = s.CompanyName,
                                             SubAddress = s.Address,
                                             Telephone = s.TelephoneNo,
                                             Mobile = s.MobileNo,
                                             SubCompanyEmail = s.EmailAddress,
                                             Fax = s.Fax,
                                             Emergency = s.EmergencyNo,
                                             Website = s.WebsiteUrl,
                                             CompanyName = c.CompanyName,
                                             //subCompanyLogo = s.CompanyLogo,
                                             AccountNo = s.AccountNo,
                                             SortCode = s.SortCode,
                                             CompanyFooterLogo = s.CompanyFooterLogo,
