        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetOperatorPrivateHireDriverRecord")]
        public JsonResult GetOperatorPrivateHireDriverRecord(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            // List<Vu_BookingDetail> list = new List<Vu_BookingDetail>();
            Gen_SubCompany objSubCompany = new Gen_SubCompany();
            try
            {
                string Message = string.Empty;
                DateTime? dtFrom = obj.Fromdate.Value.ToDateorNull();
                DateTime? dtTill = obj.Todate.Value.ToDateorNull();
                int BookingStatusId = 0;
                string MonthCommencing = string.Empty;
                if (dtFrom.Value == null)
                {
                    Message = "Required : From Date";
                }
                if (dtTill.Value == null)
                {
                    if (!string.IsNullOrEmpty(Message))
                    {
                        Message = "Required : To Date";
                    }
                    else
                    {
                        Message += Environment.NewLine;// "Required : To Date";
                        Message += "Required : To Date";
                    }
                }
                MonthCommencing = string.Format("{0:dd/MM/yyyy}", dtFrom.Value) + "-" + string.Format("{0:dd/MM/yyyy}", dtTill.Value);
                if (obj.OptAll)
                {
                    BookingStatusId = 0;
                }
                if (obj.OptCompleted)
                {
                    BookingStatusId = 2;
                }
                if (obj.OptCanceled)
                {
                    BookingStatusId = 3;
                }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var list = db.stp_OperatorPrivateHireDriverRecord(obj.SubCompanyId, dtFrom.Value, dtTill.Value + TimeSpan.Parse("23:59:59"), BookingStatusId, MonthCommencing).Where(c => c.FirstName.ToLower() != "test").ToList();
                    //var list2=NaturalSortComparer(list.OrderBy(c=>c.DriverNo)).
                    var list2 = (list.AsEnumerable().OrderBy(item => item.DriverNo, new NaturalSortComparer<string>())).ToList();
                    response.Data = new
                    {
                        list2 = Newtonsoft.Json.JsonConvert.SerializeObject(list2)//list.ToList()
                    };
                }
            }
            catch (Exception ex)
            {
                //ENUtils.ShowMessage(ex.Message);
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


