        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetDriverJobLogReport")]
        public JsonResult GetDriverJobLogReport(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            Gen_SubCompany objSubCompany = new Gen_SubCompany();
            int TotalRecord = 0;
            decimal SumTotalCharges = 0;
            try
            {
                int? driverId = obj.DriverId;

                DateTime? fromDate = obj.Fromdate.Value.ToDateorNull();
                DateTime? tillDate = obj.Todate.Value.ToDateorNull();
                //DateTime? fromDate = string.Format("{0:dd/MM/yyyy HH:mm}", obj.Fromdate.Value.ToDate() + obj.Fromdate.Value.TimeOfDay).ToDateTime();
                //DateTime? tillDate = string.Format("{0:dd/MM/yyyy HH:mm}", obj.Todate.Value.ToDate() + obj.Todate.Value.TimeOfDay).ToDateTime();
                var query = General.GetQueryable<Booking>(c => c.BookingStatusId == Enums.BOOKINGSTATUS.DISPATCHED);
                var list = (from a in query
                            where a.DriverId == driverId &&
                                (a.PickupDateTime >= fromDate && a.PickupDateTime <= tillDate)
                            orderby a.PickupDateTime descending
                            select new
                            {
                                Id = a.Id,
                                PickUpDate = a.PickupDateTime,
                                RefNumber = a.BookingNo,
                                Vehicle = a.Fleet_VehicleType.VehicleType,
                                PickupPoint = a.FromAddress,
                                Destination = a.ToAddress,
                                Total = a.TotalCharges,
                            }).ToList();
                TotalRecord = list.Count();
                SumTotalCharges = list.Sum(c => c.Total).Value.ToDecimal();
                response.Data = new
                {
                    list = Newtonsoft.Json.JsonConvert.SerializeObject(list),//list.ToList()
                    TotalRecord = TotalRecord,
                    SumTotalCharges = SumTotalCharges
                };
            }
            catch (Exception ex)
            {
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

