        public JsonResult InvoiceStatementReport(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            // List<Vu_BookingDetail> list = new List<Vu_BookingDetail>();
            Gen_SubCompany objSubCompany = new Gen_SubCompany();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var company = db.Gen_Companies.ToList();
                    var subcompany = db.Gen_SubCompanies.ToList();
                    var users = db.UM_Users.ToList();
                    var ObjSubCompany = (from c in company
                                         join s in subcompany on c.SubCompanyId equals s.Id
                                         join u in users on c.SubCompanyId equals u.Id
                                         where (obj.CompanyId == 0 || c.Id == obj.CompanyId)
                                         select new
                                         {
                                             Id = s.Id,
                                             SubCompanyName = s.CompanyName,
                                             SubAddress = s.Address,
                                             Telephone = s.TelephoneNo,
                                             Mobile = s.MobileNo,
                                             SubCompanyEmail = s.EmailAddress,
                                             Fax = s.Fax,
                                             Emergency = s.EmergencyNo,
                                             Website = s.WebsiteUrl,
                                             CompanyName = c.CompanyName,
                                             //subCompanyLogo = s.CompanyLogo,
                                             AccountNo = s.AccountNo,
                                             SortCode = s.SortCode,
                                             CompanyFooterLogo = s.CompanyFooterLogo,
                                             AccountTitle = s.AccountTitle,
                                             CompanyNumber = s.CompanyNumber,
                                             CompanyVatNumber = s.CompanyVatNumber,
                                             //CompanyLogo = s.CompanyLogo,
                                             BankName = s.BankName,
                                             AdminFeeLabel = u.UserName,
                                             AdminFees = c.AdminFees,
                                             IbanNumber = s.IbanNumber,
                                             BlcNumber = s.BlcNumber,
                                             //HideBankDetail=c.HideBankDetails
                                         }).ToList();
                    var list = db.ExecuteQuery<ClsInvoicePayment>("exec stp_InvoicePayment {0},{1}", obj.SubCompanyId, obj.CompanyId).ToList();
                    var result = (from a in list
                                  select new ClsInvoicePayment
                                  {
                                      Id = a.Id,
                                      Balance = a.Balance,
                                      CompanyName = a.CompanyName,
                                      InvoiceDate = a.InvoiceDate,
                                      InvoiceNo = a.InvoiceNo,
                                      InvoicePayment = a.InvoicePayment,
                                      InvoiceTotal = a.InvoiceTotal,
                                      PaymentDate = a.PaymentDate,
                                      TotalBalance = a.TotalBalance,
                                      CreditNoteNo = a.CreditNoteNo,
                                      CreditNoteTotal = a.CreditNoteTotal,
                                      CreditNoteDate = a.CreditNoteDate,
                                      Address = a.Address
                                  }).AsEnumerable().OrderBy(item => item.InvoiceNo, new NaturalSortComparer<string>()).ToList();
                    if (obj.Fromdate.Value != null && obj.Todate.Value != null)
                    {
                        result = result.Where(c => (c.InvoiceDate >= obj.Fromdate.Value && c.InvoiceDate <= obj.Todate.Value)).ToList();
                    }
                    else if (obj.Fromdate.Value != null && obj.Todate.Value == null)
                    {
                        result = result.Where(c => (c.InvoiceDate >= obj.Fromdate.Value)).ToList();
                    }
                    else if (obj.Fromdate.Value == null && obj.Todate.Value != null)
                    {
                        result = result.Where(c => (c.InvoiceDate <= obj.Todate.Value)).ToList();
                    }
                    if (obj.InvoiceType == 1)
                        result = result.Where(c => c.Id == 3).ToList();
                    if (obj.InvoiceType == 2)
                        result = result.Where(c => c.Id == 1 || c.Id == 2 || c.Id == 4).ToList();
                    response.Data = new
                    {
                        result = result,
                        Subcompanylist = ObjSubCompany.ToList(),
                    };
                }
            }
            catch (Exception ex)
            {
                //ENUtils.ShowMessage(ex.Message);
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }



        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("AccountInvoiceSummaryReport")]
        public JsonResult AccountInvoiceSummaryReport(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            // List<Vu_BookingDetail> list = new List<Vu_BookingDetail>();
            Gen_SubCompany objSubCompany = new Gen_SubCompany();
            try
            {
                DateTime? StartDate = obj.StartDate;
                DateTime? TillDate = obj.TillDate;
                if (TillDate != null)
                    TillDate = TillDate + TimeSpan.Parse("23:59:59");


                string sortBy = "Default";

                if (obj.OptAsc)
                    sortBy = "ASC";
                else if (obj.OptDesc)
                    sortBy = "DESC";


                int? groupId = obj.GroupId;
                int? invoicePaymentType = obj.InvoiceType;

                if (obj.CompanyId > 0)
                    groupId = 0;


                if (obj.checkAllAccounts.Value)
                {
                    using (TaxiDataContext context = new TaxiDataContext())
                    {
                        var company = context.Gen_Companies.ToList();
                        var subcompany = context.Gen_SubCompanies.ToList();
                        var users = context.UM_Users.ToList();
                        var ObjSubCompany = (from c in company
                                             join s in subcompany on c.SubCompanyId equals s.Id
                                             join u in users on c.SubCompanyId equals u.Id
                                             where (obj.CompanyId == 0 ? c.Id == c.Id : c.Id == obj.CompanyId)
                                             select new
                                             {
                                                 Id = s.Id,
                                                 SubCompanyName = s.CompanyName,
                                                 SubAddress = s.Address,
                                                 Telephone = s.TelephoneNo,
                                                 Mobile = s.MobileNo,
                                                 SubCompanyEmail = s.EmailAddress,
                                                 Fax = s.Fax,
                                                 Emergency = s.EmergencyNo,
                                                 Website = s.WebsiteUrl,
                                                 CompanyName = c.CompanyName,
                                                 //subCompanyLogo = s.CompanyLogo,
                                                 AccountNo = s.AccountNo,
                                                 SortCode = s.SortCode,
                                                 CompanyFooterLogo = s.CompanyFooterLogo,
                                                 AccountTitle = s.AccountTitle,
                                                 CompanyNumber = s.CompanyNumber,
                                                 CompanyVatNumber = s.CompanyVatNumber,
                                                 //CompanyLogo = s.CompanyLogo,
                                                 BankName = s.BankName,
                                                 AdminFeeLabel = u.UserName,
                                                 AdminFees = c.AdminFees,
                                                 IbanNumber = s.IbanNumber,
                                                 BlcNumber = s.BlcNumber,
                                                 //HideBankDetail=c.HideBankDetails
                                             }).ToList();


                        var invoiceTemp = context.Invoices.Where(w => (w.InvoiceDate >= StartDate && w.InvoiceDate <= TillDate) && w.CompanyId != null && (groupId == 0 || w.Gen_Company.GroupId == groupId)
                          && (invoicePaymentType <= 0 || (invoicePaymentType == 1 && w.InvoicePaymentTypeID == 3) || (invoicePaymentType == 2 && w.InvoicePaymentTypeID == 1 || w.InvoicePaymentTypeID == 2 || w.InvoicePaymentTypeID == 4))
                          )


                                               .Select(w => new AccountInvoiceSummary
                                               {
                                                   InviceNo = w.InvoiceNo,
                                                   InvoiceDate = w.InvoiceDate,
                                                   Id = w.Id,
                                                   AccountCode = w.Gen_Company.CompanyCode,
                                                   AccountName = w.Gen_Company.CompanyName,
                                                   TotalJobs = w.Invoice_Charges.Where(x => x.InvoiceId == w.Id).Count(),
                                                   TotalAmount = w.Invoice_Charges.Where(x => x.InvoiceId == w.Id).Sum(x => (x.Booking.CompanyPrice + x.Booking.ParkingCharges + x.Booking.WaitingCharges + x.Booking.ExtraDropCharges)),
                                                   VAT = w.Gen_Company.HasVat == true ? (w.Invoice_Charges.Where(x => x.InvoiceId == w.Id).Sum(x => (x.Booking.CompanyPrice + x.Booking.ParkingCharges + x.Booking.WaitingCharges + x.Booking.ExtraDropCharges)) * 20) / 100 : 0.00m,
                                                   GrossTotal = w.Gen_Company.DiscountPercentage,
                                                   AdminFees = w.Gen_Company.AdminFees,
                                                   VATOnAdminFee = w.Gen_Company.VatOnlyOnAdminFees,
                                                   HasVAT = w.Gen_Company.HasVat,
                                                   Margin = (w.InvoicePaymentTypeID != null && (w.InvoicePaymentTypeID == 3 || w.InvoicePaymentTypeID == 4)) ? 1 : 0
                                               }).ToList();

                        if (sortBy == "Default")
                        {

                            invoiceTemp = (from a in invoiceTemp
                                           select new AccountInvoiceSummary
                                           {
                                               InviceNo = a.InviceNo,
                                               InvoiceDate = a.InvoiceDate,
                                               Id = a.Id,
                                               AccountCode = a.AccountCode,
                                               AccountName = a.AccountName,
                                               TotalJobs = a.TotalJobs,
                                               TotalAmount = a.TotalAmount,
                                               VAT = GetVATTotal(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               GrossTotal = a.GrossTotal != null ? ((a.TotalAmount * a.GrossTotal) / 100) : 0.00m,
                                               AdminFees = GetAdminFee(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               Margin = a.Margin
                                           }).OrderByDescending(w => w.InvoiceDate).ToList();

                        }
                        else if (sortBy == "ASC")
                        {
                            invoiceTemp = (from a in invoiceTemp
                                           select new AccountInvoiceSummary
                                           {
                                               InviceNo = a.InviceNo,
                                               InvoiceDate = a.InvoiceDate,
                                               Id = a.Id,
                                               AccountCode = a.AccountCode,
                                               AccountName = a.AccountName,
                                               TotalJobs = a.TotalJobs,
                                               TotalAmount = a.TotalAmount,
                                               VAT = GetVATTotal(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               GrossTotal = a.GrossTotal != null ? ((a.TotalAmount * a.GrossTotal) / 100) : 0.00m,
                                               AdminFees = GetAdminFee(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               Margin = a.Margin
                                           }).OrderBy(item => item.InviceNo, new NaturalSortComparer<string>()).ToList();
                        }
                        else if (sortBy == "DESC")
                        {
                            invoiceTemp = (from a in invoiceTemp
                                           select new AccountInvoiceSummary
                                           {
                                               InviceNo = a.InviceNo,
                                               InvoiceDate = a.InvoiceDate,
                                               Id = a.Id,
                                               AccountCode = a.AccountCode,
                                               AccountName = a.AccountName,
                                               TotalJobs = a.TotalJobs,
                                               TotalAmount = a.TotalAmount,
                                               VAT = GetVATTotal(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               GrossTotal = a.GrossTotal != null ? ((a.TotalAmount * a.GrossTotal) / 100) : 0.00m,
                                               AdminFees = GetAdminFee(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               Margin = a.Margin
                                           }).OrderByDescending(item => item.InviceNo, new NaturalSortComparer<string>()).ToList();
                        }

                        response.Data = new
                        {
                            // invoiceTemp = Newtonsoft.Json.JsonConvert.SerializeObject(invoiceTemp),
                            invoiceTemp,
                            Subcompanylist = ObjSubCompany.ToList(),
                        };

                    }
                }
                else
                {
                    using (TaxiDataContext context = new TaxiDataContext())
                    {
                        var company = context.Gen_Companies.ToList();
                        var subcompany = context.Gen_SubCompanies.ToList();
                        var users = context.UM_Users.ToList();
                        var ObjSubCompany = (from c in company
                                             join s in subcompany on c.SubCompanyId equals s.Id
                                             join u in users on c.SubCompanyId equals u.Id
                                             where (c.Id == obj.CompanyId)
                                             select new
                                             {
                                                 Id = s.Id,
                                                 SubCompanyName = s.CompanyName,
                                                 SubAddress = s.Address,
                                                 Telephone = s.TelephoneNo,
                                                 Mobile = s.MobileNo,
                                                 SubCompanyEmail = s.EmailAddress,
                                                 Fax = s.Fax,
                                                 Emergency = s.EmergencyNo,
                                                 Website = s.WebsiteUrl,
                                                 CompanyName = c.CompanyName,
                                                 //subCompanyLogo = s.CompanyLogo,
                                                 AccountNo = s.AccountNo,
                                                 SortCode = s.SortCode,
                                                 CompanyFooterLogo = s.CompanyFooterLogo,
                                                 AccountTitle = s.AccountTitle,
                                                 CompanyNumber = s.CompanyNumber,
                                                 CompanyVatNumber = s.CompanyVatNumber,
                                                 //CompanyLogo = s.CompanyLogo,
                                                 BankName = s.BankName,
                                                 AdminFeeLabel = u.UserName,
                                                 AdminFees = c.AdminFees,
                                                 IbanNumber = s.IbanNumber,
                                                 BlcNumber = s.BlcNumber,
                                                 //HideBankDetail=c.HideBankDetails
                                             }).ToList();
                        var invoiceTemp = context.Invoices.Where(w => (w.InvoiceDate >= StartDate && w.InvoiceDate <= TillDate) && w.CompanyId != null && w.CompanyId == obj.CompanyId

                         && (invoicePaymentType <= 0 || (invoicePaymentType == 1 && w.InvoicePaymentTypeID == 3) || (invoicePaymentType == 2 && w.InvoicePaymentTypeID == 1 || w.InvoicePaymentTypeID == 2 || w.InvoicePaymentTypeID == 4))
                        )
                                         .Select(w => new AccountInvoiceSummary
                                         {
                                             InviceNo = w.InvoiceNo,
                                             InvoiceDate = w.InvoiceDate,
                                             Id = w.Id,
                                             AccountCode = w.Gen_Company.CompanyCode,
                                             AccountName = w.Gen_Company.CompanyName,
                                             TotalJobs = w.Invoice_Charges.Where(x => x.InvoiceId == w.Id).Count(),
                                             TotalAmount = w.Invoice_Charges.Where(x => x.InvoiceId == w.Id).Sum(x => (x.Booking.CompanyPrice + x.Booking.ParkingCharges + x.Booking.WaitingCharges + x.Booking.ExtraDropCharges)),

                                             VAT = w.Gen_Company.HasVat == true ? (w.Invoice_Charges.Where(x => x.InvoiceId == w.Id).Sum(x => (x.Booking.CompanyPrice + x.Booking.ParkingCharges + x.Booking.WaitingCharges + x.Booking.ExtraDropCharges)) * 20) / 100 : 0.00m,
                                             GrossTotal = w.Gen_Company.DiscountPercentage,
                                             AdminFees = w.Gen_Company.AdminFees,
                                             VATOnAdminFee = w.Gen_Company.VatOnlyOnAdminFees,
                                             HasVAT = w.Gen_Company.HasVat,
                                             Margin = (w.InvoicePaymentTypeID != null && (w.InvoicePaymentTypeID == 3 || w.InvoicePaymentTypeID == 4)) ? 1 : 0
                                         }).ToList();







                        if (sortBy == "Default")
                        {

                            invoiceTemp = (from a in invoiceTemp
                                           select new AccountInvoiceSummary
                                           {
                                               InviceNo = a.InviceNo,
                                               InvoiceDate = a.InvoiceDate,
                                               Id = a.Id,
                                               AccountCode = a.AccountCode,
                                               AccountName = a.AccountName,
                                               TotalJobs = a.TotalJobs,
                                               TotalAmount = a.TotalAmount,
                                               GrossTotal = a.GrossTotal != null ? ((a.TotalAmount * a.GrossTotal) / 100) : 0.00m,
                                               VAT = GetVATTotal(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               AdminFees = GetAdminFee(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               Margin = a.Margin
                                           })






                                         .OrderByDescending(w => w.InvoiceDate).ToList();

                        }
                        else if (sortBy == "ASC")
                        {
                            invoiceTemp = (from a in invoiceTemp
                                           select new AccountInvoiceSummary
                                           {
                                               InviceNo = a.InviceNo,
                                               InvoiceDate = a.InvoiceDate,
                                               Id = a.Id,
                                               AccountCode = a.AccountCode,
                                               AccountName = a.AccountName,
                                               TotalJobs = a.TotalJobs,
                                               TotalAmount = a.TotalAmount,
                                               GrossTotal = a.GrossTotal != null ? ((a.TotalAmount * a.GrossTotal) / 100) : 0.00m,
                                               VAT = GetVATTotal(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               AdminFees = GetAdminFee(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               Margin = a.Margin
                                           })

                                                                    .OrderBy(item => item.InviceNo, new NaturalSortComparer<string>()).ToList();
                        }
                        else if (sortBy == "DESC")
                        {
                            invoiceTemp = (from a in invoiceTemp
                                           select new AccountInvoiceSummary
                                           {
                                               InviceNo = a.InviceNo,
                                               InvoiceDate = a.InvoiceDate,
                                               Id = a.Id,
                                               AccountCode = a.AccountCode,
                                               AccountName = a.AccountName,
                                               TotalJobs = a.TotalJobs,
                                               TotalAmount = a.TotalAmount,
                                               GrossTotal = a.GrossTotal != null ? ((a.TotalAmount * a.GrossTotal) / 100) : 0.00m,
                                               VAT = GetVATTotal(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               AdminFees = GetAdminFee(a.VAT, a.GrossTotal, a.TotalAmount, a.AdminFees, a.VATOnAdminFee, a.HasVAT),
                                               Margin = a.Margin
                                           })
                                                    .OrderByDescending(item => item.InviceNo, new NaturalSortComparer<string>()).ToList();
                        }








                        response.Data = new
                        {
                            // invoiceTemp = Newtonsoft.Json.JsonConvert.SerializeObject(invoiceTemp),
                            invoiceTemp,
                            Subcompanylist = ObjSubCompany.ToList(),
                        };
                    }

                }




            }
            catch (Exception ex)
            {
                //ENUtils.ShowMessage(ex.Message);
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


