        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("UpdateInvoiceBooking")]
        public JsonResult UpdateInvoiceBooking(BookingInvoice obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {

                BookingBO _objMaster = new BookingBO();
                _objMaster.GetByPrimaryKey(obj.Id);

                if (_objMaster.Current != null)
                {
                    _objMaster.Current.CompanyPrice = obj.fare;
                    _objMaster.Current.ParkingCharges = obj.parking;
                    _objMaster.Current.WaitingCharges = obj.waiting;
                    _objMaster.Current.ExtraDropCharges = obj.extraDrop;
                    _objMaster.Current.ServiceCharges = obj.bookingFee;

                    _objMaster.Current.TotalCharges = obj.TotalCharges;
                    _objMaster.Current.InvoicePaymentTypeId = obj.invoicepaymentId;

                    //   _objMaster.Current.OrderNo =obj.orderNo;

                    _objMaster.Current.ToAddress = obj.Destination;
                    _objMaster.Current.FromAddress = obj.PickupPoint;
                    _objMaster.Current.CustomerName = obj.Passenger;


                    if (obj.waitingMins != null)
                        _objMaster.Current.DriverWaitingMins = obj.waitingMins;

                    //if (obj.escortprice.ToStr() != null)
                    //    _objMaster.Current.EscortPrice = obj.escortprice;

                    //if (obj.vehicleTypeId != 0 || obj.vehicleTypeId !=null)
                    //{
                    //    _objMaster.Current.VehicleTypeId = obj.vehicleTypeId;
                    //}
                    _objMaster.CheckCustomerValidation = false;
                    _objMaster.CheckDataValidation = false;
                    _objMaster.DisableUpdateReturnJob = true;
                    _objMaster.Save();


                }
                response.Data = new
                {
                    DataInfo = "",
                };

            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objMaster.Errors.Count > 0)
                {
                    response.Message = objMaster.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

