        [System.Web.Http.Route("DeleteAccountInvoiceHistory")]
        public JsonResult DeleteAccountInvoiceHistory(AccountInvoicehistory obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();

            try
            {
                var InvoiceId = Convert.ToInt32(obj.InvoiceId);
                objMaster.GetByPrimaryKey(InvoiceId);
                invoice_Payment _obj = General.GetObject<invoice_Payment>(c => c.invoiceId == InvoiceId);
                if (_obj == null)
                {

                    objMaster.Delete(objMaster.Current);
                    response.HasError = false;

                }
                else
                {
                    response.HasError = true;
                    response.Message = "You Cannot Delete a Record Payment Exits..";
                }
                //response.Data = new
                //{
                //    response = "",
                //};
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetInvoiceData")]
        public JsonResult GetInvoiceData(AdminApi obj)
        {

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                if (obj.invoice == null)
                {
                    var SecurityDocumentNumber = (from a in General.GetQueryable<Gen_SysPolicy_DocumentNumberSetup>(c => c.DocumentId == Enums.GEN_DOCUMENTS.INVOICENO
                                         && (c.AutoIncrement == null || c.AutoIncrement == false)
                                         )
                                                  select new
                                                  {
                                                      Id = a.Id,
                                                      SubcompanyId = a.SubcompanyId,
                                                      LastNumber = a.LastNumber,
                                                      SysPolicyId = a.SysPolicyId,
                                                      Prefix = a.Prefix,
                                                      DocumentId = a.DocumentId,
                                                      AutoIncrement = a.AutoIncrement

                                                  }).ToList();


                    var CompanyForAccountCombo = (from a in General.GetQueryable<Gen_Company>(c => c.IsClosed == false &&
                                             (c.Gen_Company_PaymentTypes.Count == 0 || (c.AccountTypeId == 1 || c.AccountTypeId == 3)))
                                                  orderby a.CompanyName
                                                  select new
                                                  {
                                                      Id = a.Id,
                                                      AccountNo = a.AccountNo != "" ? a.AccountNo + " - " + a.CompanyName : a.CompanyName
                                                  }).ToList();




                    var SubCompanyNameCombo = (from a in General.GetQueryable<Gen_SubCompany>(null)
                                               orderby a.CompanyName
                                               select new
                                               {
                                                   Id = a.Id,
                                                   CompanyName = a.CompanyName
                                               }).ToList();

                    var ByDepartmentCombo = (from a in General.GetQueryable<Gen_Company_Department>(null)
                                             orderby a.DepartmentName
                                             select new
                                             {
                                                 Id = a.Id,
                                                 DepartmentName = a.DepartmentName
                                             }).ToList();


                    var ddlBookingType = Enums.BOOKING_TYPES.LOCAL;
                    var dtpInvoiceDate = DateTime.Now.ToDate();
                    var dtpDueDate = DateTime.Now.ToDate().AddMonths(1);
                    var dtpFromDate = new DateTime(DateTime.Now.Year, DateTime.Now.Month, 1);
                    var dtpTillDate = new DateTime(DateTime.Now.Year, DateTime.Now.Month, DateTime.Now.LastDayOfMonthValue());



                    response.Data = new
                    {
                        CompanyForAccountCombo = CompanyForAccountCombo.ToList(),
                        SubCompanyNameCombo = SubCompanyNameCombo.ToList(),
                        ByDepartmentCombo = ByDepartmentCombo.ToList(),
                        ddlBookingType = Enums.BOOKING_TYPES.LOCAL,

                        dtpInvoiceDate = String.Format("{0:dd/MM/yyyy}", dtpInvoiceDate),
                        dtpDueDate = String.Format("{0:dd/MM/yyyy}", dtpDueDate),
                        dtpFromDate = String.Format("{0:dd/MM/yyyy}", dtpFromDate),
                        dtpTillDate = String.Format("{0:dd/MM/yyyy}", dtpTillDate),
                        //DocumentNumberSetup = DocumentNumberSetup,
                    };
                }
                else
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        var SecurityDocumentNumber = (from a in General.GetQueryable<Gen_SysPolicy_DocumentNumberSetup>(c => c.DocumentId == obj.invoice.InvoiceNo
                                         && (c.AutoIncrement == null || c.AutoIncrement == false)
                                         )
                                                      select new
                                                      {
                                                          Id = a.Id,
                                                          SubcompanyId = a.SubcompanyId,
                                                          LastNumber = a.LastNumber,
                                                          SysPolicyId = a.SysPolicyId,
                                                          Prefix = a.Prefix,
                                                          DocumentId = a.DocumentId,
                                                          AutoIncrement = a.AutoIncrement

                                                      }).ToList();


                        var CompanyForAccountCombo = (from a in General.GetQueryable<Gen_Company>(c => c.IsClosed == false &&
                                             (c.Gen_Company_PaymentTypes.Count == 0 || (c.AccountTypeId == 1 || c.AccountTypeId == 3)))
                                                      orderby a.CompanyName
                                                      select new
                                                      {
                                                          Id = a.Id,
                                                          AccountNo = a.AccountNo != "" ? a.AccountNo + " - " + a.CompanyName : a.CompanyName
                                                      }).ToList();

                        var SubCompanyNameCombo = (from a in General.GetQueryable<Gen_SubCompany>(null)
                                                   orderby a.CompanyName
                                                   select new
                                                   {
                                                       Id = a.Id,
                                                       CompanyName = a.CompanyName
                                                   }).ToList();
                        var ByDepartmentCombo = (from a in General.GetQueryable<Gen_Company_Department>(null)
                                                 orderby a.DepartmentName
                                                 select new
                                                 {
                                                     Id = a.Id,
                                                     DepartmentName = a.DepartmentName
                                                 }).ToList();

                        var Bookings = db.Bookings.ToList();
                        var Invoices = db.Invoices.ToList();
                        var invoice_charge = db.Invoice_Charges.ToList();
                        var company = db.Gen_Companies.ToList();
                        var invoiceList = (from b in Bookings
                                           join ic in invoice_charge on b.Id equals ic.BookingId
                                           join i in Invoices on ic.InvoiceId equals i.Id
                                           join c in company on i.CompanyId equals c.Id
                                           where i.InvoiceNo == obj.invoice.InvoiceNo
                                           select new
                                           {
                                               //ContactName = c.ContactName,
                                               //EmailAddress = c.Email,
                                               //InvoiceNumber = i.InvoiceNo,
                                               //InvoiceDate = i.InvoiceDate,
                                               //DueDate = i.DueDate,
                                               //Description = " " + b.FromAddress + " | " + b.ToAddress + " ",
                                               //Quantity = 1,
                                               //UnitAmount = b.TotalCharges,
                                               //AccountCode = c.CompanyCode,
                                               //TaxtType = c.TaxtType,
                                               CompanyPrice = b.CompanyPrice,
                                               ParkingCharges = b.ParkingCharges,
                                               WaitingCharges = b.WaitingCharges,
                                               ExtraDropCharges = b.ExtraDropCharges,
                                               ServiceCharges = b.ServiceCharges,
                                               TotalCharges = b.TotalCharges,
                                               InvoicePaymentTypeId = b.InvoicePaymentTypeId,
                                               OrderNo = b.OrderNo,
                                               ToAddress = b.ToAddress,
                                               FromAddress = b.FromAddress,
                                               CustomerName = b.CustomerName,
                                           }).ToList();

                        var ddlBookingType = Enums.BOOKING_TYPES.LOCAL;
                        var dtpInvoiceDate = DateTime.Now.ToDate();
                        var dtpDueDate = DateTime.Now.ToDate().AddMonths(1);
                        var dtpFromDate = new DateTime(DateTime.Now.Year, DateTime.Now.Month, 1);
                        var dtpTillDate = new DateTime(DateTime.Now.Year, DateTime.Now.Month, DateTime.Now.LastDayOfMonthValue());



                        response.Data = new
                        {
                            CompanyForAccountCombo = CompanyForAccountCombo.ToList(),
                            SubCompanyNameCombo = SubCompanyNameCombo.ToList(),
                            ByDepartmentCombo = ByDepartmentCombo.ToList(),
                            ddlBookingType = Enums.BOOKING_TYPES.LOCAL,

                            dtpInvoiceDate = String.Format("{0:dd/MM/yyyy}", dtpInvoiceDate),
                            dtpDueDate = String.Format("{0:dd/MM/yyyy}", dtpDueDate),
                            dtpFromDate = String.Format("{0:dd/MM/yyyy}", dtpFromDate),
                            dtpTillDate = String.Format("{0:dd/MM/yyyy}", dtpTillDate),
                            // invoiceList = invoiceList.ToList(),
                            //DocumentNumberSetup = DocumentNumberSetup,
                        };

                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }


            return Json(response, JsonRequestBehavior.AllowGet);

        }

