            ResponseAdminApi response = new ResponseAdminApi();
            List<stp_GetInvoiceBookingsResultEx> list = null;
            try
            {
                var InvoiceId = Convert.ToInt32(obj.InvoiceId);
                //GetByPrimaryKey(id);
                objMaster.GetByPrimaryKey(InvoiceId);

                using (TaxiDataContext db = new TaxiDataContext())
                {
                    list = db.ExecuteQuery<stp_GetInvoiceBookingsResultEx>("exec stp_GetInvoiceBookings {0}", objMaster.Current.Id).ToList();

                    response.Data = new
                    {
                        EditAccountInvoiceHistory = list.ToList(),
                    };
                }

            }
            catch (Exception ex)
