        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCommPayDrivers")]
        public JsonResult GetCommPayDrivers(List<SaveAllDriverCommissionRequest> obj)
        {

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                var listofDrivers = (from a in General.GetQueryable<Fleet_Driver>(c => c.IsActive == true)
                                     select new
                                     {
                                         a.Id,
                                         a.DriverName,
                                         a.DriverNo,
                                         a.MaxCommission,
                                         a.SubcompanyId,
                                         a.NICNo
                                     }).ToList();

                response.Data = new
                {
                    DriverList = listofDrivers
                };
            }
            catch (Exception ex)
            {
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCommissionByDriverId")]
        public JsonResult GetCommissionByDriverId(AdminApi obj)
        {
            //

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                //--
                using (TaxiDataContext db = new TaxiDataContext())
                {


                    var item = (from a in General.GetQueryable<Fleet_DriverCommision>(c => c.DriverId == obj.DriverId)
                                orderby a.Id descending
                                select new
                                {
                                    Id = a.Id,
                                    BalanceDue = a.Balance,
                                    DriverCommission = a.DriverOwed,
                                    TransactionNo = a.TransNo,
                                    PeriodFrom = a.FromDate,
                                    PeriodTo = a.ToDate,
                                    CommisionPaid = a.CommisionPay,
                                    PayHistory = a.DriverCommission_PaymentHistories //a.DriverRent_PaymentHistories
                                }).FirstOrDefault();

                    var list = (from a in General.GetQueryable<Fleet_DriverCommissionExpense>(c => c.CommissionId == item.Id)
                                    //where a.IsPaid == true
                                orderby a.Date
                                select new
                                {
                                    Id = a.Id,
                                    CommissionId = a.CommissionId,
                                    Credit = a.Credit,
                                    Debit = a.Debit,
                                    User = a.AddBy,
                                    Date = a.Date,
                                    Type = a.Credit > 0.00m ? "Credit" : "Debit",
                                    Amount = a.Amount,
                                    Description = a.Description,
                                    Balance = a.Fleet_DriverCommision.Balance
                                }).ToList();

                    response.Data = new
                    {
                        DriverCommPay = item,
                        CommPayList = list
                    };



                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }


            //return Json(response, JsonRequestBehavior.AllowGet);
            return new CustomJsonResult { Data = response };

        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("DeleteCommissionPayById")]
        public JsonResult DeleteCommissionPayById(AdminApi obj)
        {

            DriverCommisionBO objDriverCommision = new DriverCommisionBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                //--
                long Id = obj.CommissionPay.Id;
                long CommissionId = obj.CommissionPay.CommissionId;
                string Type = obj.CommissionPay.Type;
                decimal Amount = obj.CommissionPay.Amount.ToDecimal();
                decimal CurrentBalance = obj.CommissionPay.CurrentBalance.ToDecimal();
                decimal numCurrBalance = 0;
                if (Type == "credit")
                {
                    //if (CurrentBalance > 0)
                    //{
                    numCurrBalance = (CurrentBalance + Amount);


                }
                else
                {
                    //if (CurrentBalance > 0)
                    //{
                    numCurrBalance = (CurrentBalance - Amount);

                }
                objDriverCommision.GetByPrimaryKey(CommissionId);
                objDriverCommision.Edit();
                objDriverCommision.Current.Balance = numCurrBalance.ToDecimal();

                objDriverCommision.Save();
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var query = db.Fleet_DriverCommissionExpenses.Single(c => c.Id == Id);
                    db.Fleet_DriverCommissionExpenses.DeleteOnSubmit(query);
                    db.SubmitChanges();
                }
                response.Data = new
                {
                    Id = Id
                };
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }


            //return Json(response, JsonRequestBehavior.AllowGet);
            return new CustomJsonResult { Data = response };

        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveCommissionPay")]
        public JsonResult SaveCommissionPay(AdminApi obj)
        {

            DriverCommisionBO objDriverCommision = new DriverCommisionBO();

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                objDriverCommision.GetByPrimaryKey(obj.CommissionPay.CommissionId);
                //objDriverCommision.Edit();

                if (objDriverCommision.Current == null)
                {
                    return new CustomJsonResult { Data = response.Message = "Invalid Commission Id" };
                }
                string Description = obj.CommissionPay.Description;
                //if (string.IsNullOrEmpty(Description))
                //{
                //    ENUtils.ShowMessage("Required : Description");
                //    return;
                //}
                objDriverCommision.Edit();
                objDriverCommision.Current.Balance = obj.CommissionPay.CurrentBalance;
                Fleet_DriverCommissionExpense objDriverCommissionExpense = new Fleet_DriverCommissionExpense();

                objDriverCommissionExpense.AddBy = obj.CommissionPay.AddBy;

                if (obj.CommissionPay.IsCredit)
                {
                    objDriverCommissionExpense.Credit = obj.CommissionPay.Amount;
                    objDriverCommissionExpense.Amount = obj.CommissionPay.Amount;
                }
                else
                {
                    objDriverCommissionExpense.Debit = obj.CommissionPay.Amount;
                    objDriverCommissionExpense.Amount = obj.CommissionPay.Amount;
                }
                objDriverCommissionExpense.Date = DateTime.Now;
                objDriverCommissionExpense.Description = Description;



                if (objDriverCommissionExpense.Description.ToStr().Trim().Length == 0)
                {
                    if (obj.CommissionPay.IsCredit)
                    {
                        objDriverCommissionExpense.Description = "PAID TO OFFICE";
                    }
                    else
                    {
                        objDriverCommissionExpense.Description = "PAID TO DRIVER";

                    }
                    Description = objDriverCommissionExpense.Description;
                }

                if (objDriverCommissionExpense.Description.ToStr().Contains("(Payment)") == false)
                    objDriverCommissionExpense.Description = Description + " (Payment)";


                objDriverCommissionExpense.IsPaid = true;
                if (objDriverCommision.Current.Fleet_DriverCommissionExpenses.Count == 0)
                {
                    objDriverCommision.Current.Fleet_DriverCommissionExpenses.Add(objDriverCommissionExpense);
                }
                else
                {
                    objDriverCommision.Current.Fleet_DriverCommissionExpenses.Add(objDriverCommissionExpense);
                }


                objDriverCommision.Current.EditOn = DateTime.Now;
                objDriverCommision.Current.EditLog = obj.CommissionPay.AddBy;
                objDriverCommision.Current.EditBy = obj.CommissionPay.UserId;

                objDriverCommision.Save();
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }


            //return Json(response, JsonRequestBehavior.AllowGet);
            return new CustomJsonResult { Data = response };

        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetIncompleteBooking")]
        public JsonResult GetIncompleteBooking(AdminApi obj)
        {

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                DateTime recentDays = DateTime.Now.AddDays(-1).Date;

                var data1 = General.GetQueryable<Booking>(c => (c.PickupDateTime.Value < recentDays)
                    &&
                    (
                    c.BookingStatusId == Enums.BOOKINGSTATUS.PENDING || c.BookingStatusId == Enums.BOOKINGSTATUS.WAITING || c.BookingStatusId == Enums.BOOKINGSTATUS.ONHOLD
                    || c.BookingStatusId == Enums.BOOKINGSTATUS.NOTACCEPTED || c.BookingStatusId == Enums.BOOKINGSTATUS.REJECTED || c.BookingStatusId == Enums.BOOKINGSTATUS.BID
                   )

                    && (c.SubcompanyId == obj.SubCompanyId || obj.SubCompanyId == 0)

                    && (c.PickupDateTime.Value.Date < recentDays)

                    )
                               .OrderByDescending(c => c.PickupDateTime);




                var query = (from a in data1


                             select new
                             {
                                 Id = a.Id,
                                 RefNumber = a.BookingNo,
                                 BookingDate = a.BookingDate,
                                 PickupDate = a.PickupDateTime,
                                 Passenger = a.CustomerName,
                                 From = a.FromDoorNo != string.Empty ? a.FromDoorNo + " - " + a.FromAddress : a.FromAddress,
                                 To = a.ToDoorNo != string.Empty ? a.ToDoorNo + " - " + a.ToAddress : a.ToAddress,
                                 Fare = a.FareRate,
                                 Account = a.Gen_Company.CompanyName,
                                 Driver = a.Fleet_Driver.DriverNo,
                                 DriverId = a.DriverId,
                                 Vehicle = a.Fleet_VehicleType.VehicleType,
                                 Status = a.BookingStatus.StatusName,
                                 StatusColor = a.BookingStatus.BackgroundColor,
                                 BookingTypeId = a.BookingTypeId,
                                 VehicleBgColor = a.Fleet_VehicleType.BackgroundColor,
                                 VehicleTextColor = a.Fleet_VehicleType.TextColor,
                                 BackgroundColor1 = a.Gen_Company.BackgroundColor,
                                 TextColor1 = a.Gen_Company.TextColor,
                                 MobileNo = a.CustomerMobileNo,
                                 FromLocTypeId = a.FromLocTypeId,
                                 ToLocTypeId = a.ToLocTypeId,
                                 SubCompanyBgColor = a.SubcompanyId != null ? a.Gen_SubCompany.BackgroundColor : -1
                             }).ToList();



                response.Data = new
                {
                    Bookings = query
                };
            }
            catch (Exception ex)
            {
            }
            return new CustomJsonResult { Data = response };
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetExportBooking")]
        public CustomJsonResult GetExportBooking(int InvoiceID)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    List<ExportInvoiceCSV> list1 = db.ExecuteQuery<ExportInvoiceCSV>("exec stp_GetInvoiceBookingsForExport {0}", InvoiceID).ToList();
                    var list = (from a in list1
                                select new
                                {
                                    InvoiceNo = InvoiceID,
                                    PickupDateTime = a.PickupDateTime,
                                    OrderNo = a.OrderNo,
                                    BookingNo = a.BookingNo,
                                    CompanyPrice = a.CompanyPrice.ToDecimal(),
                                    ParkingCharges = a.ParkingCharges.ToDecimal(),
                                    WaitingCharges = a.WaitingCharges.ToDecimal(),
                                    ExtraDropCharges = a.ExtraDropCharges.ToDecimal(),
                                    CustomerName = a.CustomerName,
                                    FromAddress = a.FromAddress,
                                    ToAddress = a.ToAddress,
                                    TotalCharges = a.TotalCharges,
                                    VehicleType = a.VehicleType,
                                    DepartmentName = a.DepartmentName,
                                    TipAmount = a.TipAmount,
                                    ServiceCharges = a.ServiceCharges,
                                    BookingFee = a.BookingFee,
                                    ViaString = a.ViaString,
                                    SubTotal = a.SubTotal,
                                    BookedBy = a.BookedBy
                                }).OrderBy(c => c.PickupDateTime).ToList();
                    response.Data = new
                    {
                        ExportInvoiceCSV = list.ToList()
                    };
                    return new CustomJsonResult { Data = response };
                }
            }
            catch (Exception ex)
            {
                return null;
            }
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetDriverDropDownData")]
        public JsonResult GetDriverDropDownData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                DataSet ds = new DataSet();
                using (System.Data.SqlClient.SqlConnection sqlconn = new System.Data.SqlClient.SqlConnection(Cryptography.Decrypt(System.Configuration.ConfigurationManager.AppSettings["ConnectionString"].ToStr(), "tcloudX@@!", true)))
                {
                    sqlconn.Open();
                    using (System.Data.SqlClient.SqlCommand cmd = new System.Data.SqlClient.SqlCommand())
                    {
                        cmd.Connection = sqlconn;
                        cmd.CommandType = CommandType.StoredProcedure;
                        cmd.CommandText = "stp_FillDriverCombos";
                        using (System.Data.SqlClient.SqlDataAdapter da = new System.Data.SqlClient.SqlDataAdapter(cmd))
                        {
                            da.Fill(ds);
                        }
                    }
                    var DriverType = new List<Tuple<int, string>>();
                    DriverType.Add(Tuple.Create(1, "On Rent"));
                    DriverType.Add(Tuple.Create(2, "On Commission"));
                    var Category = new List<Tuple<int, string>>();
                    Category.Add(Tuple.Create(1, "Hackney"));
                    Category.Add(Tuple.Create(2, "Private Hire"));
                    List<string> Navigation = new List<string>();
                    Navigation.Add("All");
                    Navigation.Add("Google Navigation");
                    Navigation.Add("Waze Navigation");
                    Navigation.Add("Here we Go Navigation");
                    Navigation.Add("None");
                    var VehicleTypes = ds.Tables[0].AsEnumerable()
                     .Select(datarow => new
                     {
                         Id = datarow.Field<int>("Id"),
                         Name = datarow.Field<string>("Name")
                     });
                    var VehicleColors = ds.Tables[1].AsEnumerable()
                     .Select(datarow => new
                     {
                         Id = datarow.Field<int>("Id"),
                         Name = datarow.Field<string>("VehicleColor")
                     });
                    var DriverDocument = ds.Tables[2].AsEnumerable()
                     .Select(datarow => new
                     {
                         Id = datarow.Field<int>("Id"),
                         Name = datarow.Field<string>("DocumentName"),
                         ExpiryDays = datarow.Field<int>("ExpiryDays")
                     });
                    var DriverShifts = ds.Tables[3].AsEnumerable()
                     .Select(datarow => new
                     {
                         Id = datarow.Field<int>("Id"),
                         Name = datarow.Field<string>("ShiftName")
                     });
                    var GenAttribute = ds.Tables[4].AsEnumerable()
                     .Select(datarow => new
                     {
                         Id = datarow.Field<int>("Id"),
                         Name = datarow.Field<string>("Name"),
                         ShortName = datarow.Field<string>("ShortName")
                     });
                    response.Data = new { DriverType, Category, VehicleTypes, VehicleColors, DriverDocument, DriverShifts, GenAttribute, Navigation };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

