                                                $"Removed: [{string.Join(", ", removed)}]";

                            string logFileName = $"SaveFleetDriverDocuments_{DateTime.Now:yyyy-MM-dd}.txt";
                            string logFilePath = Path.Combine(AppContext.BaseDirectory, logFileName);
