        public static byte[] ToByteArray(Stream stream)
        {
            if (stream is MemoryStream)
                return ((MemoryStream)stream).ToArray();
            else
            {
                using (MemoryStream ms = new MemoryStream())
                {
                    stream.CopyTo(ms);
                    return ms.ToArray();
                }
            }
        }

        private void UploadImage(int driverId, string driverNo, byte[] arrImage, string fileName, string smsLinkId)
        {

            try
            {

                //

                if (smsLinkId.Length == 0)
                    smsLinkId = null;



                if (arrImage == null || arrImage.Length == 0)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {

                        db.ExecuteCommand("update Fleet_Driver_Image set PhotoLinkId=NULL where driverId=" + driverId);
                    }
                }
                else
                {
                    //  WebUploadFile obje = new WebUploadFile();



                    DriverImageUploader.WebUploadFileSoapClient ca = new DriverImageUploader.WebUploadFileSoapClient();
                    string response = ca.UploadFile(arrImage, fileName, smsLinkId, driverNo, HubProcessor.Instance.objPolicy.DefaultClientId.ToStr());
                    //  string response = obje.UploadFileGetPhotoLinkId(arrImage, fileName, smsLinkId, driverNo, HubProcessor.Instance.objPolicy.DefaultClientId.ToStr());


                    try
                    {
                        System.IO.File.WriteAllBytes(AppContext.BaseDirectory + "\\" + "DriverImageToUpload.txt", arrImage);
                    }
                    catch
                    {

                    }


                    if (response.IsNumeric())
                    {
                        try
                        {
                            System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "DriverImageUploaded.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + driverId + Environment.NewLine);
                        }
                        catch
                        {

                        }
                        using (TaxiDataContext db = new TaxiDataContext())
                        {

                            db.ExecuteCommand("update Fleet_Driver_Image set PhotoLinkId=" + response.ToInt() + " where driverId=" + driverId);
                        }
                    }
                    else
                    {
                        try
                        {
                            System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "DriverImageUploadFailed.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + driverId + ",response:" + response + Environment.NewLine);
                        }
                        catch
                        {

                        }
                        // ENUtils.ShowMessage(response);
                    }

                }


            }
            catch (Exception ex)
            {
                //  ENUtils.ShowMessage(ex.Message);
            }
        }



        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetVehicleAttributes")]
        public JsonResult GetVehicleAttributes()
        {
            ResponseAdminApi response = new ResponseAdminApi();
            var list = (from a in General.GetQueryable<Fleet_VehicleType>(null)
                        select new
                        {
                            Id = a.Id,
                            VehicleType = a.VehicleType,
                            AttributeValues = a.AttributeValues
                        }).ToList();
            response.Data = list;
            return Json(response, JsonRequestBehavior.AllowGet);
        }


