        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetInActiveDriversListData")]
        public JsonResult GetInActiveDriversListData(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    db.DeferredLoadingEnabled = false;

                    int filterType = 1;

                    var avail = db.ExecuteQuery<clsAvail>("SELECT DriverId,EndingDate=endingdate FROM Fleet_Driver_Availability where id in(select Max(Id) from  Fleet_Driver_Availability group by driverid)").ToList();

                    if (filterType == 1)
                    {
                        var query = (from a in General.GetQueryable<Fleet_Driver>(null).AsEnumerable()
                                     where a.IsActive == false || avail.Count(c => c.DriverId == a.Id && c.EndingDate != null) > 0

                                     select new stp_GetDriversList
                                     {
                                         Id = a.Id,
                                         No = a.DriverNo,
                                         Name = a.DriverName,
                                         VehicleNo = a.VehicleNo,
                                         VehicleType = a.Fleet_VehicleType.VehicleType,
                                         MOTExpirystr = String.Format("{0:dd/MM/yyyy}", a.MOTExpiryDate),
                                         MOT2Expirystr = String.Format("{0:dd/MM/yyyy}", a.MOT2ExpiryDate),

                                         PCOVehicleExpirystr = String.Format("{0:dd/MM/yyyy}", a.PCOVehicleExpiryDate),
                                         InsuranceExpirystr = String.Format("{0:dd/MM/yyyy}", a.InsuranceExpiryDate),
                                         PCODriverExpirystr = String.Format("{0:dd/MM/yyyy}", a.PCODriverExpiryDate),
                                         LicenseExpirystr = String.Format("{0:dd/MM/yyyy}", a.DrivingLicenseExpiryDate),

                                         MobileNo = a.MobileNo,
                                         EndDate = avail.FirstOrDefault(c => c.DriverId == a.Id).DefaultIfEmpty().EndingDate
                                     })

                                    .OrderBy(item => item.No, new NaturalSortComparer<string>());

                        response.Data = new { fleetDriverlistOfData = query.ToList() };
                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }

            var serializer = new JavaScriptSerializer();
            serializer.MaxJsonLength = Int32.MaxValue;
            var jsonResult = new JsonResult
            {
                Data = response,
                JsonRequestBehavior = JsonRequestBehavior.AllowGet,
                MaxJsonLength = int.MaxValue // Also increase the maxJsonLength property of the JsonResult
            };

            return jsonResult;


        }

