        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveAddLocation")]
        public JsonResult SaveAddLocation(AdminApi obj)
        {
            LocationBO objMaster = new LocationBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                long Id = obj.Gen_Location.Id;
                if (Id == 0)
                {
                    objMaster.New();
                }
                else
                {
                    objMaster.GetByPrimaryKey(Id);
                    objMaster.Edit();
                }

                objMaster.Current.LocationName = obj.Gen_Location.LocationName; //txtLocName.Text.Trim();
                objMaster.Current.LocationTypeId = obj.Gen_Location.LocationTypeId; //ddlLocationType.SelectedValue.ToIntorNull();
                objMaster.Current.Address = obj.Gen_Location.Address; //txtAddress.Text.Trim();
                objMaster.Current.PostCode = obj.Gen_Location.PostCode; //txtPostCode.Text.Trim();
                objMaster.Current.ZoneId = obj.Gen_Location.ZoneId; //ddlZone.SelectedValue.ToIntorNull();

                objMaster.Current.ExtraCommission = obj.Gen_Location.ExtraCommission; //numExtraChrgs.Value.ToDecimal();
                objMaster.Current.CustomShortKey = obj.Gen_Location.CustomShortKey; //chkShortKey.Checked;
                objMaster.Current.ShortCutKey = obj.Gen_Location.ShortCutKey; //txtShortCutKey.Text.Trim().ToLower();
                objMaster.Current.Latitude = obj.Gen_Location.Latitude != null && obj.Gen_Location.Latitude != 0 ? obj.Gen_Location.Latitude : null;  //txtLat.Text.Trim().Length > 0 ? Convert.ToDouble(txtLat.Text.Trim()) : 0;
                objMaster.Current.Longitude = obj.Gen_Location.Longitude != null && obj.Gen_Location.Longitude != 0 ? obj.Gen_Location.Longitude : null; //txtLng.Text.Trim().Length > null ? Convert.ToDouble(txtLng.Text.Trim()) : 0;


                if (objMaster.Current.Latitude > 0 && objMaster.Current.ZoneId == null)
                {
                    try
                    {

                        var plot = (from a in General.GetQueryable<Gen_Zone>(c => (c.ShapeType != null && c.ShapeType == "circle") || (c.MinLatitude != null && (objMaster.Current.Latitude >= c.MinLatitude && objMaster.Current.Latitude <= c.MaxLatitude)
                                                                          && (objMaster.Current.Longitude <= c.MaxLongitude && objMaster.Current.Longitude >= c.MinLongitude)))
                                    orderby a.PlotKind

                                    select a.Id).ToArray<int>();

                        if (plot.Count() > 0)
                        {
                            using (TaxiDataContext DB = new TaxiDataContext())
                            {
                                foreach (var item in plot)
                                {

                                    if (FindPoint(Convert.ToDouble(objMaster.Current.Latitude), Convert.ToDouble(objMaster.Current.Longitude), DB.Gen_Zone_PolyVertices.Where(c => c.ZoneId == item).ToList()))
                                    {
                                        objMaster.Current.ZoneId = item;
                                        break;
                                    }
                                }
                            }





                        }
                    }
                    catch
                    {


                    }


                }


                // objMaster.Current.FullLocationName=  (REPLACE((  objMaster.Current.LocationName + ' '+REPLACE(((objMaster.Current.Address,objMaster.Current.PostCode,"")),objMaster.Current.LocationName,"") + " "+objMaster.Current.PostCode),"  "," ");
                objMaster.IsManualLocation = true;
                objMaster.Save();


            }
            catch (Exception ex)
            {
                response.HasError = true;
                if (objMaster.Errors.Count > 0)
                {
                    response.Message = objMaster.ShowErrors();
                }
                else
                {
                    response.Message = ex.Message;
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
