        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCallStatisticsGraph")]
        public JsonResult GetCallStatisticsGraph(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();

            try
            {
                DateTime? fromDates = obj.Fromdate;
                DateTime? tillDates = obj.TillDate;

                int HourRange = obj.hourRange;
                if (HourRange == 0 || HourRange > 24)
                {
                    HourRange = 2;
                }


                string Error = "";
                if (fromDates == null)
                {
                    Error = "Required : From Date";
                }
                if (tillDates == null)
                {
                    if (string.IsNullOrEmpty(Error))
                    {
                        Error = "Required : Till Date";
                    }
                    else
                    {
                        Error += Environment.NewLine + "Required : Till Date";
                    }
                }


                var listAnswered = (from a in GeneralBLL.GetQueryable<CallHistory>(null)
                                    where (a.CallDateTime >= fromDates)
                                    && (a.CallDateTime <= tillDates) && (a.AnsweredDateTime != null)
                                    orderby a.CallDateTime descending
                                    //where (a.AnsweredDateTime.Value.Date >= fromDates)
                                    //&& (a.AnsweredDateTime.Value.Date <= tillDates)
                                    //orderby a.AnsweredDateTime descending
                                    select new
                                    {
                                        AnsweredDateTime = a.AnsweredDateTime,
                                        CallDateTime = a.CallDateTime,
                                    }).ToList();
                var listMissed = (from a in GeneralBLL.GetQueryable<CallHistory>(null)
                                  where (a.CallDateTime >= fromDates)
                                  && (a.CallDateTime <= tillDates) && (a.AnsweredDateTime == null)
                                  orderby a.CallDateTime descending
                                  //where (a.AnsweredDateTime.Value.Date >= fromDates)
                                  //&& (a.AnsweredDateTime.Value.Date <= tillDates)
                                  //orderby a.AnsweredDateTime descending
                                  select new
                                  {
                                      AnsweredDateTime = a.AnsweredDateTime,
                                      CallDateTime = a.CallDateTime,
                                  }).ToList();
                var list = listAnswered.Concat(listMissed).ToList();

                //var list1 = (from a in GeneralBLL.GetQueryable<CallHistory>(null)
                //            where (a.CallDateTime >= fromDates)
                //            && (a.CallDateTime <= tillDates) && (a.AnsweredDateTime != null)
                //            orderby a.CallDateTime descending
                //            //where (a.AnsweredDateTime.Value.Date >= fromDates)
                //            //&& (a.AnsweredDateTime.Value.Date <= tillDates)
                //            //orderby a.AnsweredDateTime descending
                //            select new
                //            {
                //                CallDateTime = a.CallDateTime,
                //            }).ToList();



                List<NewCallHistory> objCallHistory = new List<NewCallHistory>();

                List<NewCallHistory> objNewCallHistory = new List<NewCallHistory>();

                DateTime dtFrom = DateTime.Now.ToDate();
                DateTime dtTo = DateTime.Now.ToDate();

                int GroupHours = 24;
                string HoursDuration = "";

                var grouplist = list.GroupBy(c => c.CallDateTime.ToDate()).ToList();

                foreach (var item in grouplist)
                {
                    int i = 0;
                    dtFrom = item.Key.ToDate();
                    dtTo = item.Key.ToDate();

                    for (; i < GroupHours; i += HourRange)
                    {
                        if (i == 0)
                        {
                            dtTo = item.Key.AddHours(HourRange);
                        }
                        else
                        {
                            dtFrom = item.Key.AddHours(i);

                            dtTo = item.Key.AddHours((i + HourRange));
                            if (dtFrom.Date != dtTo.Date)
                            {
                                dtTo = new DateTime(dtFrom.Year, dtFrom.Month, dtFrom.Day, 23, 59, 59);
                            }
                        }
                        objCallHistory.Add(new NewCallHistory { FromTime = dtFrom, ToTime = dtTo });
                    }
                }

                foreach (var item in objCallHistory)
                {
                    dtFrom = item.FromTime.ToDateTime();
                    dtTo = item.ToTime.ToDateTime();
                    var obj1 = list.Where(c => c.CallDateTime >= item.FromTime && c.CallDateTime <= item.ToTime).ToList(); ;
                    if (obj1.Count > 1)
                    {
                        objNewCallHistory.RemoveAll(c => c.FromTime >= dtFrom && c.FromTime <= dtTo);
                    }
                    if (obj1.Count > 0)
                    {
                        HoursDuration = string.Format("{0:HH:mm}", dtFrom) + " to " + string.Format("{0:HH:mm}", dtTo);
                        if (obj1[0].AnsweredDateTime != null)
                        {
                            objNewCallHistory.Add(new NewCallHistory { FromTime = dtFrom, ToTime = dtTo, Id = obj1.Count, CalledToNumber = HoursDuration, CallDateTime = dtFrom.ToDate(), AnsweredDateTime = obj1[0].AnsweredDateTime });
                        }
                        else
                        {
                            objNewCallHistory.Add(new NewCallHistory { FromTime = dtFrom, ToTime = dtTo, Id = obj1.Count, CalledToNumber = HoursDuration, CallDateTime = dtFrom.ToDate(), AnsweredDateTime = null });
                        }
                        //objNewCallHistory.Add(new NewCallHistory { FromTime = dtFrom, ToTime = dtTo, Id = obj1.Count, Answered = obj1.Count, Unanswered = obj1.Count, CalledToNumber = HoursDuration, CallDateTime = dtFrom.ToDate() });

                    }
                }
                if (true)
                {
                    foreach (var item in grouplist)
                    {
                        int i = 0;
                        dtFrom = item.Key.ToDateTime();
                        dtTo = item.Key.ToDateTime();

                        for (; i < GroupHours; i += HourRange)
                        {
                            if (i == 0)
                            {
                                dtTo = item.Key.AddHours(HourRange);
                            }
                            else
                            {
                                dtFrom = item.Key.AddHours(i);
                                dtTo = item.Key.AddHours((i + HourRange));
                                if (dtFrom.Date != dtTo.Date)
                                {
                                    dtTo = new DateTime(dtFrom.Year, dtFrom.Month, dtFrom.Day, 23, 59, 59);
                                }
                            }
                            if (objNewCallHistory.Count(c => c.FromTime == dtFrom && c.ToTime == dtTo) == 0)
                            {
                                HoursDuration = string.Format("{0:HH:mm}", dtFrom) + " to " + string.Format("{0:HH:mm}", dtTo);
                                objNewCallHistory.Add(new NewCallHistory { FromTime = dtFrom, ToTime = dtTo, Id = 0, CalledToNumber = HoursDuration, CallDateTime = dtFrom.ToDate() });
                            }
                        }
                    }
                }


                objNewCallHistory = objNewCallHistory.OrderBy(c => c.FromTime).ToList();

                string heading = string.Empty;
                if (fromDates != null && tillDates != null)
                {
                    heading = string.Format("{0:dd/MM/yy HH:mm}", fromDates) + " to " + string.Format("{0:dd/MM/yy HH:mm}", tillDates);
                }

                response.Data = new
                {
                    list = list,
                    //grouplist = grouplist,
                    objNewCallHistory = Newtonsoft.Json.JsonConvert.SerializeObject(objNewCallHistory)
                };

            }
            catch (Exception ex)
            {

            }

            return Json(response, JsonRequestBehavior.AllowGet);
        }


        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetGraphsReport")]
        public JsonResult GetGraphsReport(AdminApi obj)
        {
            //

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {

                    int Month = obj.Month.ToInt(); ;
                    int Year = obj.Year.ToInt();
                    int User_Id = obj.UserId.ToInt();
                    string DayName = obj.DayName == null ? "" : obj.DayName;
                    string DateType = obj.DateType == null ? "" : obj.DateType;
                    string ReportType = obj.ReportType == null ? "" : obj.ReportType;
                    DateTime from = obj.Fromdate.ToDateTime();
                    DateTime till = obj.Todate.ToDateTime();


                    //FromDate = obj.Fromdate.ToDateTime();
                    //TillDate = obj.Todate.ToDateTime();


                    //FromDate
                    //ToDate
                    //ReportType
                    //DateType


                    string DateStatus = "";
                    DateTime FromDate = DateTime.Now.ToDate();
                    DateTime TillDate = DateTime.Now.ToDate();
                    DateTime Last_WK_FromDate = DateTime.Now.ToDate();
                    DateTime Last_WK_TillDate = DateTime.Now.ToDate();


                    if (DateType == "CURRENT_WEEK")
                    {
                        FromDate = DateTime.Now.GetStartOfCurrentWeek().ToDate();
                        TillDate = DateTime.Now.GetEndOfCurrentWeek().ToDate();
                        Last_WK_FromDate = DateTime.Now.GetStartOfCurrentWeek().ToDate().AddDays(-7);
                        Last_WK_TillDate = DateTime.Now.GetStartOfCurrentWeek().ToDate().AddDays(-1);

                        DateStatus = " For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());

                    }
                    //else if (DateType == "LAST_WEEK")
                    //{

                    //}
                    else if (DateType == "MONTHLY")
                    {
                        FromDate = new DateTime(Year, Month, 1);

                        TillDate = new DateTime(Year, Month, DateTime.DaysInMonth(Year, Month));


                        //Last_WK_FromDate = new DateTime(Year, Month - 1, 1);

                        //Last_WK_TillDate = new DateTime(Year, Month - 1, DateTime.DaysInMonth(Year, Month - 1));

                        DateStatus = " For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());
                    }

                    else if (DateType == "Datewise")
                    {
                        FromDate = from;

                        TillDate = till;


                        //Last_WK_FromDate = new DateTime(Year, Month - 1, 1);

                        //Last_WK_TillDate = new DateTime(Year, Month - 1, DateTime.DaysInMonth(Year, Month - 1));

                        DateStatus = " For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());
                    }

                    else if (DateType == "DAILY")
                    {
                        FromDate = DateTime.Today.ToDateTime();
                        TillDate = DateTime.Now.ToDateTime();

                        DateStatus = "For " + string.Format("{0:dd/MM/yyyy}", FromDate.ToDate()) + " to " + string.Format("{0:dd/MM/yyyy}", TillDate.ToDate());
                    }

                    FromDate = FromDate.ToDate();
                    TillDate = TillDate.ToDate() + TimeSpan.Parse("23:59:59");


                    List<GraphData> GraphDataList = null;

                    //objCnt = db.ExecuteQuery<clsBookingscount>
                    //("exec stp_getbookingsdatacountbystatus {0},{1},{2},{3}", from, till, 0, 0).ToList();
