        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetDriverBookingStatsGraphsReport")]
        public JsonResult GetDriverBookingStatsGraphsReport(AdminApi obj)
        {
            //

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    DateTime from = obj.Fromdate.ToDateTime();
                    DateTime till = obj.Todate.ToDateTime();
                    bool loginWise = obj.loginWise;

                    List<stp_DriverStatsData> resultList = null;

                    try
                    {
                        resultList = db.ExecuteQuery<stp_DriverStatsData>("exec stp_DriverStats {0},{1},{2},{3} ", from, till, loginWise, obj.SubCompanyId).ToList().OrderBy(item => item.DriverNo, new NaturalSortComparer<string>()).ToList();
                    }
                    catch
                    {
                        resultList = db.ExecuteQuery<stp_DriverStatsData>("exec stp_DriverStats {0},{1},{2} ", from, till, loginWise).ToList().OrderBy(item => item.DriverNo, new NaturalSortComparer<string>()).ToList();

                    }

                    response.Data = new
                    {
                        resultList = resultList,
                    };

                }

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }


            return Json(response, JsonRequestBehavior.AllowGet);

        }


        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveLocalizationDetail")]
        public JsonResult SaveLocalizationDetail(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                StringBuilder sb = new StringBuilder();
                StringBuilder sb2 = new StringBuilder();
                List<string> objList = new List<string>();
                string PostCode = string.Join(",", obj.LocalizationDetail.Select(item => item.PostCode).ToList());
                //string PostCode = string.Join(",", grdPostCodes.Rows.Select(c => c.Cells[COLS.PostCode].Value.ToStr()).ToArray<string>());
                string NewPostCode = string.Empty;

                foreach (var item in PostCode.Split(','))
                {
                    string Word = string.Empty;

                    for (int i = 0; i < item.Length; i++)
                    {
                        if (item[i].ToStr().IsNumeric() == true)
                        {
                            objList.Add(Word);
                            break;
                        }
                        else
                        {
                            Word += item[i].ToStr();
                        }
                    }
                }

                var list2 = obj.LocalizationDetail.Select(item => item.PostCode).ToList();

                foreach (var item in list2)
                {
                    sb2.Append("insert into PAFDb.dbo.LocalizationDetail (PostCode) values ('" + item.ToStr() + "');");
                }

                using (TaxiDataContext db = new TaxiDataContext())
                {
                    db.stp_SaveLocalaization(sb.ToStr(), sb2.ToStr());
                }

            }
            catch (Exception ex)
            {


            }


            return Json(response, JsonRequestBehavior.AllowGet);
        }


