        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetLocationList")]
        public JsonResult GetLocationList(AdminApi obj)
        {
            string pageSize = System.Configuration.ConfigurationManager.AppSettings["PageSize"];
            ResponseAdminApi response = new ResponseAdminApi();
            int TotalCount = 0;
            int ResultCount = 0;
            using (TaxiDataContext db = new TaxiDataContext())
            {
                if (obj.LocationId == null)
                {
                    //var data1 = General.GetQueryable<Gen_Location>(null).OrderBy(c => c.LocationName).AsEnumerable();
                    //var data1 = General.GetQueryable<Gen_Location>(null).OrderBy(c => c.LocationName)
                    // .Skip((obj.pageNumber - 1) * Convert.ToInt32(pageSize))
                    // .Take(Convert.ToInt32(pageSize)).AsEnumerable();
                    db.DeferredLoadingEnabled = false;
                    TotalCount = General.GetQueryable<Gen_Location>(null).Count();
                    var data1 = (from Location in db.Gen_Locations
                                 join LocationType in db.Gen_LocationTypes on Location.LocationTypeId equals LocationType.Id
                                 orderby Location.LocationName
                                 select new
                                 {
                                     Location.Id,
                                     Location.LocationName,
                                     LocationType.LocationType,
                                     Location.LocationTypeId,
                                     Location.Address,
                                     Location.PostCode,
                                     Location.ZoneId,
                                     Location.ShortCutKey,
                                     Location.Longitude,
                                     Location.Latitude
                                 });
                    //.Skip((obj.pageNumber - 1) * Convert.ToInt32(pageSize))
                    //.Take(Convert.ToInt32(pageSize))
                    //.ToList();
                    if (!string.IsNullOrEmpty(obj.searchTerm))
                    {
                        data1 = data1.Where(item =>
                            item.LocationName.Contains(obj.searchTerm) ||
                            item.LocationType.Contains(obj.searchTerm) ||
                            item.Address.Contains(obj.searchTerm) ||
                            item.PostCode.Contains(obj.searchTerm) ||
                            item.ShortCutKey.Contains(obj.searchTerm)
                        );
                    }
                    var results = data1.Skip((obj.pageNumber - 1) * Convert.ToInt32(pageSize))
                   .Take(Convert.ToInt32(pageSize))
                   .ToList();
                    if (!string.IsNullOrEmpty(obj.searchTerm))
                    {
                        ResultCount = data1.Count();
                    }
                    else
                    {
                        ResultCount = TotalCount;
                    }
                    //var data2 = General.GetQueryable<Gen_LocationType>(null).AsEnumerable();
                    //var query = from a in data1
                    //            //join b in data2 on a.LocationTypeId equals b.Id
                    //            select new
                    //            {
                    //                Id = a.Id,
                    //                LocationName = a.LocationName,
                    //                //LocationType = b.LocationType,
                    //                LocationTypeId = a.LocationTypeId,
                    //                Address = a.Address,
                    //                PostCode = a.PostCode,
                    //                ZoneId = a.ZoneId,
                    //                ShortCutKey = a.ShortCutKey,
                    //                Longitude = a.Longitude,
                    //                Latitude = a.Latitude
                    //            };
                    response.Data = new
                    {
                        LocationList = results.ToList(),
                        TotalCount = ResultCount,
                        ResultCount = pageSize
                    };
                }
                else
                {
                    var data1 = General.GetQueryable<Gen_Location>(null).OrderBy(c => c.LocationName).AsEnumerable();
                    var data2 = General.GetQueryable<Gen_LocationType>(null).AsEnumerable();
                    var query = from a in data1
                                join b in data2 on a.LocationTypeId equals b.Id
                                where a.Id == Convert.ToInt32(obj.LocationId)
                                select new
                                {
                                    Id = a.Id,
                                    LocationName = a.LocationName,
                                    LocationType = b.LocationType,
                                    LocationTypeId = a.LocationTypeId,
                                    Address = a.Address,
                                    PostCode = a.PostCode,
                                    ZoneId = a.ZoneId,
                                    ShortCutKey = a.ShortCutKey,
                                    Longitude = a.Longitude,
                                    Latitude = a.Latitude
                                };
                    response.Data = new
                    {
                        LocationList = query.ToList(),
                        TotalCount = 0,
                        ResultCount = 0
                    };
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


