        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("DeleteSingleRecentAddress")]
        public JsonResult DeleteSingleRecentAddress(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            string AddressName = obj.AddressName;
            string AddressLine1 = obj.AddressLine1;
            long Id = obj.Id;
            var query = General.GetObject<Gen_RecentAddress>(c => (c.Id == Id) && (c.AddressLine1.Contains(AddressName)));
            if (query != null)
            {
                string[] result = query.AddressLine1.Split(new string[] { "</add>" }, StringSplitOptions.RemoveEmptyEntries);
                if (result.Count() > 1)
                {
                    AddressLine1 = AddressLine1.Replace("<add>" + AddressName + "</add>", "");
                    //AddressLine1 = AddressLine1.Replace("<add></add>","");
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        if (!string.IsNullOrEmpty(AddressLine1))
                        {
                            string queryX = "UPDATE Gen_RecentAddresses SET AddressLine1 = REPLACE(AddressLine1, '<add>" + AddressName.Replace("'", "''") + "</add>', '') WHERE Id in (" + Id + "); ";




                            db.stp_RunProcedure(queryX);
                        }
                        else
                        {
                            db.stp_RunProcedure("delete  from Gen_RecentAddresses where Id=" + Id + "");
                        }


                        try
                        {
                            //
                            if (AddressName.ToStr().Trim().Length > 0)
                            {

                                db.ExecuteQuery<int>("delete from Customer_History where  (Pickup='" + AddressName + "' OR Destination='" + AddressName + "')");
                            }
                        }
                        catch
                        {


                        }


                    }
                }
                else
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        db.stp_RunProcedure("delete  from Gen_RecentAddresses where Id=" + Id + "");

                        try
                        {
                            //
                            if (AddressName.ToStr().Trim().Length > 0)
                            {

                                db.ExecuteQuery<int>("delete from Customer_History where  (Pickup='" + AddressName + "' OR Destination='" + AddressName + "')");
                            }
                        }
                        catch
                        {


                        }
                    }
                }

            }

            return Json(response, JsonRequestBehavior.AllowGet);
        }


