        public JsonResult SaveManagePlot(ManagePlotsZoneRequest obj)

        {
            ZoneBO objZone = new ZoneBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {


                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveManagePlot.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }

                DateTime? dt = null;

                ZoneBO objMaster = new ZoneBO();

                using (TaxiDataContext db = new TaxiDataContext())

                {

                    foreach (var item in obj.ManagePlotsZoneList)
                    {

                        objMaster.GetByPrimaryKey(item.Id.ToInt());

                        if (objMaster.Current != null)
                        {
                            dt = item.FlashingHour.ToDateTimeorNull();

                            if (dt != null && (dt.Value.Minute == 0 && dt.Value.Hour == 0))
                                dt = null;

                            objMaster.Current.FlashingHour = dt;


                            dt = item.JobDueTime.ToDateTimeorNull();

                            if (dt != null && (dt.Value.Minute == 0 && dt.Value.Hour == 0))
                                dt = null;

                            objMaster.Current.JobDueTime = dt;

