        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveFormListData")]
        public JsonResult SaveFormListData(AdminApi obj)
        {
            SecGroupBO objMaster = new SecGroupBO();
            ResponseAdminApi response = new ResponseAdminApi();

            try
            {
                if (string.IsNullOrEmpty(obj.Id.ToStr()))
                {
                    objMaster.New();
                }
                else
                {
                    objMaster.GetByPrimaryKey(obj.Id);
                    objMaster.Edit();
                }
                List<UM_SecurityGroup_Permission> listofAuthorities = (from r in obj.AuthoritiesList
                                                                       select new UM_SecurityGroup_Permission
                                                                       {
                                                                           Id = r.Id.ToInt(),
                                                                           FormFunctionId = r.FormFunctionId,
                                                                           SecurityGroupId = r.SecurityGroupId
                                                                       }).ToList();
                string[] skipProperties = { "UM_SecurityGroup", "UM_FormFunction" };
                IList<UM_SecurityGroup_Permission> savedList = objMaster.Current.UM_SecurityGroup_Permissions;
                Utils.General.SyncChildCollection(ref savedList, ref listofAuthorities, "Id", skipProperties);
                objMaster.Save();
                SaveFormTemplates();
                //     ENUtils.ShowMessage("Save Successful");
                objMaster.GetByPrimaryKey(objMaster.PrimaryKeyValue);
            }
            catch (Exception ex)
            {
                if (objMaster.Errors.Count > 0)
                {
                }
                else
                {
                }
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetFormFunctionData")]
        public JsonResult GetFormFunctionData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                var SecurityGroupList = (from a in General.GetQueryable<UM_SecurityGroup_Permission>(c => c.SecurityGroupId != null)
                                         orderby a.SecurityGroupId
                                         select new
                                         {
                                             FormId = a.Id,
                                             FormFunctionId = a.FormFunctionId,
                                             SecurityGroupId = a.SecurityGroupId,
                                         }).ToList();
                var FormFunctionList = (from a in General.GetQueryable<UM_FormFunction>(c => c.FormId != null)
                                        orderby a.FunctionId
                                        select new
                                        {
                                            Id = a.Id,
                                            FormId = a.FormId,
                                            FunctionId = a.FunctionId
                                        }).ToList();
                var SecurityGroupFormList = (from a in SecurityGroupList
                                             join b in FormFunctionList on a.FormFunctionId equals b.Id
                                             where a.SecurityGroupId == obj.Id
                                             orderby a.FormId
                                             select new
                                             {
                                                 SecurityGroupId = a.SecurityGroupId,
                                                 FormFunctionId = a.FormFunctionId,
                                                 FormId = b.FormId,
                                                 FunctionId = b.FunctionId
                                             }).ToList();
                var FunctionList = (from b in General.GetQueryable<UM_Function>(d => d.FunctionName != null)
                                    select new
                                    {
                                        Id = b.Id,
                                        FunctionName = b.FunctionName
                                    }).ToList();
                var JoinedList = (from a in FormFunctionList
                                  join b in FunctionList on a.FunctionId equals b.Id
                                  orderby a.FormId
                                  select new
                                  {
                                      FormId = a.FormId,
                                      FunctionId = a.FunctionId,
                                      FunctionName = b.FunctionName
                                  });
                response.Data = new { JoinedList = JoinedList, SecurityGroupFormList = SecurityGroupFormList, FormFunctionList = FormFunctionList };
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetFormListData")]
        public JsonResult GetFormListData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                var securityGroupList = (from a in General.GetQueryable<UM_SecurityGroup>(c => c.Id != null)
                                         select new
                                         {
                                             Id = a.Id,
                                             GroupName = a.GroupName
                                         }).ToList();
                var formsList = (from a in General.GetQueryable<UM_Form>(c => c.ModuleId != null)
                                 orderby a.ModuleId
                                 select new
                                 {
                                     Id = a.Id,
                                     FormName = a.FormName,
                                     FormTitle = a.FormTitle,
                                     ModuleId = a.ModuleId
                                 }).ToList();
                var modulesList = (from a in General.GetQueryable<UM_Module>(c => c.Id != null)
                                   orderby a.Id
                                   select new
                                   {
                                       Id = 0,
                                       ModuleId = a.Id,
                                       ModuleName = a.ModuleName,
                                       FormName = "",
                                       FormTitle = ""
                                   }).ToList();
                var joinedList = (from a in formsList
                                  join b in modulesList on a.ModuleId equals b.ModuleId
                                  select new
                                  {
                                      Id = a.Id,
                                      ModuleId = a.ModuleId.ToInt(),
                                      ModuleName = b.ModuleName,
                                      FormName = a.FormName,
                                      FormTitle = a.FormTitle
                                  }).ToList();
                var combinedList = modulesList.Concat(joinedList).OrderBy(item => item.ModuleId).ToList();
                response.Data = new { combinedList = combinedList, securityGroupList = securityGroupList };
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }



        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetZonesList")]
        public JsonResult GetZonesList()
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                General OBJ = new General();
                List<Gen_Zones> data = null;
                //
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetZonesList.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(response.Data) + Environment.NewLine);
                }
                catch
                {
                }
                List<Gen_Zones> lst = new List<Gen_Zones>();
                ZoneMasterDetailList obj = new ZoneMasterDetailList();
                List<ZonesMaster> zonesMaster = new List<ZonesMaster>();
                List<Gen_Zone_PolyVertices> gen_Zone_PolyVertices = new List<Gen_Zone_PolyVertices>();
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    zonesMaster = db.ExecuteQuery<ZonesMaster>(@"SELECT [Id],[ZoneName],[AddOn],[AddBy],[EditOn],[EditBy],[PostCode],[OrderNo],[ShapeCategory],[ShapeType],[Linewidth],[Lineforecolor],[MinLatitude],[MaxLatitude]
                        ,[MinLongitude],[MaxLongitude],[ShortName],[EnableAutoDespatch],[EnableBidding],[BiddingRadius],[ZoneTypeId],[PlotKind],[DisableDriverRank],[JobDueTime],[IsOutsideArea]
                        FROM[Gen_Zones]").ToList();
                    gen_Zone_PolyVertices = db.ExecuteQuery<Gen_Zone_PolyVertices>(@"SELECT[Id] ,[PostCode],[Latitude],[Longitude],[ZoneId],[Diameter] FROM[Gen_Zone_PolyVertices]").ToList();
                }

                obj.ZoneMaster = zonesMaster;
                obj.ZoneDetail = gen_Zone_PolyVertices;
                foreach (var item in obj.ZoneMaster)
                {
                    Gen_Zones dataX = new Gen_Zones();
                    dataX.Id = item.Id;
                    dataX.ZoneName = item.ZoneName;
                    dataX.AddOn = item.AddOn;
                    dataX.AddBy = item.AddBy;
                    dataX.EditOn = item.EditOn;
                    dataX.EditBy = item.EditBy;
                    dataX.PostCode = item.PostCode;
                    dataX.OrderNo = item.OrderNo;
                    dataX.ShapeCategory = item.ShapeCategory;
                    dataX.ShapeType = item.ShapeType;
                    dataX.Linewidth = item.Linewidth;
                    dataX.Lineforecolor = item.Lineforecolor;
                    dataX.MinLatitude = item.MinLatitude;
                    dataX.MaxLatitude = item.MaxLatitude;
                    dataX.MinLongitude = item.MinLongitude;
                    dataX.MaxLongitude = item.MaxLongitude;
                    dataX.ShortName = item.ShortName;
                    dataX.EnableAutoDespatch = item.EnableAutoDespatch;
                    dataX.EnableBidding = item.EnableBidding;
                    dataX.BiddingRadius = item.BiddingRadius;
                    dataX.ZoneTypeId = item.ZoneTypeId;
                    dataX.PlotKind = item.PlotKind;
                    dataX.DisableDriverRank = item.DisableDriverRank;
                    dataX.JobDueTime = item.JobDueTime;
                    dataX.IsOutsideArea = item.IsOutsideArea;
                    dataX.Gen_Zone_PolyVertices = obj.ZoneDetail.Where(a => a.ZoneId == dataX.Id).ToList();
                    lst.Add(dataX);
                }
                response.Data = lst;
            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetZonesList_exception.txt", DateTime.Now + ",exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                response.Message = ex.Message;
            }
            return new CustomJsonResult { Data = response };
        }
