        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SaveFleetVehicleType")]
        public JsonResult SaveFleetVehicleType(AdminApi obj, HttpPostedFileBase file)
        {
            //


            //BookingBO objMaster = new BookingBO();
            VehicleTypeBO objFleetType = new VehicleTypeBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {


                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFleetVehicleType.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {

                }


                using (TaxiDataContext db = new TaxiDataContext())
                {


                    //long? AdvanceBookingId = obj.advancebookingInfo.AdvanceBookingId.ToLong();

                    int? Id = obj.fleetVehicleType.Id;


                    if (Id == 0)
                    {

                        Fleet_VehicleType objVehicle = General.GetQueryable<Fleet_VehicleType>(null).OrderByDescending(c => c.Id).FirstOrDefault();
                        objFleetType.New();
                        objFleetType.Current.OrderNo = objVehicle.Id + 1;
                    }
                    else
                    {
                        objFleetType.GetByPrimaryKey(Id);
                        objFleetType.Edit();
                    }

                    //model.FileAttach.InputStream.Read(uploadedFile, 0, uploadedFile.Length);
                    objFleetType.Current.VehicleType = obj.fleetVehicleType.VehicleType.ToStr();
                    objFleetType.Current.NoofPassengers = obj.fleetVehicleType.NoofPassengers.ToInt();
                    objFleetType.Current.NoofLuggages = obj.fleetVehicleType.NoofLuggages.ToInt();
                    objFleetType.Current.NoofHandLuggages = obj.fleetVehicleType.NoofHandLuggages.ToInt();
                    objFleetType.Current.StartRate = obj.fleetVehicleType.StartRate.ToDecimal();
                    objFleetType.Current.StartRateValidMiles = obj.fleetVehicleType.StartRateValidMiles.ToDecimal();
                    //objFleetType.Current.Photo = obj.fleetVehicleType.Photo.GetByteArrayOfImage();
                    if (file != null)
                    {
                        byte[] uploadedFile = new byte[file.InputStream.Length];
                        objFleetType.Current.Photo = uploadedFile;
                    }


                    //objFleetType.Current.Priority = numASAPPriority.Value.ToInt();
                    //objFleetType.Current.PreBookPriority = numPreBookPriority.Value.ToInt();

                    objFleetType.Current.BackgroundColor = obj.fleetVehicleType.BackgroundColor.ToStr();
                    objFleetType.Current.TextColor = obj.fleetVehicleType.TextColor.ToStr();

                    if (obj.fleetVehicleType.AttributeValues.ToStr().Length > 0 && obj.fleetVehicleType.AttributeValues.ToStr().StartsWith(",") == false)
                        objFleetType.Current.AttributeValues = "," + obj.fleetVehicleType.AttributeValues.ToStr() + ",";
                    else
                        objFleetType.Current.AttributeValues = obj.fleetVehicleType.AttributeValues.ToStr();

                    if (objFleetType.Current.AttributeValues == null)
                        objFleetType.Current.AttributeValues = "";


                    objFleetType.Save();




                    db.SubmitChanges();

                    response.Data = "";




                }
            }
            catch (Exception ex)
            {
                try
                {
                    response.HasError = true;

                    if (objFleetType.Errors.Count == 0)
                    {
                        response.Message = ex.Message;
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFleetVehicleType.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);


                    }
                    else
                    {
                        response.Message = objFleetType.ShowErrors();
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "SaveFleetVehicleType.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);

                    }
                }
                catch
                {

                }
            }


            return Json(response, JsonRequestBehavior.AllowGet);

        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetFareMeterSetting")]
        public JsonResult GetFareMeterSetting(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            using (TaxiDataContext db = new TaxiDataContext())
            {
                db.DeferredLoadingEnabled = false;
                var VehicleTypes = (from a in db.Fleet_VehicleTypes
                                    orderby a.OrderNo
                                    select new
                                    {
                                        VehicleTypeId = a.Id,
                                        VehicleType = a.VehicleType
                                    }).ToList();
                List<FareMeterSetting> MeterSetting = db.ExecuteQuery<FareMeterSetting>("select * from Gen_SysPolicy_FareMeterSettings where SysPolicyId is not null").ToList();
                //var MeterSetting = (from a in General.GetQueryable<Gen_SysPolicy_FareMeterSetting>(c => c.SysPolicyId != null)
                //                    select new
                //                    {
                //                        Id = a.Id,
                //                        SysPolicyId = a.SysPolicyId,
                //                        VehicleTypeId = a.VehicleTypeId,
                //                        HasMeter = a.HasMeter,
                //                        AutoStartWaiting = a.AutoStartWaiting,
                //                        a.AutoStartWaitingBelowSpeed,
                //                        // a.AutoStartWaitingMinDist,
                //                        a.AutoStartWaitingBelowSpeedSeconds,
                //                        AutoStopWaitingSpeed = a.AutoStopWaitingOnSpeed,
                //                        DrvWaitingCharges = a.DrvWaitingChargesPerMin,
                //                        WaitingTime = a.AccWaitingChargesPerMin
                //                    }).ToList();


                var FareMeterSetting = (from a in VehicleTypes
                                        join b in MeterSetting on a.VehicleTypeId equals b.VehicleTypeId into table2
                                        from b in table2.DefaultIfEmpty()
                                        select new
                                        {
                                            Id = b != null ? b.Id : 0,
                                            VehicleTypeId = a.VehicleTypeId,
                                            VehicleType = a.VehicleType,
                                            SysPolicyId = b != null ? b.SysPolicyId : 1,
                                            HasMeter = b != null ? b.HasMeter : false,
                                            AutoStartWaiting = b != null ? b.AutoStartWaiting : false,
                                            AutoStartWaitingBelowSpeed = b != null ? b.AutoStartWaitingBelowSpeed : 0.00m,
                                            AutoStartWaitingBelowSpeedSeconds = b != null ? b.AutoStartWaitingBelowSpeedSeconds : 0,
                                            AutoStopWaitingSpeed = b != null ? b.AutoStopWaitingOnSpeed : 0.00m,
                                            DrvWaitingCharges = b != null ? b.DrvWaitingChargesPerMin : 0.00m,
                                            WaitingTime = b != null ? b.AccWaitingChargesPerMin : 0.00m,
                                            FreeWaitingSeconds = b != null ? b.FreeWaitingSeconds : 0.00m
                                        }).ToList();


                Gen_SysPolicy obj1 = db.Gen_SysPolicies.FirstOrDefault();
                var BookingFee1 = (from a in db.Gen_SysPolicy_Configurations
                                   where a.SysPolicyId == obj1.Id
                                   select new
                                   {
                                       PDANewWeekMessageByDay = a.PDANewWeekMessageByDay
                                   }).ToList();
                var jsonString = BookingFee1[0].PDANewWeekMessageByDay.ToString();
                MySettings settings = Newtonsoft.Json.JsonConvert.DeserializeObject<MySettings>(jsonString);
                response.Data = new
                {
                    FareMeterSetting = FareMeterSetting.ToList(),
                    //  PDANewWeekMessageByDay = BookingFee1[0].PDANewWeekMessageByDay,
                    BookingFeesRange = settings.BookingFeesRange,
                    ChangePlotOnAsDirected = settings.ChangePlotOnAsDirected,
                    ExtraChargesPerQty = settings.ExtraChargesPerQty,
                    RemoveExtraCharges = settings.RemoveExtraCharges,
                    ShowBookingFees = settings.ShowBookingFees,
                    ShowExtraCharges = settings.ShowExtraCharges,
                    ShowParkingCharges = settings.ShowParkingCharges
                };
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }


        #region Shuttle
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetBookingsForShuttle")]
        public JsonResult GetBookingsForShuttle(AdminApi obj)
        {
            //
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetBookingsForShuttle.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    Expression<Func<Booking, bool>> expPickBooking = null;

                    expPickBooking = c =>
                                        (c.BookingStatusId == Enums.BOOKINGSTATUS.WAITING
                                        || c.BookingStatusId == Enums.BOOKINGSTATUS.ONROUTE
                                        || c.BookingStatusId == Enums.BOOKINGSTATUS.ARRIVED
                                        || c.BookingStatusId == Enums.BOOKINGSTATUS.POB
                                          || c.BookingStatusId == Enums.BOOKINGSTATUS.STC
                                            || c.BookingStatusId == Enums.BOOKINGSTATUS.REJECTED
                                              || c.BookingStatusId == Enums.BOOKINGSTATUS.PENDING_START
                                               || c.BookingStatusId == Enums.BOOKINGSTATUS.BID

                                        || c.BookingStatusId == Enums.BOOKINGSTATUS.NOPICKUP || c.BookingStatusId == Enums.BOOKINGSTATUS.COMPLETED)
                                       && (c.PickupDateTime >= obj.Fromdate && c.PickupDateTime <= obj.TillDate);

                    var bookings = db.Bookings.Where(expPickBooking).ToList();

                    var list = (from b in bookings

                                select new
                                {
                                    Id = b.Id,
                                    PickupDate = b.PickupDateTime,
                                    RefNo = b.BookingNo,
                                    Vehicle = b.Fleet_VehicleType.VehicleType,
                                    Passenger = b.CustomerName,
                                    NoofPax = b.NoofPassengers,
                                    PickupPoint = b.FromAddress,
                                    Destination = b.ToAddress,
                                    GroupJobId = b.GroupJobId,
                                    ShuttleNo = b.GroupJobId != null ? b.BookingGroup.GroupName : "",
                                    Status = b.BookingStatus.StatusName,
                                    b.BookingStatusId
                                }).OrderBy(c => c.PickupDate).ToList();
                    int total = list.Sum(c => c.NoofPax).ToInt();

                    response.Data = new
                    {
                        Bookings = list,
                        PaxCount = total

                    };
                }
            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetBookingsForShuttle.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                response.Message = ex.Message;
            }
            return new CustomJsonResult { Data = response };
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetShuttleList")]
        public JsonResult GetShuttleList(AdminApi obj)
        {
            //
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetShuttleList.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    DateTime? FromShuttleDate = obj.DateCriteria + TimeSpan.Parse("00:00:00");
                    DateTime? ToShuttleDate = obj.DateCriteria + TimeSpan.Parse("23:59:59");

                    var list2 = General.GetGeneralList<BookingGroup>(c => c.TripDate.Value.Date >= FromShuttleDate && c.TripDate.Value.Date <= ToShuttleDate);
                    var Driver = db.Fleet_Drivers.ToList();
                    var TripStatus = db.BookingTripStatus.ToList();


                    var list = (from b in list2
                                join a in Driver on b.DriverId equals a.Id into driverJoin
                                from driver in driverJoin.DefaultIfEmpty()
                                join c in TripStatus on b.TripStatusId equals c.Id
                                where (b.TripStatusId != Enums.BOOKING_TRIPSTATUS.CANCELLED && b.TripStatusId != Enums.BOOKING_TRIPSTATUS.COMPLETED)
                                orderby b.TripDate ascending
                                select new
                                {
                                    Id = b.Id,
                                    ShuttleNo = b.GroupName,
                                    ShuttleDateTime = b.TripDate,
                                    DriverId = driver != null ? (int?)driver.Id : null,
                                    Driver = driver != null ? driver.DriverName : null, // Access driver.DriverName
                                    TotalNoOfPax = b.TotalNoOfPassenger,
                                    TotalBookings = b.TotalBookings,
                                    TripStatusId = b.TripStatusId,
                                    TripStatus = c.StatusName,
                                }).ToList();
                    response.Data = new
                    {
                        ShuttleBookings = list,
                    };
                }
            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetLoadCommisionList.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                response.Message = ex.Message;
            }
            return new CustomJsonResult { Data = response };
        }


