        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("DispatchShuttleTrip")]
        public JsonResult DispatchShuttleTrip(ShuttleTrip obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();

            string json = string.Empty;
            try
            {
                try
                {
                    //
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\dispatchtrip.txt", DateTime.Now.ToStr() + " json" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                }
                catch
                {
                }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    obj.jobs = new List<ShuttleJobs>();
                    foreach (var item in db.Bookings.Where(c => c.GroupJobId == obj.TripId).ToList())
                    {
                        ShuttleJobs job = new ShuttleJobs();
                        job.Pickup = item.FromAddress.ToStr();
                        job.Destination = item.ToAddress.ToStr();
                        job.PickupDateTime = string.Format("{0:dd/MM/yyyy HH:mm}", item.PickupDateTime);
                        job.ShowFares = true;
                        job.Passengers = item.NoofPassengers.ToInt();
                        job.BookingNo = item.BookingNo.ToStr();
                        job.JobId = item.Id.ToStr();
                        job.Payment = item.Gen_PaymentType.PaymentType.ToStr();
                        job.Did = item.DriverId.ToInt();
                        job.Cust = item.CustomerName.ToStr();


                        if (obj.TripStatusId == 0)
                            obj.TripStatusId = 1;

                        if (item.BookingStatusId == Enums.BOOKINGSTATUS.ONROUTE)
                            job.JStatus = AppJobStatus.ONROUTE;
                        else if (item.BookingStatusId == Enums.BOOKINGSTATUS.ARRIVED)
                            job.JStatus = AppJobStatus.ARRIVED;
                        else if (item.BookingStatusId == Enums.BOOKINGSTATUS.POB)
                            job.JStatus = AppJobStatus.POB;
                        else if (item.BookingStatusId == Enums.BOOKINGSTATUS.STC)
                            job.JStatus = AppJobStatus.STC;
                        //   else  if (item.BookingStatusId == Enums.BOOKINGSTATUS.)
                        else
                            job.JStatus = AppJobStatus.ACCEPT;
                        if (item.BookingStatusId != Enums.BOOKINGSTATUS.DISPATCHED && item.BookingStatusId != Enums.BOOKINGSTATUS.NOPICKUP && item.BookingStatusId != Enums.BOOKINGSTATUS.CANCELLED)
                        {
                            obj.jobs.Add(job);
                        }
                    }

                }
                json = new JavaScriptSerializer().Serialize(obj);
                if (obj.TripStatusId.ToStr() == "17")
                {
                    json = "alertpreshuttlelist:You have received a shuttle";
                }
                HubProcessor.Instance.listofJobs.Add(new clsPDA
                {
                    DriverId = obj.DriverId.ToInt(),
                    JobId = obj.TripId,
                    MessageDateTime = DateTime.Now.AddSeconds(-30),
                    JobMessage = json,
                    MessageTypeId = eMessageTypes.TRIP
                });
                if (obj.TripStatusId == Enums.BOOKING_TRIPSTATUS.CANCELLED || obj.TripStatusId == 5)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                        db.ExecuteQuery<int>("exec stp_updatetripstatus {0},{1},{2},{3}", obj.TripId, obj.TripStatusId, obj.DriverId.ToInt(), obj.Message.ToStr());
                    General.BroadCastMessage("**refresh required dashboard");
                }
                else if (obj.TripStatusId == Enums.BOOKING_TRIPSTATUS.INPROGRESS)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        db.ExecuteQuery<int>("Update Booking set bookingstatusId=5   where bookingstatusid in(1,11,12,15) and groupJobId = " + obj.TripId + "");
                    }
                }

                else if (obj.TripStatusId.ToStr() == "17")
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        db.ExecuteQuery<int>("update BookingGroup set TripStatusId=17 where id=" + obj.TripId);
                        foreach (var item in obj.jobs)
                        {
                            db.stp_UpdateJobStatus(item.JobId.ToLong(), Enums.BOOKINGSTATUS.PENDING_START);
                        }
                    }
                }
                response.HasError = false;
                return new CustomJsonResult { Data = response };
            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\dispatchtrip_exception.txt", DateTime.Now.ToStr() + " json" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                return new CustomJsonResult { Data = response };
            }
        }



