                    ObjMaster.Current.Name = obj.AttributeName;
                    ObjMaster.Current.ShortName = obj.ShortName;
                    // ObjMaster.Current.AttributeCategoryId = Enums.ATTRIBUTE_CATEGORY.Driver;
