                                           a.DisableRejectJobAuth
                                       }).ToList();
                    var data1 = General.GetQueryable<Fleet_Driver>(null).OrderBy(c => c.DriverNo).AsEnumerable();
                    var data2 = General.GetQueryable<Fleet_Driver_PDASetting>(null).AsEnumerable();
                    var data3 = General.GetQueryable<Fleet_DriverQueueList>(null).AsEnumerable();
                    var PDALoggedinDriversList = from a in data1
                                                 join b in data2 on a.Id equals b.DriverId
                                                 join c in data3 on a.Id equals c.DriverId
                                                 where a.HasPDA == true && c.Status == true
                                                 group new { a, b } by new { a.Id, a.DriverNo } into g
                                                 select new
                                                 {
