                                                     DriverNo = g.Key.DriverNo,
                                                     CurrentPdaVersion = g.FirstOrDefault().b.CurrentPdaVersion
                                                 };
                    var PDAAllDriversList = from a in data1
                                            join b in data2 on a.Id equals b.DriverId
                                            join c in data3 on a.Id equals c.DriverId
                                            where a.HasPDA == true && c.Status != null
                                            group new { a, b } by new { a.Id, a.DriverNo } into g
                                            select new
                                            {
