                    //            where a.Status != null && a.Status == true && a.Fleet_Driver.HasPDA == true
                    //            select new
                    //            {
                    //                DriverId = a.Fleet_Driver.Id,
                    //                DriverNo = a.Fleet_Driver.DriverNo,
                    //                CurrentPdaVersion = a.Fleet_Driver.Fleet_Driver_PDASettings.Count > 0 ? a.Fleet_Driver.Fleet_Driver_PDASettings.FirstOrDefault().CurrentPdaVersion : null
                    //            }).ToList().Where(c => c.CurrentPdaVersion != null).OrderBy(item => item.DriverNo, new NaturalSortComparer<string>()).ToList();
                    //var PDAAllDriversList = (from a in db.GetTable<Fleet_DriverQueueList>()
                    //                              where a.Status != null && a.Fleet_Driver.HasPDA == true
                    //                              select new
                    //                              {
                    //                                  DriverId = a.Fleet_Driver.Id,
                    //                                  DriverNo = a.Fleet_Driver.DriverNo,
                    //                                  CurrentPdaVersion = a.Fleet_Driver.Fleet_Driver_PDASettings.Count > 0 ? a.Fleet_Driver.Fleet_Driver_PDASettings.FirstOrDefault().CurrentPdaVersion : null
                    //                              }).ToList().Where(c => c.CurrentPdaVersion != null).OrderBy(item => item.DriverNo, new NaturalSortComparer<string>()).ToList();
                    response.Data = new { PDALoggedinDriversList = PDALoggedinDriversList, PDAAllDriversList = PDAAllDriversList, PDASettings = PDASettings };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
        int oddCnt = 1;
        string lastETA = string.Empty;
        double? LastSpeed = null;
        //GMapMarkerCustom markerDrv = null;
        string EstimatedTimeLeft = "";
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetETA")]
        public JsonResult GetETA(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                if (obj.chkETA)
                {
                    var key = "";
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        var etaKey = db.ExecuteQuery<string>("select APIKey from MapKeys where Id=6").ToList();
                        key = etaKey[0];
                    }
                    if ((LastSpeed == null || LastSpeed != obj.Speed))
                    {
                        if (oddCnt % 2 == 1)
                        {
                            try
                            {
                                GetDistance.Coords obj1 = new GetDistance.Coords { Latitude = obj.Latitude, Longitude = obj.Longitude };
                                if (obj.WorkStatus.ToStr() == "On Route" || obj.WorkStatus.ToStr() == "Arrived")
                                {
                                    //GetDistance.Coords obj2 = new GetDistance.Coords { Latitude = gMapControl1.Overlays[0].Markers.FirstOrDefault(c => c.Tag.ToStr() == "Pickup").Position.Lat, Longitude = gMapControl1.Overlays[0].Markers.FirstOrDefault(c => c.Tag.ToStr() == "Pickup").Position.Lng };
                                    GetDistance.Coords obj2 = new GetDistance.Coords { Latitude = obj.PosLatitude, Longitude = obj.PosLongitude };
                                    // EstimatedTimeLeft = GetDistance.GetLocationDetailsByMapHere(obj1, obj2, AppVars.etaKey, null);
                                    EstimatedTimeLeft = General.GetETATime(obj1.Latitude + "," + obj1.Longitude, obj2.Latitude + "," + obj2.Longitude, key);
                                    if (EstimatedTimeLeft.ToStr().Trim().Length > 0)
                                    {
                                        EstimatedTimeLeft = "Pickup ETA : " + EstimatedTimeLeft;
                                    }
                                }
                                else if (obj.WorkStatus.ToStr() == "Passenger On Board" || obj.WorkStatus.ToStr() == "Soon To Clear")
                                {
                                    //if (gMapControl1.Overlays[0].Markers.Count > 2)
                                    // {
                                    GetDistance.Coords obj2 = new GetDistance.Coords { Latitude = obj.PosLatitude, Longitude = obj.PosLongitude };
                                    //EstimatedTimeLeft = GetDistance.GetLocationDetailsByMapHere(obj1, obj2, AppVars.etaKey, null);
                                    EstimatedTimeLeft = General.GetETATime(obj1.Latitude + "," + obj1.Longitude, obj2.Latitude + "," + obj2.Longitude, key);
                                    if (EstimatedTimeLeft.ToStr().Trim().Length > 0)
                                    {
                                        EstimatedTimeLeft = "DropOff ETA : " + EstimatedTimeLeft;
                                    }
                                    // }
                                    // else
                                    // {
                                    try
                                    {
                                        obj.chkETA = false;
                                    }
                                    catch
                                    {
                                    }
                                    //}
                                }
                            }
                            catch
                            {
                            }
                            lastETA = EstimatedTimeLeft;
                        }
                        else
                            EstimatedTimeLeft = lastETA;
                        oddCnt++;
                    }
                }
                else
                {
                    EstimatedTimeLeft = lastETA;
                }
                response.Data = EstimatedTimeLeft;
            }
            catch (Exception ex)
            {
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetJobClearingData")]
        public JsonResult GetJobClearingData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                int hours = obj.ExpiredPDAJobHours;

                DateTime now = DateTime.Now.AddHours(-hours);

                var JobClearing = (from a in General.GetQueryable<Booking>(null).Where(c => (c.BookingStatusId == Enums.BOOKINGSTATUS.ONROUTE || c.BookingStatusId == Enums.BOOKINGSTATUS.ARRIVED
                                                                   || c.BookingStatusId == Enums.BOOKINGSTATUS.POB || c.BookingStatusId == Enums.BOOKINGSTATUS.STC
                                                                   || c.BookingStatusId == Enums.BOOKINGSTATUS.FOJ)
                                                                   //&& c.DriverId != null && DateTime.Now.Subtract(c.PickupDateTime.Value).Hours >= hours)
                                                                   && c.DriverId != null && c.PickupDateTime.Value < now)

                                   select new
                                   {
                                       Id = a.Id,
                                       RefNo = a.BookingNo,
                                       PickupDateTime = a.PickupDateTime,
                                       Passenger = a.CustomerName,
                                       PickupPoint = a.FromAddress,
                                       Destination = a.ToAddress,
                                       Driver = a.Fleet_Driver.DriverNo,
                                       Status = a.BookingStatus.StatusName

                                   }).OrderByDescending(c => c.PickupDateTime).ToList();


                response.Data = new { JobClearing = Newtonsoft.Json.JsonConvert.SerializeObject(JobClearing) };

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
