        [System.Web.Http.Route("ClearSingleJobData")]
        public JsonResult ClearSingleJobData(AdminApi obj)
        {
            //
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                BookingBO obj1 = new BookingBO();
                obj1.GetByPrimaryKey(obj.JobId.ToInt());
                if (obj1.Current != null)
                {
                    obj1.CheckCustomerValidation = false;
                    obj1.CheckDataValidation = false;
                    obj1.DisableUpdateReturnJob = true;
                    obj1.Current.BookingStatusId = Enums.BOOKINGSTATUS.DISPATCHED;
                    obj1.Save();
                }

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("DeleteDriverCommissionListRecord")]
        public JsonResult DeleteDriverCommissionListRecord(AdminApi obj)
        {
            //
            DriverCommisionBO objMaster = new DriverCommisionBO();
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                objMaster.GetByPrimaryKey(obj.Id);
                string Transaction = obj.TransNo;
                int DriverId = obj.DriverId.ToInt();
                var query = General.GetQueryable<Fleet_DriverCommision>(c => c.DriverId == DriverId).OrderByDescending(c => c.Id).FirstOrDefault();
                if (query != null)
                {
                    string Transno = query.TransNo.ToStr();
                    if (Transno == Transaction)
                    {
                        objMaster.Delete(objMaster.Current);
                    }
                    else
                    {
                        //response.ShowMessage("You Can not delete a record..");
                    }
                }
            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetDriverCommissionList.txt", DateTime.Now + " exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                response.Message = ex.Message;
            }
            return new CustomJsonResult { Data = response };
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetDriverEarningReportPrint")]
        public JsonResult GetDriverEarningReportPrint(AdminApi obj)
        {
            string templateName = null;
            //
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetDriverEarningReportPrint.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                if (templateName == null)
                    templateName = General.GetObject<UM_Form_Template>(c => c.UM_Form.FormName == "rptfrmDriverEarning" && c.IsDefault == true).DefaultIfEmpty().TemplateName.ToStr();


                DateTime FromdatePart = (obj.Fromdate).ToDateTime();
                DateTime FromtimePart = (obj.FromTime).ToDateTime();
                // Combine date from datePart and time from timePart
                DateTime FromDate = new DateTime(
                    FromdatePart.Year,
                    FromdatePart.Month,
                    FromdatePart.Day,
                    FromtimePart.Hour,
                    FromtimePart.Minute,
                    FromtimePart.Second
                );
                DateTime TodatePart = (obj.Todate).ToDateTime();
                DateTime TotimePart = (obj.ToTime).ToDateTime();
                // Combine date from datePart and time from timePart
                DateTime ToDate = new DateTime(
                    TodatePart.Year,
                    TodatePart.Month,
                    TodatePart.Day,
