        private decimal AvgJob(decimal Total, decimal Commission, int JobsDone)
        {
            decimal Avg = 0.00m;
            if (JobsDone == 0)
                JobsDone = 1;
            Avg = ((Total - Commission) / JobsDone);
            return Avg;
        }
