        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("RecallBooking")]
        public JsonResult RecallBooking(BookingRecallRequest obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                bool success = false;
                if (obj.bookingStatusId.ToInt() == Enums.BOOKINGSTATUS.FOJ)
                {
                    success = General.ReCallFOJBooking(obj.id, obj.driverId);
                }
                else if (obj.bookingStatusId.ToInt() == Enums.BOOKINGSTATUS.PENDING_START)
                {
                    success = General.ReCallPreBooking(obj.id, obj.driverId, obj.UserName);

                }

                else
                {

                    success = General.ReCallBooking(obj.id, obj.driverId);
                }
                General.MessageToPDA("request broadcast=" + RefreshTypes.REFRESH_REQUIRED_DASHBOARD + "=" + obj.id);
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            var jsonResult = Json(response, JsonRequestBehavior.AllowGet);
            jsonResult.MaxJsonLength = int.MaxValue;
            return jsonResult;
        }


        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("RecoverJob")]
        public JsonResult RecoverJob(AdminApi request)
        {
            ResponseAdminApi response = new ResponseAdminApi();

            try
            {
                if (request.DriverId <= 0)
                {
                    response.HasError = true;
                    response.Message = "Invalid Driver Id";
                    return Json(response, JsonRequestBehavior.AllowGet);
                }

                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var objLogin = db.Fleet_DriverQueueLists.FirstOrDefault(c => c.Status == true && c.DriverId == request.DriverId);

                    if (objLogin == null || objLogin.CurrentJobId == null)
                    {
                        response.HasError = true;
                        response.Message = "No Current Job Found";
                        return Json(response, JsonRequestBehavior.AllowGet);
                    }

                    int statusId = objLogin.DriverWorkStatusId.ToInt();
                    long jobId = objLogin.CurrentJobId.ToLong();
                    string driverNo = objLogin.Fleet_Driver?.DriverNo ?? "";

                    if (statusId == Enums.Driver_WORKINGSTATUS.NOTAVAILABLE || statusId == Enums.Driver_WORKINGSTATUS.SOONTOCLEAR)
                    {
                        response.HasError = true;
                        response.Message = "Job cannot be recalled as driver is on POB or STC status.";
                        return Json(response, JsonRequestBehavior.AllowGet);
                    }

                    try
                    {

                        db.stp_UpdateJob(jobId, request.DriverId.Value, Enums.BOOKINGSTATUS.WAITING, Enums.Driver_WORKINGSTATUS.AVAILABLE, HubProcessor.Instance.objPolicy.SinBinTimer.ToInt());
                        //   }


                        try
                        {
                            string username = request.UserName.ToStr().Trim();

                            if (username.Length == 0)
                                username = "system";
                            //s
                            //  db.ExecuteQuery<int>("exec stp_BookingLog {0},{1},{2},{3} ", obj.bookingInfo.Id, obj.UserName.ToStr(), "Job is Recovered by Controller", DateTime.Now.GetUtcTimeZone());
                            db.stp_BookingLog(jobId, username, "Job is Recovered by Controller");
                        }
                        catch
                        {


                        }

                        General.CancelledJobFromController(request.DriverId.Value, jobId);



                        //// Perform the recall
                        //General.ReCallBooking(jobId, request.DriverId.Value);
                        //string message = $"auth>>{jobId}>>{request.DriverId}>>13>>1>>{driverNo}";



                        //General.BroadCastMessage("**broadcast close auth job>>" + Environment.MachineName + ">>" + message.ToStr().Replace(">>", "<<") + ">>allow");
                        //System.Threading.Thread.Sleep(500);

                        //General.requestPDA("request pda=" + request.DriverId + "=" + 0 + "=" + "Message>>Driver Priority - No Show>>" + String.Format("{0:dd/MM/yyyy HH:mm:ss}", DateTime.Now) + "=4");
                        //System.Threading.Thread.Sleep(500);

                        //string recallMessage = $"request pda={request.DriverId}={jobId}=<<Recall Job>>={((int)eMessageTypes.RECALLJOB)}";

                        //new System.Threading.Thread(() =>
                        //{
                        //    General.requestPDA(recallMessage);
                        //}).Start();


                        // Log the recall
                        //db.stp_BookingLog(jobId, request.UserName.ToStr(), "Recall Job from Driver (" + driverNo + ")");
                    }
                    catch (Exception ex)
                    {
                        response.HasError = true;
                        response.Message = "Recall failed: " + ex.Message;
                        return Json(response, JsonRequestBehavior.AllowGet);
                    }

                    response.HasError = false;
                    response.Message = "Job recalled successfully";
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = "Error: " + ex.Message;
            }

            return Json(response, JsonRequestBehavior.AllowGet);
        }


