        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SavePaymentGatewaySettings")]
        public JsonResult SavePaymentGatewaySettings(PaymentGatewaySetting gatewaySetting) // PaymentGatewayDetail gatewaySetting
        {
            ResponseAdminApi response = new ResponseAdminApi();
            SysPolicyBO objMaster = new SysPolicyBO();

            try
            {
                Gen_SysPolicy obj = General.GetQueryable<Gen_SysPolicy>(null).FirstOrDefault();
                if (obj != null)
                {
                    objMaster.GetByPrimaryKey(obj.Id);
                    objMaster.Edit();
                }

                string[] skipProperties = new string[] { "Gen_SysPolicy", "PaymentGateway" };
                List<Gen_SysPolicy_PaymentDetail> listGateways = new List<Gen_SysPolicy_PaymentDetail>();

                foreach (var paymentDetail in gatewaySetting.PaymentDetail)
                {
                    paymentDetail.SysPolicyId = obj.Id;

                    listGateways.Add(new Gen_SysPolicy_PaymentDetail
                    {

                        Id = paymentDetail.Id,
                        SysPolicyId = paymentDetail.SysPolicyId,
                        MerchantID = paymentDetail.MerchantID,
                        MerchantPassword = paymentDetail.MerchantPassword,
                        ApiUsername = paymentDetail.ApiUsername,
                        ApiPassword = paymentDetail.ApiPassword,
                        ApplicationId = paymentDetail.ApplicationId,
                        PaymentGatewayId = paymentDetail.PaymentGatewayId,
                        ApiCertificate = paymentDetail.ApiCertificate,
                        PaypalID = paymentDetail.PaypalID,
                        EnableMobileIntegration = paymentDetail.EnableMobileIntegration
                    });
                }

                IList<Gen_SysPolicy_PaymentDetail> savedListGateways = objMaster.Current.Gen_SysPolicy_PaymentDetails;
                Utils.General.SyncChildCollection(ref savedListGateways, ref listGateways, "Id", skipProperties);
                objMaster.Save();

                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var settings = db.Gen_PaymentColumnSettings.FirstOrDefault(c => c.Id > 0);
                    if (settings != null)
                    {
                        settings.ShowFares = gatewaySetting.PdaSetting.ShowFares;
                        settings.EditFares = gatewaySetting.PdaSetting.EditFares;
                        settings.ShowParking = gatewaySetting.PdaSetting.ShowParking;
                        settings.EditParking = gatewaySetting.PdaSetting.EditParking;
                        settings.ShowWaiting = gatewaySetting.PdaSetting.ShowWaiting;
                        settings.EditWaiting = gatewaySetting.PdaSetting.EditWaiting;
                        db.SubmitChanges();
                    }
                    else
                    {
                        settings = new Gen_PaymentColumnSetting
                        {
                            ShowFares = gatewaySetting.PdaSetting.ShowFares,
                            EditFares = gatewaySetting.PdaSetting.EditFares,
                            ShowParking = gatewaySetting.PdaSetting.ShowParking,
                            EditParking = gatewaySetting.PdaSetting.EditParking,
                            ShowWaiting = gatewaySetting.PdaSetting.ShowWaiting,
                            EditWaiting = gatewaySetting.PdaSetting.EditWaiting
                        };

                        db.Gen_PaymentColumnSettings.InsertOnSubmit(settings);
                        db.SubmitChanges();
                    }
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine(ex.Message);
            }

            return Json(response, JsonRequestBehavior.AllowGet);
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
