        public JsonResult GetPaymentGateways()
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var gateways = db.ExecuteQuery<PaymentGatewayList>("SELECT Id,Name FROM PaymentGateways Where Id In (6,7,9,15)").ToList();
                    var settings = db.Gen_PaymentColumnSettings.FirstOrDefault(c => c.Id > 0);
                    var gatewayDetails = db.ExecuteQuery<PaymentGatewayDetail>("select pg.[Name], pd.* from Gen_SysPolicy_PaymentDetails pd inner join PaymentGateways pg on pg.id = pd.PaymentGatewayId").ToList();
