            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("MakePayment")]
        public JsonResult MakePayment(WebApiClasses.RequestWebApi obj)
        {
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\MakePayment.txt", DateTime.Now + ",json:" + obj.SendType + Environment.NewLine);
            }
            catch
            {
            }
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                List<Gen_SysPolicy_PaymentDetail> objMerchantInfo = General.GetQueryable<Gen_SysPolicy_PaymentDetail>(c => c.PaymentGatewayId != 9).ToList();

                if (objMerchantInfo.Count == 0)
                {
                    response.Message = "Merchant Details is not defined in Settings.";
                    response.HasError = true;
                }
                else
                {
                    Booking_Payment objBookingPayment = new Booking_Payment();


                    if (new TaxiDataContext().Gen_SysPolicy_PaymentDetails.Where(c => (c.PaymentGatewayId == Enums.PAYMENT_GATEWAY.STRIPE && c.ApiCertificate != null && (c.ApiCertificate == "1" || c.ApiCertificate == "2"))).Count() > 0)
                    {
                        if (obj.SendType == 1)
                        {
                            if (obj.bookingInfo.CustomerMobileNo.ToStr().Trim().Length == 0)
                            {
                                response.HasError = true;
                                response.Message = "Required : Mobile No";
                            }
                        }

                        else if (obj.SendType == 2)
                        {
                            if (obj.bookingInfo.CustomerEmail.ToStr().Trim().Length == 0)
                            {
                                response.HasError = true;
                                response.Message = "Required : Email";
                            }
                        }

                    }
                    else if (new TaxiDataContext().Gen_SysPolicy_PaymentDetails.Where(c => (c.PaymentGatewayId == 15 && c.PaypalID != null)).Count() > 0)
                    {

                        if (obj.bookingInfo.CustomerMobileNo.ToStr().Trim().Length == 0)
                        {
                            response.HasError = true;
                            response.Message = "Required : Mobile No";
                        }
                    }
                }

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return new CustomJsonResult { Data = response };
        }
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetTotalFares")]
        public JsonResult GetTotalFares(int BookingId)
        {
            ResponseAdminApi response = new ResponseAdminApi();

            try
            {
                decimal total = 0.00m;
                using (TaxiDataContext db = new TaxiDataContext())
                {

                    var objBooking = db.Bookings.Where(x => x.Id == BookingId)
                         .Select(args => new { args.JourneyTypeId, args.PaymentTypeId, args.CompanyId, args.CompanyPrice, args.FareRate, args.CongtionCharges, args.ParkingCharges, args.MeetAndGreetCharges, args.WaitingCharges, args.ExtraDropCharges }).FirstOrDefault();


                    if (objBooking.CompanyId == null)
                    {
                        total = objBooking.FareRate.ToDecimal() + objBooking.CongtionCharges.ToDecimal() + objBooking.MeetAndGreetCharges.ToDecimal() + objBooking.ExtraDropCharges.ToDecimal();

                        if (objBooking.JourneyTypeId.ToInt() == 2)
                        {
                            objBooking = db.Bookings.Where(x => x.MasterJobId == BookingId)
                     .Select(args => new { args.JourneyTypeId, args.PaymentTypeId, args.CompanyId, args.CompanyPrice, args.FareRate, args.CongtionCharges, args.ParkingCharges, args.MeetAndGreetCharges, args.WaitingCharges, args.ExtraDropCharges }).FirstOrDefault();


                            if (objBooking != null)
                                total += objBooking.FareRate.ToDecimal() + objBooking.CongtionCharges.ToDecimal() + objBooking.MeetAndGreetCharges.ToDecimal() + objBooking.ExtraDropCharges.ToDecimal();

                        }
                    }
                    else
                    {
                        total = objBooking.CompanyPrice.ToDecimal() + objBooking.CongtionCharges.ToDecimal() + objBooking.MeetAndGreetCharges.ToDecimal() + objBooking.ExtraDropCharges.ToDecimal();
                        if (objBooking.JourneyTypeId.ToInt() == 2)
                        {
                            objBooking = db.Bookings.Where(x => x.MasterJobId == BookingId)
                     .Select(args => new { args.JourneyTypeId, args.PaymentTypeId, args.CompanyId, args.CompanyPrice, args.FareRate, args.CongtionCharges, args.ParkingCharges, args.MeetAndGreetCharges, args.WaitingCharges, args.ExtraDropCharges }).FirstOrDefault();


                            if (objBooking != null)
                                total += objBooking.CompanyPrice.ToDecimal() + objBooking.CongtionCharges.ToDecimal() + objBooking.MeetAndGreetCharges.ToDecimal() + objBooking.ExtraDropCharges.ToDecimal();

                        }

                    }

                    response.Data = total;

                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }

            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetBookingReceiptDeposit")]
        public JsonResult GetBookingReceiptDeposit(WebApiClasses.RequestWebApi obj)
        {

            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "GetBookingReceiptDeposit.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);

                }
                catch
                {

                }

                List<Vu_BookingDetail> cls = new List<Vu_BookingDetail>();
                Gen_SubCompany objSubCompany = new Gen_SubCompany();

                string bookingNo = obj.bookingInfo.BookingNo.ToStr().Trim();

                if (bookingNo.ToStr().Trim().Length > 0)
                {
                    using (TaxiDataContext db = new TaxiDataContext())
                    {
                        decimal SurchargeAmount = 0.00m;
                        string cardNumber = string.Empty;


                        var list = db.ExecuteQuery<Vu_BookingDetail>("select * from Vu_BookingDetailsDeposit where Id =" + obj.JobId).ToList();

                        //var list = db.Vu_BookingDetails.Where(c => c.Id == obj.JobId || c.MasterJobId == obj.JobId).ToList();

                        cls = list;

                        if (list != null && list[0].AuthCode.ToStr().Trim().Length > 0 &&
                           (list[0].PaymentTypeId.ToInt() == Enums.PAYMENT_TYPES.CREDIT_CARD || list[0].PaymentTypeId.ToInt() == Enums.PAYMENT_TYPES.BANK_ACCOUNT || list[0].PaymentTypeId.ToInt() == Enums.PAYMENT_TYPES.CREDIT_CARD_PAID))
                        {
                            Booking_Payment objPayment = General.GetObject<Booking_Payment>(c => c.BookingId == list[0].Id).DefaultIfEmpty();

                            if (objPayment != null)
                            {

                                SurchargeAmount = objPayment.SurchargeAmount.ToDecimal();
                                cls[0].SurchargeAmount = SurchargeAmount.ToStr();

                                if (objPayment.CardNumber.ToStr().Length >= 16)
                                    cardNumber = "**************" + objPayment.CardNumber.Substring(14).ToStr();

                                cls[0].CardNumber = cardNumber;

                            }

                        }

                        string criteria = obj.bookingInfo.ViaString;
                        if (list != null)
                        {
                            if (list[0].CompanyId.ToInt() == 0 && criteria == "Customer")
                            {
                                criteria = "Driver";
                            }

                            cls[0].NotesString = criteria;
                            db.DeferredLoadingEnabled = false;
                            objSubCompany = db.Gen_SubCompanies.FirstOrDefault(c => c.Id == list[0].SubCompanyId);
                            objSubCompany.CompanyLogo = null;
                        }



                        response.Data = new { bookingReceipt = cls, ObjSubCompany = objSubCompany }; //new { cls, objSubCompany };


                    }


                }
                else
                {
                    response.HasError = true;
                    response.Message = "Required : Booking Ref";

                }

            }
            catch (Exception ex)
            {
                try
                {
                    response.HasError = true;
                    response.Message = ex.Message;

                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "GetBookingReceiptDeposit_exception.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + ",exception:" + ex.Message + Environment.NewLine);
                }
                catch
                {

                }
            }

            return Json(response, JsonRequestBehavior.AllowGet);
            //return new CustomJsonResult { Data = response };

        }

