        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetDetailsForKonnectPayment")]
        public JsonResult GetDetailsForKonnectPayment(long BookingId)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    var Options = db.ExecuteQuery<string>("Select MerchantPassword from Gen_SysPolicy_PaymentDetails where PaymentGatewayId=15").FirstOrDefault();
                    bool IsAuthorize = false;
                    bool IsPayemntCaptured = false;
                    Taxi_Model.Booking objBooking = General.GetObject<Taxi_Model.Booking>(c => c.Id == BookingId);
                    if (objBooking.BookingPayment != null && objBooking.BookingPayment.AuthCode.ToStr().Length > 0)
                    {
                        response.Message = "Payment Already Captured against this booking!";
                        response.HasError = false;
                        IsPayemntCaptured = true;
                    }
                    else if (!string.IsNullOrEmpty(objBooking.CustomerCreditCardDetails) && objBooking.CustomerCreditCardDetails.ToStr().ToLower().StartsWith("pi") && !objBooking.CustomerCreditCardDetails.ToStr().ToLower().Contains("secret"))
                    {
                        response.Message = "Card is Authorize for this booking!";
                        response.HasError = false;
                        IsAuthorize = true;
                    }

                    response.Data = new
                    {
                        IsAuthorize = IsAuthorize,
                        IsPayemntCaptured = IsPayemntCaptured,
                        KonnectPayOptions = Options,
                    };
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
            }
            return Json(response, JsonRequestBehavior.AllowGet);
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("SendPaymentLinkKP")]
        public JsonResult SendPaymentLinkKP(SendPaymentLinkKP obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            string DefaultCurrency = System.Configuration.ConfigurationManager.AppSettings["DefaultCurrency"];
            string DefaultClientLocation = System.Configuration.ConfigurationManager.AppSettings["DefaultClientLocation"];
            string json = string.Empty;
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\SendPaymentLinkKP.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            try
            {


                PaymentConfig objMerchantInfo = null;
                Taxi_Model.Booking objBooking = General.GetObject<Taxi_Model.Booking>(c => c.Id == obj.bookingId);
                int SubcompanyId = 1;
                if (objBooking != null && objBooking?.SubcompanyId != null && objBooking?.SubcompanyId > 0) { SubcompanyId = Convert.ToInt32(objBooking.SubcompanyId); }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    objMerchantInfo = General.GetKoNectConfigDetails(SubcompanyId);

                }
                if (objMerchantInfo == null || (string.IsNullOrEmpty(objMerchantInfo.ApplicationId) || string.IsNullOrEmpty(objMerchantInfo.PaypalID)))
                {
                    response.Message = "Payment Gateway Configuration is not defined in Settings!";
                    response.HasError = true;
                }
                else
                {
                    //Taxi_Model.Booking objBooking = General.GetObject<Taxi_Model.Booking>(c => c.Id == obj.bookingId);
                    if (objBooking.BookingPayment != null && objBooking.BookingPayment.AuthCode.ToStr().Length > 0)
                    {
                        response.Message = "Payment Already Captured against this booking";
                        response.HasError = true;
                        response.Data = "";
                        return new CustomJsonResult { Data = response };

                    }
                    if (obj.IsIncremental)
                    {
                        if (obj.ExtraHold > 0)
                        {
                            obj.numTotalCharges = obj.numTotalCharges + ((obj.numTotalCharges * obj.ExtraHold) / 100);
                        }
                        else
                        {
                            obj.numTotalCharges = obj.numTotalCharges + ((obj.numTotalCharges * 20) / 100);
                        }

                    }


                    string CustomerStripeID = "";
                    DriverAppController.CustomerCardDetails CardDetails = null;
                    Customer Customerobj = null;
                    if (!string.IsNullOrEmpty(objBooking.CustomerMobileNo))
                    {
                        Customerobj = General.GetObject<Customer>(c => c.MobileNo == objBooking.CustomerMobileNo.ToStr().Trim());
                    }

                    if (Customerobj.CreditCardDetails.ToStr().ToLower().StartsWith("cus"))
                    {
                        CustomerStripeID = Customerobj?.CreditCardDetails?.ToStr();
                        CardDetails = GetCardDetailsKP(Customerobj.Id);
                    }

                    string baseUrl = System.Configuration.ConfigurationManager.AppSettings["huburl"].ToStr();
                    Classes.KonnectSupplier.StripePaymentRequestDto SpDTO = new Classes.KonnectSupplier.StripePaymentRequestDto();
                    SpDTO.isAuthorized = obj.IsAuthorize;
                    SpDTO.key = "";
                    SpDTO.secret = "";
                    SpDTO.countryId = objMerchantInfo.ApplicationId.ToInt();
                    SpDTO.connectedAccountId = objMerchantInfo.PaypalID.Trim();
                    SpDTO.applicationFee = 0;
                    SpDTO.otherCharges = 0;
                    SpDTO.bookingId = obj.bookingId;
                    SpDTO.bookingRef = obj.BookingNo ?? "";
                    SpDTO.amount = (obj.numTotalCharges * 100).ToInt();
                    SpDTO.displayAmount = obj.numTotalCharges.ToDecimal();
                    SpDTO.currency = DefaultCurrency;
                    SpDTO.description = obj?.subCompanyName + " | " + obj.BookingNo.ToStr() + " | " + "Fares : " + obj.numTotalCharges + " " + DefaultCurrency;
                    SpDTO.paymentMethodId = CardDetails?.CustomerCardToken ?? "";
                    SpDTO.customerId = CustomerStripeID ?? "";
                    SpDTO.customerName = objBooking?.CustomerName.ToStr();
                    SpDTO.email = obj?.CustomerEmail.ToStr().Trim();
                    SpDTO.phoneNumber = obj?.CustomerMobileNo.ToStr().Trim();

                    SpDTO.lastfour = CardDetails?.Lastfour ?? "";
                    SpDTO.expiry = CardDetails?.expiry ?? "";
                    SpDTO.cardtype = CardDetails?.cardType ?? "";
                    SpDTO.companyName = obj?.subCompanyName ?? "";
                    SpDTO.defaultClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr();
                    SpDTO.location = DefaultClientLocation;
                    SpDTO.verificationWebhook = "";
                    SpDTO.paymentUpdateWebhook = "";
                    SpDTO.ReturnAmount = obj?.ReturnFareRate ?? 0;
                    SpDTO.UpdatePaymentURL = baseUrl;
                    SpDTO.OperatorName = "";
                    SpDTO.PreAuthUrl = "";
                    SpDTO.PayByDispatch = "0";
                    if (!string.IsNullOrEmpty(objMerchantInfo.ApplicationId) && !string.IsNullOrEmpty(objMerchantInfo.PaypalID))
                    {
                        json = Newtonsoft.Json.JsonConvert.SerializeObject(SpDTO);
                        if (obj.IsAuthorize)
                        {
                            var result = new SupplierController().SendPreAuthLinkKP(json);
                            if (!string.IsNullOrEmpty(result) && !result.ToStr().Contains("false"))
                            {
                                response.Message = "Authorization Link Sent to Customer!";
                                response.HasError = false;
                                response.Data = "";

                            }
                            else
                            {
                                response.HasError = true;
                                response.Data = "";
                                response.Message = "Error in Sending Authorization Link!";
                            }
                        }
                        else
                        {
                            var result = new SupplierController().SendPayByLinkKP(json);
                            if (!string.IsNullOrEmpty(result) && !result.ToStr().Contains("false"))
                            {
                                response.Message = "Payment Link Sent to Customer!";
                                response.HasError = false;
                                response.Data = "";

                            }
                            else
                            {
                                response.HasError = true;
                                response.Data = "";
                                response.Message = "Error in Sending Payment Link!";
                            }
                        }


                    }
                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\SendPaymentLinkKP.txt", DateTime.Now.ToStr() + ": json" + new JavaScriptSerializer().Serialize(SpDTO) + "bookingno:" + objBooking.BookingNo.ToStr() + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                    }
                    catch
                    {

                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\SendPaymentLinkKP_Exception.txt", DateTime.Now.ToStr() + ": Exception" + ex.Message + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                }
                catch
                {

                }
            }
            return new CustomJsonResult { Data = response };
        }

