            string DefaultClientLocation = System.Configuration.ConfigurationManager.AppSettings["DefaultClientLocation"];
            string json = string.Empty;
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetPaymentLinkKP.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            try
            {
                PaymentConfig objMerchantInfo = null;
