                        response.Data = "";
                        return new CustomJsonResult { Data = response };

                    }

                    string CustomerStripeID = "";
                    DriverAppController.CustomerCardDetails CardDetails = new DriverAppController.CustomerCardDetails();

                    Customer Customerobj = null;
                    if (!string.IsNullOrEmpty(objBooking.CustomerMobileNo))
                    {
                        Customerobj = General.GetObject<Customer>(c => c.MobileNo == objBooking.CustomerMobileNo.ToStr().Trim());
                    }

                    if (Customerobj.CreditCardDetails.ToStr().ToLower().StartsWith("cus"))
                    {
                        CustomerStripeID = Customerobj?.CreditCardDetails?.ToStr();
                        CardDetails = GetCardDetailsKP(Customerobj.Id);
                    }


                    string baseUrl = System.Configuration.ConfigurationManager.AppSettings["huburl"].ToStr();
                    Classes.KonnectSupplier.StripePaymentRequestDto SpDTO = new Classes.KonnectSupplier.StripePaymentRequestDto();
                    SpDTO.isAuthorized = false;
                    SpDTO.key = "";
                    SpDTO.secret = "";
                    SpDTO.countryId = objMerchantInfo.ApplicationId.ToStr().ToInt();
                    SpDTO.connectedAccountId = objMerchantInfo?.PaypalID.Trim();
                    SpDTO.applicationFee = 0;
                    SpDTO.otherCharges = 0;
                    SpDTO.bookingId = objBooking?.Id ?? 0;
                    SpDTO.bookingRef = objBooking?.BookingNo ?? "";
                    SpDTO.amount = (obj.numTotalCharges * 100).ToInt();
                    SpDTO.displayAmount = obj.numTotalCharges.ToDecimal();
                    SpDTO.currency = DefaultCurrency;
                    SpDTO.description = objBooking?.Gen_SubCompany?.CompanyName + " | " + objBooking?.BookingNo.ToStr() + " | " + "Fares : " + obj.numTotalCharges.ToDecimal() + " " + DefaultCurrency;
                    SpDTO.paymentMethodId = CardDetails?.CustomerCardToken ?? "";
                    SpDTO.customerId = CustomerStripeID ?? "";
                    SpDTO.customerName = objBooking?.CustomerName?.ToStr().Trim();
                    SpDTO.email = objBooking?.CustomerEmail?.ToStr().Trim();
                    SpDTO.phoneNumber = objBooking?.CustomerMobileNo?.ToStr().Trim();

                    SpDTO.lastfour = CardDetails?.Lastfour ?? "";
                    SpDTO.expiry = CardDetails?.expiry ?? "";
                    SpDTO.cardtype = CardDetails?.cardType ?? "";
                    SpDTO.companyName = objBooking?.Gen_SubCompany?.CompanyName ?? "";
                    SpDTO.defaultClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr();
                    SpDTO.location = DefaultClientLocation;
                    SpDTO.verificationWebhook = baseUrl + "/api/Supplier/VerifyPaymentKOnnectPay";
                    SpDTO.paymentUpdateWebhook = baseUrl + "/api/Supplier/UpdateDataFromPayByLinkKOnnectPay";
                    SpDTO.ReturnAmount = objBooking.ReturnFareRate.HasValue ? objBooking.ReturnFareRate.Value : 0;
                    SpDTO.UpdatePaymentURL = baseUrl;
                    SpDTO.OperatorName = "";
                    SpDTO.PreAuthUrl = "";
                    SpDTO.PayByDispatch = "1";


                    if (!string.IsNullOrEmpty(objMerchantInfo?.ApplicationId) && !string.IsNullOrEmpty(objMerchantInfo?.PaypalID))
                    {
                        string data = new JavaScriptSerializer().Serialize(SpDTO);
                        string StripeAPIBaseURL = System.Configuration.ConfigurationManager.AppSettings["StripeAPIBaseURL"];
                        var PayLink = StripeAPIBaseURL + "/checkout?data=" + new SupplierController().EncodeBASE64(data);

                        if (PayLink.ToStr().Contains("tinyurl") == false)
                        {
                            PayLink = General.ToTinyURLS(PayLink.ToStr());
                        }

                        if (PayLink.ToStr().Length > 0)
                        {
                            response.Message = SpDTO.description;
                            response.HasError = false;
                            response.Data = PayLink;

                        }
                        else
                        {
                            response.HasError = true;
                            response.Data = "";
                            response.Message = "Error in Creating Payment Link!";
                        }

                    }
                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetPaymentLinkKP.txt", DateTime.Now.ToStr() + ": json" + new JavaScriptSerializer().Serialize(SpDTO) + "bookingno:" + objBooking.BookingNo.ToStr() + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                    }
                    catch
                    {

                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetPaymentLinkKP_Exception.txt", DateTime.Now.ToStr() + ": Exception" + ex.Message + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                }
                catch
                {

                }
            }
            return new CustomJsonResult { Data = response };
        }


