        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetCustomerCardsKP")]
        public JsonResult GetCustomerCardsKP(SendPaymentLinkKP obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            List<CCDetailsKP> CardList = new List<CCDetailsKP>();
            string json = string.Empty;
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetCustomerCardsKP.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            try
            {

                Customer Customerobj = null;
                int CustomerID = 0;
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    Customerobj = General.GetObject<Customer>(c => c.MobileNo == obj.CustomerMobileNo.ToStr() && c.CreditCardDetails != null && c.CreditCardDetails.StartsWith("cus_"));
                    CustomerID = Convert.ToInt32(Customerobj?.Id);

                }

                if (Customerobj == null || CustomerID == 0)
                {
                    response.Message = "NO Customer Details Found against this booking!";
                    response.HasError = true;
                    response.Data = "";
                    return new CustomJsonResult { Data = response };

                }
                List<ClsCCDetails> ccList = new List<ClsCCDetails>();
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    ccList = db.ExecuteQuery<ClsCCDetails>("select Id,CCDetails,IsDefault from Customer_CCDetails where customerId=" + CustomerID).ToList();

                }
                if (ccList.Count > 0)
                {

                    foreach (var itm in ccList)
                    {
                        string CardToken = string.Empty;

                        CCDetailsKP CardDetails = new CCDetailsKP();
                        if (!string.IsNullOrEmpty(itm.CCDetails) && itm.CCDetails.Contains("KonnectPayToken"))
                        {
                            var CardObj = itm.CCDetails.Split('|');
                            if (CardObj != null && CardObj.Length > 1)
                            {
                                CardDetails.Id = itm.Id;
                                var Token = CardObj[0].Split(':');
                                if (Token != null && Token.Length > 1)
                                {
                                    CardDetails.CardToken = Token[1].ToStr().Trim();
                                }

                                var CardDetailObj = CardObj[1].Split(',');
                                if (CardDetailObj != null && CardDetailObj.Length > 2)
                                {
                                    var CNumber = CardDetailObj[0].Split(':');
                                    if (CNumber.Length > 1)
                                    {
                                        CardDetails.cardNumber = CNumber[1];
                                    }

                                    var CExpiry = CardDetailObj[1].Split(':');
                                    //CExpiry = CExpiry[1].Split('/');
                                    if (CExpiry.Length > 1) { CardDetails.cardExpiry = CExpiry[1]; }

                                    var Ctype = CardDetailObj[2].Split(':');
                                    if (Ctype.Length > 0) { CardDetails.CardType = Ctype[1]; }

                                    CardList.Add(CardDetails);
                                }

                            }

                        }


                    }


                    response.Message = "Customer list";
                    response.HasError = false;
                    response.Data = CardList;

                }
                else
                {
                    response.Message = "No Card found!";
                    response.HasError = false;
                    response.Data = "";
                    return new CustomJsonResult { Data = response };


                }

                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetCustomerCardsKP.txt", DateTime.Now.ToStr() + ": response" + new JavaScriptSerializer().Serialize(response) + "CustomerID :" + Customerobj.CreditCardDetails.ToStr() + Environment.NewLine);
                }
                catch
                {

                }

            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\GetCustomerCardsKP_Exception.txt", DateTime.Now.ToStr() + ": Exception" + ex.Message + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                }
                catch
                {

                }
            }
            return new CustomJsonResult { Data = response };
        }




        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("ProcessPaymentWithCardKP")]
        public JsonResult ProcessPaymentWithCardKP(SendPaymentLinkKP obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            string DefaultCurrency = System.Configuration.ConfigurationManager.AppSettings["DefaultCurrency"];
            string DefaultCurrencySign = System.Configuration.ConfigurationManager.AppSettings["DefaultCurrencySign"];
            string DefaultClientLocation = System.Configuration.ConfigurationManager.AppSettings["DefaultClientLocation"];
            string json = string.Empty;
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessPaymentWithCardKP.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            try
            {

                PaymentConfig objMerchantInfo = null;
                Taxi_Model.Booking objBooking = General.GetObject<Taxi_Model.Booking>(c => c.Id == obj.bookingId);
                int SubcompanyId = 1;
                if (objBooking != null && objBooking?.SubcompanyId != null && objBooking?.SubcompanyId > 0) { SubcompanyId = Convert.ToInt32(objBooking.SubcompanyId); }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    objMerchantInfo = General.GetKoNectConfigDetails(SubcompanyId);

                }
                if (objMerchantInfo == null || (string.IsNullOrEmpty(objMerchantInfo.ApplicationId) || string.IsNullOrEmpty(objMerchantInfo.PaypalID)))
                {
                    response.Message = "Payment Gateway Configuration is not defined in Settings!";
                    response.HasError = true;
                }
                else
                {

                    if (objBooking.BookingPayment != null && objBooking.BookingPayment.AuthCode.ToStr().Length > 0)
                    {
                        response.Message = "Payment Already Captured against this booking";
                        response.HasError = true;
                        response.Data = "";
                        return new CustomJsonResult { Data = response };

                    }

                    string baseUrl = System.Configuration.ConfigurationManager.AppSettings["huburl"].ToStr();
                    Classes.KonnectSupplier.StripePaymentRequestDto SpDTO = new Classes.KonnectSupplier.StripePaymentRequestDto();
                    SpDTO.isAuthorized = false;
                    SpDTO.key = "";
                    SpDTO.secret = "";
                    SpDTO.countryId = objMerchantInfo.ApplicationId.ToInt();
                    SpDTO.connectedAccountId = objMerchantInfo.PaypalID.Trim();
                    SpDTO.applicationFee = 0;
                    SpDTO.otherCharges = 0;
                    SpDTO.bookingId = objBooking?.Id ?? 0;
                    SpDTO.bookingRef = objBooking?.BookingNo ?? "";
                    SpDTO.amount = (obj.numTotalCharges * 100).ToInt();
                    SpDTO.displayAmount = obj.numTotalCharges.ToDecimal();
                    SpDTO.currency = DefaultCurrency;
                    SpDTO.description = objBooking?.Gen_SubCompany?.CompanyName + " | " + objBooking?.BookingNo.ToStr() + " | " + "Fares : " + obj.numTotalCharges.ToDecimal() + " " + DefaultCurrency;
                    SpDTO.paymentMethodId = obj.CardToken;
                    SpDTO.customerId = objBooking?.Customer?.CreditCardDetails;
                    SpDTO.customerName = objBooking?.CustomerName?.ToStr().Trim();
                    SpDTO.email = objBooking?.CustomerEmail?.ToStr().Trim();
                    SpDTO.phoneNumber = objBooking?.CustomerPhoneNo?.ToStr().Trim();

                    SpDTO.lastfour = "";
                    SpDTO.expiry = "";
                    SpDTO.cardtype = "";
                    SpDTO.companyName = objBooking?.Gen_SubCompany?.CompanyName ?? "";
                    SpDTO.defaultClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr();
                    SpDTO.location = DefaultClientLocation;
                    SpDTO.ReturnAmount = objBooking.ReturnFareRate.HasValue ? objBooking.ReturnFareRate.Value : 0;
                    SpDTO.UpdatePaymentURL = baseUrl;
                    SpDTO.OperatorName = "";
                    SpDTO.PreAuthUrl = "";
                    SpDTO.PayByDispatch = "";


                    if (!string.IsNullOrEmpty(objMerchantInfo.ApplicationId) && !string.IsNullOrEmpty(objMerchantInfo.PaypalID))
                    {
                        var DataObj = Newtonsoft.Json.JsonConvert.SerializeObject(SpDTO);
                        string StripeAPIBaseURL = System.Configuration.ConfigurationManager.AppSettings["StripeAPIBaseURL"];

                        using (var client = new HttpClient())
                        {
                            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                            client.BaseAddress = new Uri(StripeAPIBaseURL);
                            client.DefaultRequestHeaders.Accept.Add(new System.Net.Http.Headers.MediaTypeWithQualityHeaderValue("application/json"));
                            var content = new StringContent(DataObj, Encoding.UTF8, "application/json");
                            var postTask = client.PostAsync(StripeAPIBaseURL + "/v1/PaymentWithExistingCustomer", content).Result;
                            string PayResp = postTask.Content.ReadAsStringAsync().Result;
                            PaymentWithExistingCustomerResponse PaymentResp = new JavaScriptSerializer().Deserialize<PaymentWithExistingCustomerResponse>(PayResp);

                            if (PaymentResp != null)
                            {

                                using (TaxiDataContext db = new TaxiDataContext())
                                {

                                    if (PaymentResp.status.ToStr().ToLower() == "succeeded" || PaymentResp.isSuccess)
                                    {
                                        //  rtn = "true |" + obj.paymentIntentId;
                                        response.Message = "Payment Captured!";
                                        response.Data = PaymentResp.paymentIntentId;

                                        string msg = "PAID " + DefaultCurrencySign + string.Format("{0:f2}", PaymentResp.amount) + " | TRANSACTION - " + PaymentResp.paymentIntentId.ToStr() + " | " + string.Format("{0:dd/MM/yyyy HH:mm}", DateTime.Now);

                                        db.ExecuteQuery<int>("update booking set Paymenttypeid=6,PaymentComments='" + msg + "' where id=" + obj.bookingId.ToLong());

                                        db.stp_BookingLog(obj.bookingId.ToLong(), "Customer", msg);

                                        if ((db.ExecuteQuery<int>("select count(*) from booking_payment where bookingId=" + obj.bookingId.ToLong()).FirstOrDefault()) == 0)
                                        {
                                            db.ExecuteQuery<int>("insert into Booking_Payment(bookingid,PaymentGatewayId,AuthCode)VALUES(" + obj.bookingId.ToLong() + ",15,'" + PaymentResp.paymentIntentId.ToStr() + "')");
                                        }
                                        try
                                        {
                                            long jobId = obj.bookingId.ToLong();
                                            using (TaxiDataContext db2 = new TaxiDataContext())
                                            {
                                                General.UpdateJobToDriverPDA(db2.Bookings.FirstOrDefault(c => c.Id == jobId), "Credit Card(PAID)");
                                            }

                                        }
                                        catch
                                        {
                                        }
                                        try
                                        {
                                            long returnBookingId = db.ExecuteQuery<long>("select Id from booking where masterjobid=" + obj.bookingId).FirstOrDefault();
                                            if (returnBookingId > 0)
                                            {
                                                db.ExecuteQuery<int>("update booking set Paymenttypeid=6,PaymentComments='" + "TRANSACTION - " + PaymentResp.paymentIntentId.ToStr() + " | " + string.Format("{0:dd/MM/yyyy HH:mm}", DateTime.Now) + "' where Id=" + returnBookingId);
                                                db.ExecuteQuery<int>("insert into Booking_Payment(bookingid,PaymentGatewayId,AuthCode)VALUES(" + returnBookingId + ",15,'" + PaymentResp.paymentIntentId.ToStr() + "')");
                                                using (TaxiDataContext db2 = new TaxiDataContext())
                                                {
                                                    General.UpdateJobToDriverPDA(db2.Bookings.FirstOrDefault(c => c.Id == returnBookingId), "Credit Card(PAID)");
                                                }
                                            }

                                        }
                                        catch (Exception ex)
                                        {
                                            try
                                            {
                                                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\UpdateDataFromPayByLinkKOnnectPay_exception1.txt", DateTime.Now.ToStr() + " json" + json + ",exception:" + ex.Message + Environment.NewLine);
                                            }
                                            catch
                                            {
                                            }
                                        }



                                    }
                                    else
                                    {
                                        response.Message = "Error in payment process!";
