                                }
                                catch
                                {
                                }
                                RefreshRequiredDashboard(obj.bookingId.ToStr());
                            }

                        }

                    }
                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessPaymentWithCardKP.txt", DateTime.Now.ToStr() + ": json" + new JavaScriptSerializer().Serialize(SpDTO) + "bookingno:" + objBooking.BookingNo.ToStr() + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
