        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("RefundPaymentKP")]
        public JsonResult RefundPaymentKP(SendPaymentLinkKP obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            string DefaultCurrency = System.Configuration.ConfigurationManager.AppSettings["DefaultCurrency"];
            string DefaultClientLocation = System.Configuration.ConfigurationManager.AppSettings["DefaultClientLocation"];
            string json = string.Empty;
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\RefundPaymentKP.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            try
            {


                PaymentConfig objMerchantInfo = null;
                Taxi_Model.Booking objBooking = General.GetObject<Taxi_Model.Booking>(c => c.Id == obj.bookingId);
                int SubcompanyId = 1;
                if (objBooking != null && objBooking?.SubcompanyId != null && objBooking?.SubcompanyId > 0) { SubcompanyId = Convert.ToInt32(objBooking.SubcompanyId); }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    objMerchantInfo = General.GetKoNectConfigDetails(SubcompanyId);

                }
                if (objMerchantInfo == null || (string.IsNullOrEmpty(objMerchantInfo.ApplicationId) || string.IsNullOrEmpty(objMerchantInfo.PaypalID)))
                {
                    response.Message = "Payment Gateway Configuration is not defined in Settings!";
                    response.HasError = true;
                    return new CustomJsonResult { Data = response };
                }
                else
                {

                    Booking_Log RefundLog = null;
                    if (objBooking.Booking_Logs != null)
                    {
                        RefundLog = objBooking.Booking_Logs.Where(c => c.AfterUpdate.ToLower().Contains("refund") && c.AfterUpdate.ToLower().Contains("payment")).FirstOrDefault();
                        if (RefundLog != null)
                        {
                            response.Message = "Payment already refunded for this booking!";
                            response.HasError = true;
                            return new CustomJsonResult { Data = response };
                        }
                    }



                    if (obj.RefundAmount > 0 && obj.RefundAmount > objBooking?.TotalCharges)
                    {
                        response.Message = "Refund amount must be less than charged amount!";
                        response.HasError = true;
                        return new CustomJsonResult { Data = response };

                    }
                    else if (obj.RefundAmount > 0 && obj.RefundAmount <= objBooking?.TotalCharges)
                    {
                        objBooking.TotalCharges = obj.RefundAmount;
                    }


                    string baseUrl = System.Configuration.ConfigurationManager.AppSettings["huburl"].ToStr();
                    RefundPaymentDto SpDTO = new RefundPaymentDto();

                    SpDTO.countryId = objMerchantInfo.ApplicationId.ToInt();
                    SpDTO.connectedAccountId = objMerchantInfo.PaypalID.Trim();
                    SpDTO.bookingId = objBooking?.Id ?? 0;
                    SpDTO.bookingRef = objBooking?.BookingNo ?? "";
                    SpDTO.amount = (objBooking?.TotalCharges * 100).ToInt();
                    SpDTO.displayAmount = objBooking.TotalCharges.ToDecimal();
                    SpDTO.currency = DefaultCurrency;
                    SpDTO.description = "Refund Payment " + objBooking?.Gen_SubCompany?.CompanyName + " | " + objBooking?.BookingNo.ToStr() + " | " + "Fares : " + objBooking?.TotalCharges.ToDecimal() + " " + DefaultCurrency;
                    SpDTO.companyName = objBooking?.Gen_SubCompany?.CompanyName ?? "";
                    SpDTO.defaultClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr();
                    SpDTO.location = DefaultClientLocation;





                    if (!string.IsNullOrEmpty(objMerchantInfo.ApplicationId) && !string.IsNullOrEmpty(objMerchantInfo.PaypalID))
                    {

                        //RefundPaymentKonnectPay
                        string sendResponse = new SupplierController().RefundPaymentKonnectPay(new JavaScriptSerializer().Serialize(SpDTO));
                        response.Message = sendResponse;
                        if (!string.IsNullOrEmpty(sendResponse) && sendResponse.ToLower().Contains("success"))
                        {
                            response.HasError = false;
                        }
                        else { response.HasError = true; }
                    }
                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\RefundPaymentKP.txt", DateTime.Now.ToStr() + ": json" + new JavaScriptSerializer().Serialize(SpDTO) + "bookingno:" + objBooking.BookingNo.ToStr() + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                    }
                    catch
                    {

                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\RefundPaymentKP_Exception.txt", DateTime.Now.ToStr() + ": Exception" + ex.Message + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                }
                catch
                {

                }
            }
            return new CustomJsonResult { Data = response };
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("ProcessAuthorizePaymentKP")]
        public JsonResult ProcessAuthorizePaymentKP(SendPaymentLinkKP obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            string DefaultCurrency = System.Configuration.ConfigurationManager.AppSettings["DefaultCurrency"];
            string DefaultCurrencySign = System.Configuration.ConfigurationManager.AppSettings["DefaultCurrencySign"];
            string DefaultClientLocation = System.Configuration.ConfigurationManager.AppSettings["DefaultClientLocation"];
            string json = string.Empty;
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessAuthorizePaymentKP.txt", DateTime.Now + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }
            try
            {
                PaymentConfig objMerchantInfo = null;
                Taxi_Model.Booking objBooking = General.GetObject<Taxi_Model.Booking>(c => c.Id == obj.bookingId);
                int SubcompanyId = 1;
                if (objBooking != null && objBooking?.SubcompanyId != null && objBooking?.SubcompanyId > 0) { SubcompanyId = Convert.ToInt32(objBooking.SubcompanyId); }
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    objMerchantInfo = General.GetKoNectConfigDetails(SubcompanyId);

                }

                if (objMerchantInfo == null || (string.IsNullOrEmpty(objMerchantInfo.ApplicationId) || string.IsNullOrEmpty(objMerchantInfo.PaypalID)))
                {
                    response.Message = "Payment Gateway Configuration is not defined in Settings!";
                    response.HasError = true;
                }
                else
                {

                    if (objBooking.BookingPayment != null && objBooking.BookingPayment.AuthCode.ToStr().Length > 0)
                    {
                        response.Message = "Payment Already Captured against this booking";
                        response.HasError = true;
                        response.Data = "";
                        return new CustomJsonResult { Data = response };

                    }
                    else if (string.IsNullOrEmpty(objBooking.CustomerCreditCardDetails) || (objBooking.CustomerCreditCardDetails.ToStr().ToLower().StartsWith("pi") && objBooking.CustomerCreditCardDetails.ToStr().ToLower().Contains("secret")))
                    {
                        response.Message = "Payment Intent is not valid for this booking";
                        response.HasError = true;
                        response.Data = "";
                        return new CustomJsonResult { Data = response };

                    }

                    try
                    {
                        Booking_Log BookLog = null;

                        if (objBooking.Booking_Logs != null)
                        {
                            BookLog = objBooking.Booking_Logs.Where(c => c.AfterUpdate.ToLower().Contains("hold amount")).FirstOrDefault();
                            if (BookLog != null && !string.IsNullOrEmpty(BookLog.AfterUpdate))
                            {
                                var HoldObj = BookLog.AfterUpdate.Split('|');
                                decimal HoldAmount = Convert.ToDecimal(HoldObj[1]);
                                if (HoldAmount < obj.numTotalCharges)
                                {

                                    string msg = "Capture Amount is greater than Hold Amount!";
                                    try
                                    {
                                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessAuthorizePaymentKP.txt", DateTime.Now.ToStr() + ": request" + objBooking.Id.ToStr() + ",token:" + objBooking?.CustomerCreditCardDetails.ToStr() + " | " + msg + ",Request DTO:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                                    }
                                    catch { }
                                    obj.numTotalCharges = HoldAmount;
                                }

                            }
                        }
                    }
                    catch
                    {

                    }
                    string baseUrl = System.Configuration.ConfigurationManager.AppSettings["huburl"].ToStr();
                    PaymentCaptureDto SpDTO = new PaymentCaptureDto();
                    SpDTO.bookingId = objBooking?.Id ?? 0;
                    SpDTO.description = objBooking?.Gen_SubCompany?.CompanyName + " | " + objBooking?.BookingNo.ToStr() + " | " + "Fares : " + obj.numTotalCharges.ToDecimal() + " " + DefaultCurrency;
                    SpDTO.bookingRef = objBooking?.BookingNo ?? "";
                    SpDTO.countryId = objMerchantInfo.ApplicationId.ToInt();
                    SpDTO.connectedAccountId = objMerchantInfo.PaypalID.Trim();
                    SpDTO.applicationFee = 0;
                    SpDTO.otherCharges = 0;
                    SpDTO.key = "";
                    SpDTO.secret = "";
                    SpDTO.amount = (obj.numTotalCharges * 100).ToInt();
                    SpDTO.displayAmount = obj.numTotalCharges.ToDecimal();
                    SpDTO.currency = DefaultCurrency;
                    SpDTO.defaultClientId = HubProcessor.Instance.objPolicy.DefaultClientId.ToStr();
                    SpDTO.location = DefaultClientLocation;
                    SpDTO.companyName = objBooking?.Gen_SubCompany?.CompanyName ?? "";
                    SpDTO.paymentIntentId = objBooking?.CustomerCreditCardDetails.ToStr();
                    SpDTO.status = objBooking?.CompanyCreditCardDetails.ToStr();

                    if (!string.IsNullOrEmpty(objMerchantInfo.ApplicationId) && !string.IsNullOrEmpty(objMerchantInfo.PaypalID))
                    {
                        var DataObj = Newtonsoft.Json.JsonConvert.SerializeObject(SpDTO);
                        string StripeAPIBaseURL = System.Configuration.ConfigurationManager.AppSettings["StripeAPIBaseURL"];

                        using (var client = new HttpClient())
                        {
                            ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                            client.BaseAddress = new Uri(StripeAPIBaseURL);
                            client.DefaultRequestHeaders.Accept.Add(new System.Net.Http.Headers.MediaTypeWithQualityHeaderValue("application/json"));
                            var content = new StringContent(DataObj, Encoding.UTF8, "application/json");
                            var postTask = client.PostAsync(StripeAPIBaseURL + "/v1/CapturePayment/IncrementAuthorization", content).Result;
                            string PayResp = postTask.Content.ReadAsStringAsync().Result;
                            PaymentCaptureResponse PaymentResp = new JavaScriptSerializer().Deserialize<PaymentCaptureResponse>(PayResp);

                            if (PaymentResp != null)
                            {

                                using (TaxiDataContext db = new TaxiDataContext())
                                {

                                    if (PaymentResp.status.ToStr().ToLower() == "succeeded" || PaymentResp.isSuccess)
                                    {
                                        response.Message = "Payment Captured!";
                                        response.Data = PaymentResp.paymentId;

                                        string msg = "PAID " + DefaultCurrencySign + string.Format("{0:f2}", obj.numTotalCharges) + " | TRANSACTION - " + PaymentResp.paymentId.ToStr() + " | " + string.Format("{0:dd/MM/yyyy HH:mm}", DateTime.Now);

                                        db.ExecuteQuery<int>("update booking set Paymenttypeid=6,PaymentComments='" + msg + "' where id=" + obj.bookingId.ToLong());

                                        db.stp_BookingLog(obj.bookingId.ToLong(), "Customer", msg);

                                        if ((db.ExecuteQuery<int>("select count(*) from booking_payment where bookingId=" + obj.bookingId.ToLong()).FirstOrDefault()) == 0)
                                        {
                                            db.ExecuteQuery<int>("insert into Booking_Payment(bookingid,PaymentGatewayId,AuthCode,Status,TotalAmount)VALUES(" + obj.bookingId.ToLong() + ",15,'" + PaymentResp.paymentId.ToStr() + "','Paid'," + obj.numTotalCharges + ")");
                                        }
                                        try
                                        {
                                            long jobId = obj.bookingId.ToLong();
                                            using (TaxiDataContext db2 = new TaxiDataContext())
                                            {
                                                General.UpdateJobToDriverPDA(db2.Bookings.FirstOrDefault(c => c.Id == jobId), "Credit Card(PAID)");
                                            }

                                        }
                                        catch
                                        {
                                        }
                                        try
                                        {
                                            long returnBookingId = db.ExecuteQuery<long>("select Id from booking where masterjobid=" + obj.bookingId).FirstOrDefault();
                                            if (returnBookingId > 0)
                                            {
                                                db.ExecuteQuery<int>("update booking set Paymenttypeid=6,PaymentComments='" + "TRANSACTION - " + PaymentResp.paymentId.ToStr() + " | " + string.Format("{0:dd/MM/yyyy HH:mm}", DateTime.Now) + "' where Id=" + returnBookingId);
                                                db.ExecuteQuery<int>("insert into Booking_Payment(bookingid,PaymentGatewayId,AuthCode)VALUES(" + returnBookingId + ",15,'" + PaymentResp.paymentId.ToStr() + "')");
                                                using (TaxiDataContext db2 = new TaxiDataContext())
                                                {
                                                    General.UpdateJobToDriverPDA(db2.Bookings.FirstOrDefault(c => c.Id == returnBookingId), "Credit Card(PAID)");
                                                }
                                            }

                                        }
                                        catch (Exception ex)
                                        {
                                            try
                                            {
                                                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessAuthorizePaymentKP_exception.txt", DateTime.Now.ToStr() + " json" + json + ",exception:" + ex.Message + Environment.NewLine);
                                            }
                                            catch
                                            {
                                            }
                                        }



                                    }
                                    else
                                    {
                                        response.Message = "Error in payment process!";
                                        db.ExecuteQuery<int>("update booking set PaymentComments='PAYMENT FAILED : " + PaymentResp.status.ToStr() + "'  where id=" + obj.bookingId.ToLong());
                                        db.stp_BookingLog(obj.bookingId.ToLong(), "Customer", "PAYMENT FAILED - " + PaymentResp.error.ToStr());
                                        if (!string.IsNullOrEmpty(PaymentResp.error)) { response.Message = PaymentResp.error; }
                                    }

                                }


                                try
                                {
                                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessAuthorizePaymentKP.txt", DateTime.Now.ToStr() + " payment response " + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                                }
                                catch
                                {
                                }
                                RefreshRequiredDashboard(obj.bookingId.ToStr());
                            }

                        }

                    }
                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessAuthorizePaymentKP.txt", DateTime.Now.ToStr() + ": json" + new JavaScriptSerializer().Serialize(SpDTO) + "bookingno:" + objBooking.BookingNo.ToStr() + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                    }
                    catch
                    {

                    }
                }
            }
            catch (Exception ex)
            {
                response.HasError = true;
                response.Message = ex.Message;
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\ProcessAuthorizePaymentKP_exception.txt", DateTime.Now.ToStr() + ": Exception" + ex.Message + ",response:" + new JavaScriptSerializer().Serialize(response) + Environment.NewLine);
                }
                catch
                {

                }
            }
            return new CustomJsonResult { Data = response };
        }



        private DriverAppController.CustomerCardDetails GetCardDetailsKP(int? CustomerId)
        {
            DriverAppController.CustomerCardDetails CCDetail = new DriverAppController.CustomerCardDetails();
            try
            {
                ClsCCDetails CardDetails = new ClsCCDetails();
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    CardDetails = db.ExecuteQuery<ClsCCDetails>("select RecordId=Id,CCDetails,IsDefault from  Customer_CCDetails where customerId=" + CustomerId.ToInt()).LastOrDefault();

                }

                if (CardDetails != null && !string.IsNullOrEmpty(CardDetails.CCDetails) && CardDetails.CCDetails.ToLower().Contains("konnectpaytoken"))
                {
                    var CCDetails = CardDetails.CCDetails.Split('|');
                    string Token = CCDetails[0];
                    if (!string.IsNullOrEmpty(Token)) { CCDetail.CustomerCardToken = Token.Replace("KonnectPayToken:", "").Trim(); }
                    if (!string.IsNullOrEmpty(CCDetails[1]))
                    {
                        var CardInfo = CCDetails[1].Split(',');
                        if (CardInfo != null)
                        {
                            if (CardInfo[0] != null && CardInfo[0].ToLower().Contains("last four"))
                            {
                                CCDetail.Lastfour = CardInfo[0].Replace("last four", "");
                                CCDetail.Lastfour = CCDetail.Lastfour.Replace(":", "").Trim();
                            }
                            if (CardInfo[1] != null && CardInfo[1].ToLower().Contains("expiry"))
                            {
                                CCDetail.expiry = CardInfo[1].Replace("expiry", "");
                                CCDetail.expiry = CCDetail.expiry.Replace(":", "").Trim();


                            }
                            if (CardInfo[2] != null && CardInfo[2].ToLower().Contains("cardtype"))
                            {
                                CCDetail.cardType = CardInfo[2].Replace("cardType", "");
                                CCDetail.cardType = CCDetail.cardType.Replace(":", "").Trim();
                            }


                        }
                    }
                }

            }
            catch
            {

            }

            return CCDetail;
        }
