        DriverCommisionBO objMaster_DC = null;
        private bool OnSave(int DriverId, decimal oldBalance, decimal DriverCommissionPerBooking, decimal pdaCommission
         , decimal InitialBalance, decimal CommissionPayValue, ref decimal accJobs, ref long transId
         , ref decimal rentDue, ref decimal currBalance, bool IsHoliday, ref decimal MaxCommission, ref decimal minCommission, decimal VAT
         , List<long?> bookingIds, List<stp_getDriverListForGeneratingCommResult2> driverCommissionList, DateTime? fromDate, DateTime? tillDate)
        {

            bool IsSaved = false;


            try
            {

                long savedTransId = transId;

                objMaster_DC = new DriverCommisionBO();

                if (transId == 0)
                {

                    objMaster_DC.New();

                }
                else
                {
                    objMaster_DC.GetByPrimaryKey(transId);

                    if (objMaster_DC.Current == null)
                        objMaster_DC.New();
                    //
                }


                List<Fleet_DriverCommision_Charge> ListDetail = null;
                var list2 = (from a in driverCommissionList
                             join b in bookingIds on a.Id equals b into table2
                             from b in table2.DefaultIfEmpty()

                             where (b == null) && a.Driverid == DriverId
                             select new
                             {
                                 a.Id,
                                 a.TotalFare,
                                 a.CompanyId,
                                 a.AccountTypeId,

                                 a.DriverCommissionAmount,
                                 a.DriverCommissionType,
                                 a.IsCommissionWise,
                                 a.AgentCommission,
                                 a.DropOffCharge,
                                 a.PickupCharge,
                                 a.Parking,
                                 a.BookingFee,
                                 a.ExtraDropCharges,
                                 a.PickupPlot,
                                 a.DropOffPlot,
                                 a.PaymentTypeId,
                                 a.Waiting,
                                 a.FareRate,
                                 a.Promotion,

                             }).ToList();



                //if (chkOperatedDrivers.Checked)
                //{
                //    if (list2.Count == 0)
                //    {

                //        IsSaved = false;
                //        transId = 0;
                //        return IsSaved;
                //    }

                //}

                ListDetail = (from a in list2
                              select new Fleet_DriverCommision_Charge
                              {
                                  //Id = a.Id,
                                  TransId = objMaster_DC.Current.Id,
                                  BookingId = a.Id,
                                  CommissionPerBooking = (a.TotalFare * DriverCommissionPerBooking) / 100
                                  //CommissionPerBooking=a.DriverCommissionAmount
                              }).ToList();

                string[] skipProperties = { "Fleet_DriverCommision", "Booking" };
                IList<Fleet_DriverCommision_Charge> savedList = objMaster_DC.Current.Fleet_DriverCommision_Charges;

                Utils.General.SyncChildCollection(ref savedList, ref ListDetail, "Id", skipProperties);


                decimal Total = list2.Sum(c => c.TotalFare).ToDecimal();
                decimal ACCJobsTotal = list2.Where(c => c.AccountTypeId != Enums.ACCOUNT_TYPE.CASH)
                                       .Sum(c => c.TotalFare).ToDecimal();


                decimal parkingTotal = list2.Where(c => c.AccountTypeId != Enums.ACCOUNT_TYPE.CASH)
                                                             .Sum(c => c.Parking.ToDecimal());

                ////if (AppVars.listUserRights.Count(c => c.functionId == "DEBIT CONGESTION") > 0)
                ////{
                parkingTotal = list2.Where(c => c.AccountTypeId != Enums.ACCOUNT_TYPE.CASH
                      && (
                       c.PickupPlot.ToStr().ToUpper().Contains("CONGESTION") == false
                                        && c.DropOffPlot.ToStr().ToUpper().ToStr().Contains("CONGESTION") == false

                         )

                                                      ).Sum(c => c.Parking.ToDecimal());

                //}


                decimal promotionTotal = list2.Where(c => c.Promotion != null && c.Promotion > 0)
                                                          .Sum(c => c.Promotion.ToDecimal());


                decimal subtractPromotionTotal = -(list2.Where(c => c.Promotion != null && c.Promotion < 0)
                                                        .Sum(c => c.Promotion.ToDecimal()));

                double totalWeeks = (tillDate.Value.ToDate().Subtract(fromDate.Value.ToDate()).TotalDays) / 7;

                if (totalWeeks < 1)
                    totalWeeks = 1;




                decimal TotalPDARent = (pdaCommission * totalWeeks.ToInt());

                decimal AgentCommission = list2.Where(c => c.AccountTypeId == Enums.ACCOUNT_TYPE.CASH).Sum(c => c.AgentCommission).ToDecimal();

                // bookingfee
                ////if (AppVars.objPolicyConfiguration.PickCommissionDeductionFromJobsTotal.ToBool())
                ////{

                AgentCommission = AgentCommission + list2.Where(c => c.AccountTypeId == Enums.ACCOUNT_TYPE.CASH).Sum(c => c.BookingFee).ToDecimal();
                //   }
                //
                // Total = Total;


                decimal DriverCommissionTotal = 0;

                decimal accountsBookingFeeTotal = list2.Where(c => c.AccountTypeId != Enums.ACCOUNT_TYPE.CASH).Sum(c => c.BookingFee).ToDecimal();




                ////if (AppVars.objPolicyConfiguration.NoCommissionFromAccount.ToBool())
                ////{

                decimal CashTotal = list2.Where(c => c.PaymentTypeId != Enums.PAYMENT_TYPES.BANK_ACCOUNT).Sum(c => c.TotalFare).ToDecimal();
                decimal AccTotal = 0;
                DriverCommissionTotal = ((CashTotal + AccTotal) * DriverCommissionPerBooking / 100);


                ////}
                ////else
                ////{
                DriverCommissionTotal = ((Total - subtractPromotionTotal) * DriverCommissionPerBooking / 100);

                //    //if (AppVars.objPolicyConfiguration.DrvCommissionCalculationType.ToInt() == 13) // fare+extradrop
                //    //{
                //    //    Total = list2.Sum(c => c.FareRate.ToDecimal() + c.ExtraDropCharges.ToDecimal()).ToDecimal();
                //    //    DriverCommissionTotal = ((Total - subtractPromotionTotal) * DriverCommissionPerBooking / 100);

                //    //}
                //    //else if (AppVars.objPolicyConfiguration.DrvCommissionCalculationType.ToInt() == 14) // fare+waiting
                //    //{
                //    //    Total = list2.Sum(c => c.FareRate.ToDecimal() + c.Waiting.ToDecimal()).ToDecimal();
                //    //    DriverCommissionTotal = ((Total - subtractPromotionTotal) * DriverCommissionPerBooking / 100);

                //    //}


                ////}
                ////    }

                // MaxCommission

                if (MaxCommission > 0 && DriverCommissionTotal > MaxCommission)
                {
                    DriverCommissionTotal = MaxCommission;
                }



                if (minCommission > 0 && DriverCommissionTotal < minCommission && list2.Count > 0)
                {
                    DriverCommissionTotal = minCommission;
                }

                if (VAT.ToDecimal() > 0)
                {
                    DriverCommissionTotal = DriverCommissionTotal + Math.Round(((DriverCommissionTotal * VAT.ToDecimal()) / 100), 2);

                }

                //





                objMaster_DC.Current.CollectionDeliveryCharges = promotionTotal;

                objMaster_DC.Current.MaxCommission = MaxCommission;

                objMaster_DC.Current.Adjustments = 0.00m;




                decimal owed = 0.00m;
                decimal AccountExpenses = 0.00m;

                decimal totalCredit = 0.00m;
                decimal totalDebit = 0.00m;



                decimal Debit = 0.00m;
                decimal Credit = 0.00m;

                if (savedTransId > 0 && objMaster_DC.Current.Fleet_DriverCommissionExpenses.Count > 0)
                {
                    Debit = objMaster_DC.Current.Fleet_DriverCommissionExpenses.Where(c => c.Debit.ToDecimal() > 0).Select(c => c.Debit).Sum().ToDecimal();
                    Credit = objMaster_DC.Current.Fleet_DriverCommissionExpenses.Where(c => c.Credit.ToDecimal() > 0).Select(c => c.Credit).Sum().ToDecimal();
                }
                else

                {

                    ////if (AppVars.listUserRights.Count(c => c.functionId == "DEBIT CONGESTION") > 0)
                    ////{
                    decimal congestion = list2
                        //.Where(c => c.AccountTypeId == Enums.ACCOUNT_TYPE.CASH)
                        .Where(c => c.PickupPlot.ToStr().ToUpper().Contains("CONGESTION")
                                        || c.DropOffPlot.ToStr().ToUpper().ToStr().Contains("CONGESTION"))
                                                         .Sum(c => c.Parking.ToDecimal());
                    if (congestion > 0)
                    {
                        objMaster_DC.Current.Fleet_DriverCommissionExpenses.Add(new Fleet_DriverCommissionExpense
                        {
                            Description = "CONGESTION",
                            Debit = congestion,

                        });
                        Debit = congestion;
                    }

                    ////}

                }
                //

                totalDebit = (DriverCommissionTotal + TotalPDARent + AgentCommission + Debit);
                totalCredit = (ACCJobsTotal + parkingTotal + AccountExpenses + objMaster_DC.Current.Adjustments.ToDecimal() + promotionTotal + Credit);
                owed = (totalDebit - totalCredit);
                objMaster_DC.Current.DriverOwed = owed;

                totalDebit += oldBalance;
                //totalCredit = (DriverCommissionTotal  + AccountExpenses + Credit);
                //totalDebit = (ACCJobsTotal + Debit);

                objMaster_DC.Current.Balance = (totalDebit - totalCredit);

                objMaster_DC.Current.AccountExpenses = AccountExpenses;
                objMaster_DC.Current.OldAgentCommission = accountsBookingFeeTotal;

                objMaster_DC.Current.AccJobsTotal = ACCJobsTotal;

                objMaster_DC.Current.CommissionTotal = DriverCommissionTotal;
                objMaster_DC.Current.JobsTotal = Total;
                objMaster_DC.Current.AgentFeesTotal = AgentCommission;

                objMaster_DC.Current.CommisionPay = CommissionPayValue.ToDecimal();
                ////objMaster_DC.Current.VAT = VAT.ToDecimal();

                objMaster_DC.Current.DriverCommision = DriverCommissionPerBooking;

                // add pda rent
                objMaster_DC.Current.Extra = pdaCommission;

                objMaster_DC.Current.PDARent = TotalPDARent;

                ////objMaster_DC.Current.AddBy = AppVars.LoginObj.LuserId.ToInt();
                ////objMaster_DC.Current.AddLog = AppVars.LoginObj.LoginName.ToStr();
                objMaster_DC.Current.AddOn = DateTime.Now;
                objMaster_DC.Current.TransDate = DateTime.Now; //dtpTransactionDate.Value.ToDateTime();
                objMaster_DC.Current.DriverId = DriverId;//ddlDriver.SelectedValue.ToIntorNull();
                objMaster_DC.Current.OldBalance = oldBalance;// (CurrentBalance - RentPay);
                objMaster_DC.Current.FromDate = fromDate;
                objMaster_DC.Current.ToDate = tillDate;
                objMaster_DC.Current.TransFor = "Weekly";//ddlDayWise.SelectedText.ToStr();


                ////objMaster_DC.Current.AccountBookingDays = ddlAccountBookingDays.Text.ToInt();
                objMaster_DC.Current.TotalWeeks = totalWeeks.ToInt();

                // objMaster.Current.Fuel = 0;//Fuel.ToDecimal();
                //   objMaster.Current.Extra = 0;// Extra.ToDecimal();



                //  decimal parkingTotal = list2.Sum(c => c.Parking.ToDecimal()).ToDecimal();
                objMaster_DC.Current.Fuel = parkingTotal;



                if (IsHoliday)
                {
                    objMaster_DC.Current.Extra = 0.00m;
                    objMaster_DC.Current.PDARent = 0.00m;
                    objMaster_DC.Current.CollectionDeliveryCharges = 0.00m;


                }

                objMaster_DC.Current.WeekOff = IsHoliday;

                objMaster_DC.DisableCheckTotalBookings = true;


                objMaster_DC.Current.TransactionType = Enums.TRANSACTIONTYPE.DRIVER_COMMISSION_EXPENSE5;


                objMaster_DC.Save();


                currBalance = objMaster_DC.Current.Balance.ToDecimal();
                IsSaved = true;
                transId = objMaster_DC.Current.Id;

                //   }
            }
            catch (Exception ex)
            {
                //if (objMaster.Errors.Count > 0)
                //    ENUtils.ShowMessage(objMaster.ShowErrors());
                //else
                //{
                //    ENUtils.ShowMessage(ex.Message);

                //}
            }

            return IsSaved;

        }


        private decimal? GetVATTotal(decimal? VAT, decimal? GrossTotal, decimal? TotalAmount, decimal? AdminFees, bool? vatOnAdminFee, bool? hasVat)
        {
            decimal? vat = 0.00m;
            if (hasVat.ToBool())
            {
                GrossTotal = GrossTotal.ToDecimal();
                TotalAmount = TotalAmount.ToDecimal();
                AdminFees = AdminFees.ToDecimal();
                vatOnAdminFee = vatOnAdminFee.ToBool();
                if (AdminFees > 0 && vatOnAdminFee.ToBool())
                {
                    vat = (((TotalAmount * AdminFees) / 100) * 20) / 100;
                }
                else
                {
                    if (AdminFees.ToDecimal() > 0)
                    {
                        TotalAmount = TotalAmount + GetAdminFee(vat, GrossTotal, TotalAmount, AdminFees, vatOnAdminFee, hasVat);
                    }
                    vat = ((TotalAmount - ((TotalAmount * GrossTotal) / 100)) * 20) / 100;
                }
            }
            return vat;
        }
        private decimal? GetAdminFee(decimal? VAT, decimal? GrossTotal, decimal? TotalAmount, decimal? AdminFees, bool? vatOnAdminFee, bool? hasVat)
        {
            decimal? fee = 0.00m;
            fee = ((TotalAmount - (((TotalAmount * GrossTotal) / 100) * 20) / 100) * AdminFees) / 100;
            return fee;
        }
