                        Task<HttpResponseMessage> response1 = client.SendAsync(request);
                        var result = response1.Result;
                        var str = result.Content.ReadAsStringAsync();
                        response.Data = new
                        {
                            Message = str
                        };

                    }
                }

                //lst.DestinationNumber = PhNo;



