        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetDriverJobShiftReport")]
        public JsonResult GetDriverJobShiftReport(AdminApi obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();

            Gen_SubCompany objSubCompany = new Gen_SubCompany();

            try
            {
                int? driverId = obj.DriverId;

                DateTime? fromDate = obj.Fromdate;

                DateTime? tillDate = obj.Todate?.Date.AddDays(1).AddMilliseconds(-1);

                //DateTime? fromDate = string.Format("{0:dd/MM/yyyy HH:mm}", obj.Fromdate.Value.ToDate() + obj.Fromdate.Value.TimeOfDay).ToDateTime();
                //DateTime? tillDate = string.Format("{0:dd/MM/yyyy HH:mm}", obj.Todate.Value.ToDate() + obj.Todate.Value.TimeOfDay).ToDateTime();
                //DateTime? fromDate = DateTime.ParseExact(obj.Fromdate.Value.ToString("yyyy-MM-dd HH:mm:ss"), "yyyy-MM-dd HH:mm:ss", System.Globalization.CultureInfo.InvariantCulture);
                //DateTime? tillDate = DateTime.ParseExact(obj.Todate.Value.ToString("yyyy-MM-dd HH:mm:ss"), "yyyy-MM-dd HH:mm:ss", System.Globalization.CultureInfo.InvariantCulture);
                using (TaxiDataContext db = new TaxiDataContext())

                {

                    try

                    {

                        // Execute the query and get the list of DriverShiftReport objects
                        var list = db.ExecuteQuery<DriverShiftReport>("EXEC GetDriverShiftReport  {0},{1},{2}", driverId, fromDate, tillDate).ToList();

                        foreach (var item in list)

                        {

                            item.DriverShiftStartedFormatted = item.DriverShiftStarted.ToString("yyyy-MM-dd HH:mm:ss"); // You can adjust the format
                            item.DriverShiftEndedFormatted = item.DriverShiftEnded.ToString("yyyy-MM-dd HH:mm:ss"); // You can adjust the format
                        }

                        // Prepare the response with data, total record count, and sum of Total charges
                        response.Data = new

                        {

                            list = Newtonsoft.Json.JsonConvert.SerializeObject(list),
                            // Serialize list to JSON
                            TotalRecord = list.Count(),
                            // Get the total number of records
                            SumTotalCharges = list.Sum(c => c.Total) // Sum the Total charges
                        };

                    }

                    catch (Exception ex)

                    {

                        response.Data = null;

                    }

                }

            }

            catch (Exception ex)

            {

            }

            return Json(response, JsonRequestBehavior.AllowGet);

        }

        #region Online Booking
        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetOnlineBookingList")]
        public JsonResult GetOnlineBookingList()
        {
            List<WebApiClasses.ClsOnlineBooking> list = null;
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {

                //
                using (TaxiDataContext db = new TaxiDataContext())
                {

                    //
                    list = (from a in db.Bookings
                            join b in db.Gen_PaymentTypes on a.PaymentTypeId equals b.Id
                            join c in db.Gen_Companies on a.CompanyId equals c.Id into table2
                            join v in db.Fleet_VehicleTypes on a.VehicleTypeId equals v.Id
                            from c in table2.DefaultIfEmpty()
                            where a.BookingStatusId == Enums.BOOKINGSTATUS.WAITING_WEBBOOKING
                            && (a.BookingTypeId == Enums.BOOKING_TYPES.ONLINE || a.BookingTypeId == Enums.BOOKING_TYPES.WEB || a.BookingTypeId == 11)

                            select new WebApiClasses.ClsOnlineBooking
                            {
                                Id = a.Id,
                                BookingNo = a.BookingNo,
                                BookingDate = a.BookingDate,
                                //BookingDateString = a.BookingDate.HasValue ? "" : a.BookingDate.Value.ToString("dd-MMM-yyyy"),
                                PickupDateTime = a.PickupDateTime,
                                //PickupDateString = a.PickupDateTime.HasValue? "" : a.PickupDateTime.Value.ToString("dd-MMM-yyyy"),
                                //PickupTimeString = a.PickupDateTime.HasValue? "" : a.PickupDateTime.Value.ToString("HH:mm"),
                                CustomerName = a.CustomerName,
                                CustomerEmail = a.CustomerEmail,
                                CustomerMobileNo = a.CustomerMobileNo,
                                CustomerPhoneNo = a.CustomerPhoneNo,
                                CompanyPrice = a.CompanyPrice,
                                Extra = a.ExtraDropCharges,
                                FareRate = a.FareRate,
                                Parking = a.CongtionCharges,
                                Waiting = a.MeetAndGreetCharges,

                                FromAddress = a.FromAddress,
                                FromDoorNo = a.FromDoorNo,
                                FromStreet = a.FromStreet,
                                ToAddress = a.ToAddress,
                                ToDoorNo = a.ToDoorNo,

                                ToStreet = a.ToStreet,
                                BookingStatusId = a.BookingStatusId,
                                BookingTypeId = a.BookingTypeId,
                                CompanyName = c.CompanyName,
                                VehicleType = v.VehicleType,
                                ViaString = a.ViaString,
                                PaymentType = b.PaymentType,
                                SpecialRequirements = a.SpecialRequirements,
                                FlightNumber = a.FromFlightNo,
                                PaymentComments = a.PaymentComments,                                

                            }).ToList();
                }
                response.Data = list;
            }
            catch (Exception e)
            {
                response.Message = "Some Error Occured while retrieving list";
                response.HasError = true;
            }
            return new CustomJsonResult { Data = response };
        }

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("UpdateOnlineBookingStatus")]
        public JsonResult UpdateOnlineBookingStatus(WebApiClasses.ClsOnlineBooking obj)
        {
            ResponseAdminApi response = new ResponseAdminApi();
            try
            {
                System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\UpdateOnlineBookingStatus.txt", DateTime.Now + ",json: " + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
            }
            catch
            {
            }



            try
            {

                using (TaxiDataContext db = new TaxiDataContext())
                {



                    if (obj.BookingStatusId.ToInt() == 1)
                    {
                        
                        db.stp_UpdateOnlineJobStatus(obj.Id, Enums.BOOKINGSTATUS.WAITING, "OnlineBooking Accept", "Accept", "Controller");
                        if (Global.EnableOnlineBookingEmail == "1")
                        {
                            string subject = "";
                            string FromEmail = "";

                            var booking = db.Bookings.Where(x => x.Id == obj.Id).Select(x => new { PickupDateTime = x.PickupDateTime, BookingNo = x.BookingNo, SubCompanyId = x.SubcompanyId,CustomerEmail = x.CustomerEmail }).FirstOrDefault();

                            var subCompany = db.ExecuteQuery<WebApiClasses.Gen_SubcompanyFields>($"select Id,EmailAddress,SmtpEmailAddress,SmtpInvoiceEmailAddress,SmtpDriverEmailAddress,CAST(ISNULL(UseDifferentEmailForInvoices,0) AS BIT) UseDifferentEmailForInvoices,SmtpInvoiceUserName from Gen_SubCompany WHERE Id={booking.SubCompanyId}").FirstOrDefault();

                            

                            subject = "Online BOOKING CONFIRMATION -  " + string.Format("{0:dd MMMM yyyy}", booking.PickupDateTime)
                                     + ", TIME " + string.Format("{0:HH.mm}", booking.PickupDateTime) + " - BOOKING ID "
                                     + booking.BookingNo.ToStr();

                            

                            WebApiClasses.RequestWebApi obj1 = new WebApiClasses.RequestWebApi();
                            obj1.emailInfo = new WebApiClasses.EmailInfo();
                            obj1.emailInfo.From = subCompany.EmailAddress;
                            obj1.emailInfo.BookingId = obj.Id;
                            obj1.emailInfo.Subject = subject;
                            obj1.emailInfo.To = booking.CustomerEmail;

                            WebApiController controller = new WebApiController();
                            controller.SendConfirmationEmail(obj1);
                        }

                    }
                    else
                    {
                        db.stp_UpdateOnlineJobStatus(obj.Id, Enums.BOOKINGSTATUS.CANCELLED, "OnlineBooking Declined:" + "", "Declined", "Controller");
                        if (Global.EnableOnlineBookingEmail == "1")
                        {
                            string subject = "";
                            string FromEmail = "";
                            var booking = db.Bookings.Where(x => x.Id == obj.Id).Select(x => new { PickupDateTime = x.PickupDateTime, BookingNo = x.BookingNo, CustomerEmail = x.CustomerEmail, SubCompanyId = x.SubcompanyId }).FirstOrDefault();
                            var objSubcompany = new TaxiDataContext().Gen_SubCompanies.FirstOrDefault(x => x.Id == booking.SubCompanyId.ToInt());
                            
                            
                            subject = "Online Cancelled BOOKING -  " + string.Format("{0:dd MMMM yyyy}", booking.PickupDateTime)
                                     + ", TIME " + string.Format("{0:HH.mm}", booking.PickupDateTime) + " - BOOKING ID "
                                     + booking.BookingNo.ToStr();

                           
                            List<System.Net.Mail.Attachment> attachments = new List<System.Net.Mail.Attachment>();
                            string body = "your booking Ref " + booking.BookingNo + " has been Cancelled from our System";

                            ClsEmail Email = new ClsEmail();
                            ClsEmail.Send(subject, body, objSubcompany.EmailAddress, booking.CustomerEmail, attachments, objSubcompany, "");
                        }
                    }
                }
                //

                General.BroadCastMessage("**close authorize web>>" + Environment.MachineName + ">>" + obj.Id + ">>" + obj.BookingStatusId.ToInt());


                if (obj.BookingStatusId.ToInt() != 1)
                {


                    CallSupplierApi.UpdateStatus(obj.Id, Enums.BOOKINGSTATUS.CANCELLED.ToInt());

                    try
                    {
                        System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\" + "UpdateOnlineBookingStatusDeclined.txt", DateTime.Now.ToString("dd/MM/yyyy HH:mm:ss") + ",json:" + new JavaScriptSerializer().Serialize(obj) + Environment.NewLine);
                    }
                    catch
                    {

                    }

                }


                try
                {

                    using (TaxiDataContext db = new TaxiDataContext())
                    {

                        var detail = db.Bookings.Where(c => c.Id == obj.Id).Select(c => new { c.CustomerId, c.BookingTypeId }).FirstOrDefault();

                        if (detail.CustomerId != null && detail.BookingTypeId.ToInt() == Enums.BOOKING_TYPES.ONLINE)
                        {
                            if (obj.BookingStatusId.ToInt() != 1)
                                General.SendPushNotification("Your Booking is Rejected [" + obj.Id.ToStr() + "]", "", detail.CustomerId.ToInt());
                            else
                                General.SendPushNotification("Your Booking is Approved [" + obj.Id.ToStr() + "]", "", detail.CustomerId.ToInt());



                        }

                    }
                }
                catch
                {

                }

            }
            catch (Exception ex)
            {
                try
                {
                    System.IO.File.AppendAllText(AppContext.BaseDirectory + "\\AcceptOnlineBookingException.txt", DateTime.Now + ",json: " + ex.Message + Environment.NewLine);
                }
                catch
                {
                }
                response.HasError = true;
                response.Message = ex.Message;
            }

            return Json(response, JsonRequestBehavior.AllowGet);
        }

        #endregion

        #region Braithwaites invoice report 

        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetInvoiceHtmlTemplate")]
        public JsonResult GetInvoiceHtmlTemplate(int templateId)
        {
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    string sql = "SELECT HtmlTemplate FROM InvoiceTemplates WHERE Id = {0}";
                    var result = db.ExecuteQuery<string>(sql, templateId).FirstOrDefault();

                    if (string.IsNullOrEmpty(result))
                    {
                        return Json(new { success = false, message = "Template not found." }, JsonRequestBehavior.AllowGet);
                    }

                    return Json(new { success = true, template = result }, JsonRequestBehavior.AllowGet);
                }
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }


        [System.Web.Http.HttpGet]
        [System.Web.Http.HttpPost]
        [System.Web.Http.Route("GetInvoiceTemplateTypeByCompany")]
        public JsonResult GetInvoiceTemplateTypeByCompany(int companyId)
        {
            try
            {
                using (TaxiDataContext db = new TaxiDataContext())
                {
                    string sql = "SELECT InvoiceTemplateType FROM Gen_Company WHERE id = {0}";
                    var result = db.ExecuteQuery<int?>(sql, companyId).FirstOrDefault();

                    if (!result.HasValue)
                    {
                        return Json(new { success = false, message = "Company not found or no template set." }, JsonRequestBehavior.AllowGet);
                    }

                    return Json(new { success = true, template = result.Value }, JsonRequestBehavior.AllowGet);
                }
            }
            catch (Exception ex)
            {
                return Json(new { success = false, message = ex.Message }, JsonRequestBehavior.AllowGet);
            }
        }
        #endregion
    }
